class EdgePartition(Enum):
    OPEN = 0
    INCLUDED = 1
    EXCLUDED = 2


def _directed_graph_has_successor(self, u, v):
    return u in self and v in self.succ[u]


def _directed_graph_has_predecessor(self, u, v):
    return u in self and v in self.pred[u]


def _digraph_out_edges(self, nbunch=None, data=False, default=None):
    return list(self.edges(nbunch=nbunch, data=data, default=default))


def _digraph_in_edges(self, nbunch=None, data=False, default=None):
    result = []
    for target in self.nbunch_iter(nbunch):
        for source, attrs in self.pred[target].items():
            if data is True:
                result.append((source, target, attrs))
            elif data is False:
                result.append((source, target))
            else:
                result.append((source, target, attrs.get(data, default)))
    return result


def _multidigraph_out_edges(self, nbunch=None, data=False, keys=False, default=None):
    return list(self.edges(nbunch=nbunch, data=data, keys=keys, default=default))


def _multidigraph_in_edges(self, nbunch=None, data=False, keys=False, default=None):
    result = []
    for target in self.nbunch_iter(nbunch):
        for source, keyed_attrs in self.pred[target].items():
            for key, attrs in keyed_attrs.items():
                if data is True and keys:
                    result.append((source, target, key, attrs))
                elif data is True:
                    result.append((source, target, attrs))
                elif data is False and keys:
                    result.append((source, target, key))
                elif data is False:
                    result.append((source, target))
                elif keys:
                    result.append((source, target, key, attrs.get(data, default)))
                else:
                    result.append((source, target, attrs.get(data, default)))
    return result


def _graph_nbunch_iter(self, nbunch=None):
    adjacency = self.adj
    if nbunch is None:
        return iter(adjacency)
    if nbunch in self:
        return iter([nbunch])

    def bunch_iter(nlist, adj):
        try:
            for n in nlist:
                hash(n)
                if n in adj:
                    yield n
        except TypeError as err:
            exc, message = err, err.args[0]
            if "iter" in message:
                exc = NetworkXError("nbunch is not a node or a sequence of nodes.")
            if "object is not iterable" in message:
                exc = NetworkXError(f"Node {nbunch} is not in the graph.")
            if "hashable" in message:
                exc = NetworkXError(f"Node {n} in sequence nbunch is not a valid node.")
            raise exc

    return bunch_iter(nbunch, adjacency)


def _size_with_unweighted_int(size_impl):
    def size(self, weight=None):
        if weight is None:
            return self.number_of_edges()
        return size_impl(self, weight)

    return size


def _number_of_edges_with_endpoints(number_of_edges_impl):
    def number_of_edges(self, u=None, v=None):
        if u is None and v is None:
            return number_of_edges_impl(self)
        if v is None:
            if u not in self:
                raise KeyError(u)
            return 0
        if u is None:
            raise TypeError("number_of_edges() missing 1 required positional argument: 'u'")
        return 1 if self.has_edge(u, v) else 0

    return number_of_edges


def _neighbors_with_networkx_missing_node_error(neighbors_impl, *, graph_kind="graph"):
    def neighbors(self, node):
        try:
            result = neighbors_impl(self, node)
        except NodeNotFound as exc:
            raise NetworkXError(f"The node {node} is not in the {graph_kind}.") from exc
        # br-nbriter: nx.Graph.neighbors returns a dict_keyiterator
        # (iterator). fnx's Rust impl returns a list. Code like
        # ``for x in G.neighbors(u): break`` + ``for x in same_list``
        # accidentally restarts iteration because list iteration is not
        # stateful across re-entries — e.g. nx.dfs_labeled_edges broke
        # on fnx when it pushed ``(start, G.neighbors(start))`` onto a
        # stack and the outer ``for child in children`` re-ran from the
        # beginning after break, producing spurious nontree edges.
        # Always return a proper iterator so algorithms that rely on
        # iterator state work.
        if isinstance(result, list):
            return iter(result)
        return result

    return neighbors


def _remove_edge_with_networkx_missing_edge_error(
    remove_edge_impl, *, missing_edge_message, supports_key=False
):
    if supports_key:

        def remove_edge(self, u, v, key=None):
            if key is None:
                if not self.has_edge(u, v):
                    raise NetworkXError(missing_edge_message.format(u=u, v=v))
            elif not self.has_edge(u, v, key):
                raise NetworkXError(f"The edge {u}-{v} with key {key} is not in the graph.")
            return remove_edge_impl(self, u, v, key)

    else:

        def remove_edge(self, u, v):
            if not self.has_edge(u, v):
                raise NetworkXError(missing_edge_message.format(u=u, v=v))
            return remove_edge_impl(self, u, v)

    return remove_edge


def _remove_node_with_networkx_missing_node_error(remove_node_impl, *, graph_kind="graph"):
    def remove_node(self, n):
        if n not in self:
            raise NetworkXError(f"The node {n} is not in the {graph_kind}.")
        return remove_node_impl(self, n)

    return remove_node


class EdgeDataView:
    """Live view over ``G.edges(data=..., nbunch=...)`` matching nx's
    EdgeDataView contract (br-r37-c1-sf1ku).

    The Rust EdgeView's ``__call__`` materialises a list eagerly. nx's
    EdgeDataView is a true view over the graph — mutations after the
    view is captured are reflected on iteration. This wrapper stores
    the call site's resolved kwargs and re-invokes the underlying
    edge_view_call on each access (iter / len / contains / repr) so
    drop-in code that captures a view and iterates after mutating gets
    nx's live semantics. Class name aligned to ``EdgeDataView`` so
    ``type(view).__name__`` checks match nx.
    """

    def __init__(self, edge_view_call, view_self, *, data, default, nbunch_list, graph=None):
        self._call = edge_view_call
        self._view = view_self
        self._data = data
        self._default = default
        self._nbunch_list = nbunch_list
        self._nbset = set(nbunch_list) if nbunch_list is not None else None
        # br-r37-c1-dc14n: graph reference (when known) lets the
        # adj-walk path compute edges in nx-matching adj order. Look
        # up via the global EdgeView->Graph map populated by the
        # _private_aware_edges property if not provided.
        if graph is None:
            try:
                graph = _EDGE_VIEW_GRAPH_OWNER.get(id(view_self))
            except (NameError, TypeError):
                graph = None
        self._graph = graph

    def _materialize(self):
        data = self._data
        default = self._default
        data_is_none = data is None
        rust_data = False if data_is_none else data
        if self._nbunch_list is not None and self._graph is not None:
            # br-r37-c1-dc14n: nx's edges(nbunch) iterates nbunch in
            # user-given order and for each node yields edges (u, v)
            # in adj[u] order, skipping edges where v has already
            # been seen via this iteration. The Rust path returned
            # edges in G.nodes()-order filtered by nbunch — mismatched
            # iteration order. Replicate nx's algorithm explicitly so
            # G.edges(nbunch) matches nx's contract on undirected
            # graphs. (Directed/multigraph go through different
            # EdgeView classes which already match nx.)
            return self._materialize_via_adj_walk(data, default, data_is_none)
        result = self._call(
            self._view,
            data=rust_data,
            nbunch=self._nbunch_list,
            default=default,
        )
        if data_is_none:
            result = [edge + (default,) for edge in result]
        return list(result)

    def _materialize_via_adj_walk(self, data, default, data_is_none):
        """Mirror nx's UndirectedEdgeView.__call__ when nbunch is set:
        walk nbunch_list in user order, for each node iterate
        adj[node] yielding (u, v) plus optional data, skipping
        edges where the second endpoint has already been visited."""
        graph = self._graph
        seen = set()
        result = []
        for node in self._nbunch_list:
            if node not in graph:
                # nx skips missing nbunch nodes silently.
                continue
            adj_view = graph[node]
            for nbr, edge_data in adj_view.items():
                if nbr in seen:
                    continue
                if data is False:
                    result.append((node, nbr))
                elif data is True:
                    result.append((node, nbr, dict(edge_data)))
                elif data_is_none:
                    result.append((node, nbr, default))
                else:
                    # data is a string attr name
                    result.append((node, nbr, edge_data.get(data, default)))
            # br-r37-c1-6yimw: nx adds node to ``seen`` *after* the
            # inner adj loop so self-loop edges (where nbr == node)
            # are still emitted. The previous pre-loop ``seen.add``
            # ate self-loops.
            seen.add(node)
        return result

    def _reorder(self, edge):
        if not isinstance(edge, tuple) or len(edge) < 2:
            return edge
        u, v = edge[0], edge[1]
        rest = edge[2:]
        if u in self._nbset:
            return edge
        if v in self._nbset:
            return (v, u) + rest
        return edge

    def __iter__(self):
        return iter(self._materialize())

    def __len__(self):
        return len(self._materialize())

    def __contains__(self, item):
        return item in self._materialize()

    def __repr__(self):
        return f"EdgeDataView({self._materialize()!r})"

    def __str__(self):
        # br-r37-c1-mpv5x: nx EdgeDataView.__str__ is str(list(self)).
        return str(self._materialize())

    def __eq__(self, other):
        if hasattr(other, "__iter__"):
            return list(self._materialize()) == list(other)
        return NotImplemented

    __hash__ = None


def _edge_view_call_with_nbunch_first(edge_view_call):
    _unset = object()

    def wrapped(self, *args, **kwargs):
        nbunch = kwargs.pop("nbunch", _unset)
        data = kwargs.pop("data", _unset)
        default = kwargs.pop("default", _unset)
        if kwargs:
            unexpected = next(iter(kwargs))
            raise TypeError(f"__call__() got an unexpected keyword argument '{unexpected}'")

        if len(args) > 3:
            raise TypeError(
                f"__call__() takes from 1 to 4 positional arguments but {len(args) + 1} were given"
            )
        if len(args) >= 1:
            if nbunch is not _unset:
                raise TypeError("__call__() got multiple values for argument 'nbunch'")
            nbunch = args[0]
        if len(args) >= 2:
            if data is not _unset:
                raise TypeError("__call__() got multiple values for argument 'data'")
            data = args[1]
        if len(args) == 3:
            if default is not _unset:
                raise TypeError("__call__() got multiple values for argument 'default'")
            default = args[2]

        if nbunch is _unset:
            nbunch = None
        if data is _unset:
            data = False
        if default is _unset:
            default = None
        # br-edgesnb: nx.EdgeView accepts a single node as nbunch
        # (yielding edges incident to that node). The Rust edge_view_call
        # expects None or an iterable; a single node like `u = 0` raised
        # TypeError: 'int' object is not iterable. Detect single-node
        # nbunch by trying to iterate it; fall back to `[nbunch]`.
        nbunch_list = None
        if nbunch is not None:
            try:
                iter(nbunch)
                if isinstance(nbunch, (str, bytes)):
                    nbunch = [nbunch]
            except TypeError:
                nbunch = [nbunch]
            # Materialize nbunch so we can both pass it to Rust and use
            # it to reorder the returned edge tuples below.
            nbunch_list = [n for n in nbunch]
        # When data is non-False or nbunch is given, return a live
        # EdgeDataView wrapper (br-r37-c1-sf1ku) instead of a list
        # snapshot. The wrapper re-invokes edge_view_call on each access.
        if nbunch_list is not None or data is not False:
            return EdgeDataView(
                edge_view_call,
                self,
                data=data,
                default=default,
                nbunch_list=nbunch_list,
            )
        # data=False, no nbunch — return the live Rust EdgeView directly.
        return edge_view_call(self, data=False, nbunch=None, default=default)

    return wrapped


class NodeDataView:
    """Live view over ``G.nodes(data=...)`` matching nx's NodeDataView
    contract (br-r37-c1-j2vof).

    The Rust NodeView's ``__call__(data=True)`` returns a NodeView
    object (class name ``NodeView``); the data='attr' path used to
    return a Python list. nx returns a ``NodeDataView`` in both cases.
    This wrapper re-invokes the underlying Rust call (or rebuilds the
    attr-projection list) on each access (iter / len / contains / repr)
    so mutations are reflected and class-name introspection matches.
    """

    def __init__(self, node_view_call, view_self, *, data, default):
        self._call = node_view_call
        self._view = view_self
        self._data = data
        self._default = default

    def _materialize(self):
        data = self._data
        default = self._default
        if isinstance(data, bool):
            # Rust path: returns a NodeView; iterate its content directly.
            return list(self._call(self._view, data, default))
        return [
            (node, self._view[node].get(data, default))
            for node in self._view
        ]

    def __iter__(self):
        return iter(self._materialize())

    def __len__(self):
        return len(self._materialize())

    def __contains__(self, item):
        # Match nx: a bare node is considered in the view (data
        # variant strips the data when checking containment).
        if not isinstance(item, tuple):
            return item in self._view
        return item in self._materialize()

    def __getitem__(self, key):
        # nx NodeDataView supports view[node] -> attrs / value.
        data = self._data
        default = self._default
        if isinstance(data, bool):
            attrs = self._view[key]
            return dict(attrs) if data else None
        return self._view[key].get(data, default)

    def __repr__(self):
        if isinstance(self._data, bool) and not self._data:
            return f"NodeDataView({self._materialize()!r}, data=False)"
        if isinstance(self._data, bool):
            return f"NodeDataView({dict(self._materialize())!r})"
        return f"NodeDataView({dict(self._materialize())!r}, data={self._data!r})"

    def __str__(self):
        # br-r37-c1-mpv5x: nx NodeDataView.__str__ is str(list(self)).
        return str(self._materialize())

    def __eq__(self, other):
        if hasattr(other, "__iter__"):
            return list(self._materialize()) == list(other)
        return NotImplemented

    __hash__ = None


def _node_view_call_with_attr_support(node_view_call):
    _unset = object()

    def wrapped(self, *args, **kwargs):
        data = kwargs.pop("data", _unset)
        default = kwargs.pop("default", _unset)
        if kwargs:
            unexpected = next(iter(kwargs))
            raise TypeError(f"__call__() got an unexpected keyword argument '{unexpected}'")

        if len(args) > 2:
            raise TypeError(
                f"__call__() takes from 1 to 3 positional arguments but {len(args) + 1} were given"
            )
        if len(args) >= 1:
            if data is not _unset:
                raise TypeError("__call__() got multiple values for argument 'data'")
            data = args[0]
        if len(args) == 2:
            if default is not _unset:
                raise TypeError("__call__() got multiple values for argument 'default'")
            default = args[1]

        if data is _unset:
            data = False
        if default is _unset:
            default = None
        # br-r37-c1-f8gi1: data=False with no kwargs must return a LIVE
        # node view — i.e. ``self`` — so subsequent graph mutations are
        # visible when the captured view is iterated again. Matches nx's
        # NodeView.__call__() returning self. The Rust-side
        # MultiGraphNodeView / MultiDiGraphNodeView ``__call__`` returns
        # a frozen list when invoked through the FFI; bypass it here.
        # Graph and DiGraph were already correct because their Rust
        # ``__call__`` returns self for default args, but uniformly
        # returning ``self`` keeps the contract consistent across all
        # four classes and avoids future drift.
        if data is False:
            return self
        # data=True or data='attr' return a NodeDataView wrapper
        # (br-r37-c1-j2vof).
        return NodeDataView(
            node_view_call, self, data=data, default=default
        )

    return wrapped


def _adjacency_view_get(self, node, default=None):
    try:
        return self[node]
    except KeyError:
        return default


def _adjacency_view_keys(self):
    # br-adjkset: nx internals (non_neighbors) do
    # ``graph._adj.keys() - graph._adj[node].keys() - {node}`` expecting
    # dict_keys-like views that support set-difference. A plain iterator
    # fails with TypeError. Return a KeysView-like frozen set snapshot
    # so - | & operators work.
    from collections.abc import KeysView

    class _AdjKeysView(KeysView):
        __slots__ = ("_snapshot",)

        def __init__(self, snapshot):
            self._snapshot = snapshot

        def __iter__(self):
            return iter(self._snapshot)

        def __contains__(self, item):
            return item in self._snapshot

        def __len__(self):
            return len(self._snapshot)

    return _AdjKeysView(list(self))


def _adjacency_view_items(self):
    """br-viewitems: return a re-iterable view matching nx's ItemsView
    contract rather than a one-shot generator. User code that iterates
    ``G.edges.items()`` twice (e.g. compute + re-render flow) previously
    saw the second pass empty.
    """
    from collections.abc import ItemsView

    view = self

    class _AdjItemsView(ItemsView):
        def __init__(self):
            pass

        def __iter__(self):
            return ((node, view[node]) for node in view)

        def __contains__(self, item):
            try:
                key, val = item
            except (TypeError, ValueError):
                return False
            return key in view and view[key] == val

        def __len__(self):
            return len(view)

    return _AdjItemsView()


def _adjacency_view_values(self):
    """br-viewitems: re-iterable ValuesView matching nx."""
    from collections.abc import ValuesView

    view = self

    class _AdjValuesView(ValuesView):
        def __init__(self):
            pass

        def __iter__(self):
            return (view[node] for node in view)

        def __contains__(self, value):
            for node in view:
                if view[node] == value:
                    return True
            return False

        def __len__(self):
            return len(view)

    return _AdjValuesView()


class AtlasView(Mapping):
    def __init__(self, atlas_getter):
        self._atlas_getter = atlas_getter

    def _atlas(self):
        return self._atlas_getter()

    def __len__(self):
        return len(self._atlas())

    def __iter__(self):
        return iter(self._atlas())

    def __getitem__(self, node):
        return self._atlas()[node]

    def __repr__(self):
        # br-r37-c1-k147g: nx.AtlasView prints the underlying mapping
        # (e.g. ``AtlasView({1: {}})``); without an explicit __repr__
        # Python falls back to ``<franken_networkx.AtlasView object at 0x...>``.
        return f"AtlasView({dict(self._atlas())!r})"

    def __str__(self):
        # br-r37-c1-mpv5x: nx.AtlasView.__str__ returns the bare dict
        # ('{1: {}}'), not the wrapped repr.
        return str(dict(self._atlas()))

    def copy(self):
        """br-atlascp: nx.AtlasView has a dict-style copy(). nx internals
        like ``to_dict_of_dicts`` do ``nbrdict.copy()`` on the adj value,
        which crashed on fnx because AtlasView lacked the method. Return
        a plain dict snapshot of the underlying mapping.
        """
        return {k: dict(v) if hasattr(v, "items") else v for k, v in self._atlas().items()}


class AdjacencyView(Mapping):
    def __init__(self, atlas_getter):
        self._atlas_getter = atlas_getter

    def _atlas(self):
        return self._atlas_getter()

    def __len__(self):
        return len(self._atlas())

    def __iter__(self):
        return iter(self._atlas())

    def __getitem__(self, node):
        try:
            self._atlas()[node]
        except KeyError as exc:
            # br-keystr: preserve the original key type (int/tuple/...)
            # in the KeyError args instead of the Rust side's str repr.
            raise KeyError(node) from exc
        return AtlasView(lambda: self._atlas()[node])

    def __repr__(self):
        # br-r37-c1-k147g: print the underlying mapping like nx does.
        return f"AdjacencyView({self.copy()!r})"

    def __str__(self):
        # br-r37-c1-mpv5x: bare-dict str like nx.
        return str(self.copy())

    def copy(self):
        """br-adjcp: nx.to_dict_of_dicts does ``nbrdict.copy()`` on the
        adjacency value; AdjacencyView (used for MultiGraph inner) had
        no copy() method. Return a plain dict-of-dicts snapshot.
        """
        return {k: dict(v) if hasattr(v, "items") else v for k, v in self._atlas().items()}


class MultiAdjacencyView(Mapping):
    def __init__(self, atlas_getter):
        self._atlas_getter = atlas_getter

    def _atlas(self):
        return self._atlas_getter()

    def __len__(self):
        return len(self._atlas())

    def __iter__(self):
        return iter(self._atlas())

    def __getitem__(self, node):
        try:
            self._atlas()[node]
        except KeyError as exc:
            raise KeyError(node) from exc
        return AdjacencyView(lambda: self._atlas()[node])

    def __repr__(self):
        # br-r37-c1-k147g: print the underlying mapping like nx does.
        return f"MultiAdjacencyView({self.copy()!r})"

    def __str__(self):
        # br-r37-c1-mpv5x: bare-dict str like nx.
        return str(self.copy())

    def copy(self):
        """br-adjcp: snapshot the multigraph adjacency as a plain
        dict-of-dicts-of-dicts, recursively.
        """
        out = {}
        atlas = self._atlas()
        for u, nbrs in atlas.items():
            inner = {}
            for v, keyed in nbrs.items():
                inner[v] = dict(keyed) if hasattr(keyed, "items") else keyed
            out[u] = inner
        return out


def _multigraph_adj_view(self):
    return MultiAdjacencyView(lambda: _MULTIGRAPH_ADJ_DESCRIPTOR.__get__(self, MultiGraph))


def _graph_adj_view(self):
    return AdjacencyView(lambda: _GRAPH_ADJ_DESCRIPTOR.__get__(self, Graph))


def _digraph_adj_view(self):
    return AdjacencyView(lambda: _DIGRAPH_ADJ_DESCRIPTOR.__get__(self, DiGraph))


def _multidigraph_adj_view(self):
    return MultiAdjacencyView(
        lambda: _MULTIDIGRAPH_ADJ_DESCRIPTOR.__get__(self, MultiDiGraph)
    )


def _digraph_succ_view(self):
    return AdjacencyView(lambda: _DIGRAPH_SUCC_DESCRIPTOR.__get__(self, DiGraph))


def _digraph_pred_view(self):
    return AdjacencyView(lambda: _DIGRAPH_PRED_DESCRIPTOR.__get__(self, DiGraph))


def _multidigraph_succ_view(self):
    return MultiAdjacencyView(
        lambda: _MULTIDIGRAPH_SUCC_DESCRIPTOR.__get__(self, MultiDiGraph)
    )


def _multidigraph_pred_view(self):
    return MultiAdjacencyView(
        lambda: _MULTIDIGRAPH_PRED_DESCRIPTOR.__get__(self, MultiDiGraph)
    )


def _graph_getitem_from_adj(self, node):
    # br-keystr: the Rust adj view stringifies the key in the KeyError
    # (``G[(0, 0)]`` -> ``KeyError('(0, 0)')`` str, not ``KeyError((0, 0))``
    # with the original tuple). Re-raise with the original key object so
    # typed ``except KeyError`` handlers that inspect ``e.args[0]`` get the
    # value they passed in.
    try:
        return self.adj[node]
    except KeyError as exc:
        raise KeyError(node) from exc


def _to_directed_class(self):
    return MultiDiGraph if self.is_multigraph() else DiGraph


def _to_undirected_class(self):
    return MultiGraph if self.is_multigraph() else Graph


def _multigraph_new_edge_key(self, u, v):
    try:
        keydict = self.adj[u][v]
    except KeyError:
        return 0
    key = len(keydict)
    while key in keydict:
        key += 1
    return key


def _multigraph_edge_subgraph(self, edges):
    return edge_subgraph(self, edges)


class _DiGraphEdgeView:
    def __init__(self, graph):
        self._graph = graph

    def _materialize(self):
        result = []
        for source in self._graph:
            for target in self._graph.succ[source]:
                result.append((source, target))
        return result

    def __iter__(self):
        # br-r37-c1-msf5j: walk adj directly so __call__ can return
        # self (a live view) without causing __iter__ → __call__
        # recursion when called with default args.
        return iter(self._materialize())

    def __len__(self):
        return self._graph.number_of_edges()

    def __contains__(self, edge):
        try:
            u, v = edge[:2]
        except (TypeError, ValueError):
            return False
        return self._graph.has_edge(u, v)

    def __getitem__(self, edge):
        u, v = edge
        if not self._graph.has_edge(u, v):
            raise KeyError(edge)
        return self._graph.succ[u][v]

    def __call__(self, nbunch=None, data=False, default=None):
        # br-r37-c1-msf5j: when called with default args, return self
        # so the resulting "view" stays live with respect to subsequent
        # graph mutations — matches nx's OutEdgeView.__call__ contract:
        #
        #   v = G.edges(); G.add_edge(...); list(v)  # sees the new edge
        #
        # The data/nbunch-filtered paths still snapshot to a list (a
        # full EdgeDataView would be needed for live data views; out of
        # scope here, and nx's EdgeDataView is also itself snapshot-ish
        # in practice for many of its consumers).
        if nbunch is None and data is False:
            return self
        result = []
        for source in self._graph.nbunch_iter(nbunch):
            for target, attrs in self._graph.succ[source].items():
                if data is True:
                    result.append((source, target, attrs))
                elif data is False:
                    result.append((source, target))
                else:
                    result.append((source, target, attrs.get(data, default)))
        return result

    def __or__(self, other):
        return set(self) | set(other)

    def __and__(self, other):
        return set(self) & set(other)

    def __sub__(self, other):
        return set(self) - set(other)

    def __xor__(self, other):
        return set(self) ^ set(other)


def _digraph_edges(self):
    return _DiGraphEdgeView(self)


def _multi_edge_keys(self):
    # Upstream MultiEdgeView yields (u, v, k) keys for the Mapping contract.
    return iter(self(keys=True))


def _multi_edge_items(self):
    # Each (u, v, k) key maps to the corresponding edge attrs dict.
    return ((key, self[key]) for key in self.keys())


def _multi_edge_values(self):
    return (self[key] for key in self.keys())


def _multi_edge_get(self, key, default=None):
    try:
        return self[key]
    except KeyError:
        return default


class _LiveMultiEdgeCallView:
    """br-r37-c1-msf5j: result of ``MG.edges()`` (no args) on a (Multi)
    graph. Mirrors nx's ``MultiEdgeDataView`` for the default-args
    case: yields 2-tuples on iteration, stays live with respect to
    subsequent graph mutations (re-walks ``adj`` / ``succ`` on every
    iter), and supports ``len`` / ``in``. The ``MG.edges`` (no parens)
    direct view continues to yield 3-tuples via ``_MultiGraphEdgeView``.
    """

    __slots__ = ("_graph", "_directed")

    def __init__(self, graph, *, directed):
        self._graph = graph
        self._directed = directed

    def _walk(self):
        graph = self._graph
        if self._directed:
            for source in graph:
                for target, keyed_attrs in graph.succ[source].items():
                    for _key in keyed_attrs:
                        yield (source, target)
        else:
            seen = set()
            for source in graph:
                for target, keyed_attrs in graph.adj[source].items():
                    for _key in keyed_attrs:
                        marker = (frozenset((source, target)), _key)
                        if marker in seen:
                            continue
                        seen.add(marker)
                        yield (source, target)

    def __iter__(self):
        return self._walk()

    def __len__(self):
        return self._graph.number_of_edges()

    def __contains__(self, edge):
        if not isinstance(edge, tuple) or len(edge) < 2:
            return False
        u, v = edge[0], edge[1]
        graph = self._graph
        if self._directed:
            return u in graph.succ and v in graph.succ[u]
        adj = graph.adj
        return (u in adj and v in adj[u]) or (v in adj and u in adj[v])

    def __repr__(self):
        return f"MultiEdgeDataView({list(self)!r})"

    def __eq__(self, other):
        if isinstance(other, (set, frozenset)):
            return set(self) == other
        if isinstance(other, _LiveMultiEdgeCallView):
            return list(self) == list(other)
        try:
            return list(self) == list(other)
        except TypeError:
            return NotImplemented

    def __ne__(self, other):
        eq = self.__eq__(other)
        if eq is NotImplemented:
            return NotImplemented
        return not eq

    __hash__ = None


class _MultiGraphEdgeView:
    def __init__(self, graph):
        self._graph = graph

    def __iter__(self):
        # br-multiiterkeys: nx.MultiEdgeView default iteration yields
        # 3-tuples ``(u, v, key)`` (as opposed to the ``G.edges()`` call
        # form which defaults to 2-tuples). fnx's __iter__ called
        # self() (keys=False) and yielded 2-tuples, so Set comparisons
        # and direct iteration consumers (including downstream nx
        # algorithms) got a different edge count than nx on multigraphs
        # with parallel edges.
        return iter(self(keys=True))

    def __len__(self):
        return self._graph.number_of_edges()

    def __getitem__(self, edge):
        # Accept (u, v, k) 3-tuples like upstream MultiEdgeView.
        if not isinstance(edge, tuple) or len(edge) != 3:
            raise KeyError(edge)
        u, v, key = edge
        adj = self._graph.adj
        if u in adj and v in adj[u] and key in adj[u][v]:
            return adj[u][v][key]
        # Undirected fallback: accept reversed orientation.
        if v in adj and u in adj[v] and key in adj[v][u]:
            return adj[v][u][key]
        raise KeyError(edge)

    keys = _multi_edge_keys
    items = _multi_edge_items
    values = _multi_edge_values
    get = _multi_edge_get

    def __contains__(self, edge):
        if not isinstance(edge, tuple) or len(edge) < 2:
            return False
        u, v = edge[0], edge[1]
        # Undirected: check both orientations
        adj = self._graph.adj
        if u not in adj and v not in adj:
            return False
        # Check u->v or v->u
        has_edge = (u in adj and v in adj[u]) or (v in adj and u in adj[v])
        if not has_edge:
            return False
        if len(edge) == 2:
            return True
        # 3-tuple: check specific key
        key = edge[2]
        if u in adj and v in adj[u] and key in adj[u][v]:
            return True
        if v in adj and u in adj[v] and key in adj[v][u]:
            return True
        return False

    def __call__(self, nbunch=None, data=False, keys=False, default=None):
        # br-r37-c1-msf5j: when called with all-default args, return a
        # live wrapper that yields 2-tuples on iter and re-walks the
        # graph each time so subsequent edge mutations are visible.
        # Matches nx's MultiEdgeView.__call__() returning a live
        # MultiEdgeDataView.
        if nbunch is None and data is False and keys is False:
            return _LiveMultiEdgeCallView(self._graph, directed=False)
        result = _EdgeListWithSetAlgebra()
        seen = set()
        for source in self._graph.nbunch_iter(nbunch):
            for target, keyed_attrs in self._graph.adj[source].items():
                for key, attrs in keyed_attrs.items():
                    marker = (frozenset((source, target)), key)
                    if marker in seen:
                        continue
                    seen.add(marker)
                    if data is True and keys:
                        result.append((source, target, key, attrs))
                    elif data is True:
                        result.append((source, target, attrs))
                    elif data is False and keys:
                        result.append((source, target, key))
                    elif data is False:
                        result.append((source, target))
                    elif keys:
                        result.append((source, target, key, attrs.get(data, default)))
                    else:
                        result.append((source, target, attrs.get(data, default)))
        return result


class _EdgeListWithSetAlgebra(list):
    """List subclass that supports set-algebra operators.

    Returned by MultiGraph.edges(keys=...) / MultiDiGraph.edges(keys=...)
    so the result matches upstream NetworkX's set-like behaviour
    (expressions like edges | {...}, edges & {...}, edges == set) without
    breaking existing callers that iterate the value as a list.
    """

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)

    def __eq__(self, other):
        # br-mgedgeeq: nx's MultiEdgeView inherits from Set, so
        # `MG.edges(keys=True) == {...}` compares as sets. fnx's list
        # subclass previously required another list for equality.
        if isinstance(other, (set, frozenset)):
            return set(self) == other
        return list.__eq__(self, other)

    def __ne__(self, other):
        eq = self.__eq__(other)
        if eq is NotImplemented:
            return NotImplemented
        return not eq

    __hash__ = None


def _multigraph_edges(self):
    return _MultiGraphEdgeView(self)


class _MultiDiGraphEdgeView:
    def __init__(self, graph):
        self._graph = graph

    def __iter__(self):
        # br-multiiterkeys: see _MultiGraphEdgeView — default iteration
        # yields 3-tuples ``(u, v, key)`` matching nx.MultiEdgeView's
        # default iter contract; the ``G.edges()`` call form still
        # defaults to 2-tuples via the keys=False default.
        return iter(self(keys=True))

    def __len__(self):
        return self._graph.number_of_edges()

    def __contains__(self, edge):
        if not isinstance(edge, tuple) or len(edge) < 2:
            return False
        u, v = edge[0], edge[1]
        succ = self._graph.succ
        if u not in succ or v not in succ[u]:
            return False
        if len(edge) == 2:
            return True
        key = edge[2]
        return key in succ[u][v]

    def __getitem__(self, edge):
        if not isinstance(edge, tuple) or len(edge) != 3:
            raise KeyError(edge)
        u, v, key = edge
        succ = self._graph.succ
        if u in succ and v in succ[u] and key in succ[u][v]:
            return succ[u][v][key]
        raise KeyError(edge)

    def __call__(self, nbunch=None, data=False, keys=False, default=None):
        # br-r37-c1-msf5j: live wrapper for default args (see
        # _MultiGraphEdgeView.__call__).
        if nbunch is None and data is False and keys is False:
            return _LiveMultiEdgeCallView(self._graph, directed=True)
        result = _EdgeListWithSetAlgebra()
        for source in self._graph.nbunch_iter(nbunch):
            for target, keyed_attrs in self._graph.succ[source].items():
                for key, attrs in keyed_attrs.items():
                    if data is True and keys:
                        result.append((source, target, key, attrs))
                    elif data is True:
                        result.append((source, target, attrs))
                    elif data is False and keys:
                        result.append((source, target, key))
                    elif data is False:
                        result.append((source, target))
                    elif keys:
                        result.append((source, target, key, attrs.get(data, default)))
                    else:
                        result.append((source, target, attrs.get(data, default)))
        return result

    keys = _multi_edge_keys
    items = _multi_edge_items
    values = _multi_edge_values
    get = _multi_edge_get


def _multidigraph_edges(self):
    return _MultiDiGraphEdgeView(self)


def _simple_graph_adjacency(self):
    # br-adjiter: nx.Graph.adjacency() returns a dict_itemiterator — an
    # iterator, not a materialised list. User code calling
    # ``next(G.adjacency())`` TypeErrored on fnx previously. Yield
    # lazily so the contract matches.
    if isinstance(self, _FilteredGraphView):
        return ((node, FilterAtlas(self, node)) for node in self)
    return ((node, self.adj[node]) for node in self)


def _multigraph_adjacency(self):
    """br-adjiter: return a generator matching nx.MultiGraph.adjacency."""
    return ((node, self.adj[node]) for node in self)


_GRAPH_COPY = Graph.copy
