def _networkx_graph_for_parity(G):
    if isinstance(G, (Graph, DiGraph, MultiGraph, MultiDiGraph)):
        from franken_networkx.backend import _fnx_to_nx

        return _fnx_to_nx(G)
    return G


def _networkx_graph_for_traversal_parity(G):
    if not isinstance(G, (Graph, DiGraph, MultiGraph, MultiDiGraph)):
        return G

    if G.is_multigraph():
        graph = _nx.MultiDiGraph() if G.is_directed() else _nx.MultiGraph()
    else:
        graph = _nx.DiGraph() if G.is_directed() else _nx.Graph()

    graph.graph.update(dict(G.graph))
    node_view = getattr(G, "nodes", None)
    for node in G:
        if node_view is not None:
            graph.add_node(node, **dict(node_view[node]))
        else:
            graph.add_node(node)

    seen = set()
    for u in G:
        if G.is_multigraph():
            for v, keyed_attrs in G.adj[u].items():
                if not G.is_directed():
                    edge_id = frozenset((u, v))
                    if edge_id in seen:
                        continue
                    seen.add(edge_id)
                for key, attrs in keyed_attrs.items():
                    graph.add_edges_from([(u, v, key, dict(attrs))])
        else:
            for v, attrs in G.adj[u].items():
                if not G.is_directed():
                    edge_id = frozenset((u, v))
                    if edge_id in seen:
                        continue
                    seen.add(edge_id)
                graph.add_edge(u, v, **dict(attrs))

    return graph


def _path_query_has_missing_nodes(G, source=None, target=None):
    return (source is not None and source not in G) or (
        target is not None and target not in G
    )


def _has_negative_edge_weight_for_dijkstra(G, weight):
    if not isinstance(weight, str):
        return False

    if G.is_multigraph():
        edge_iter = G.edges(keys=True, data=True)
        attrs_iter = (attrs for _, _, _, attrs in edge_iter)
    else:
        edge_iter = G.edges(data=True)
        attrs_iter = (attrs for _, _, attrs in edge_iter)

    for attrs in attrs_iter:
        value = attrs.get(weight, 1)
        if isinstance(value, numbers.Real) and math.isfinite(value) and value < 0:
            return True
    return False


def _should_delegate_dijkstra_to_networkx(G, weight):
    if callable(weight):
        return True
    return _has_negative_edge_weight_for_dijkstra(G, weight)


def _graph_has_nonunit_weight(G, weight):
    """br-dijkignoreweight: the Rust single_source_dijkstra
    (and its family) silently returns hop-count distances — not
    weighted distances — when edges carry non-unit weight values.
    This check detects that case so the single_source wrappers can
    route to nx. Different from
    _has_negative_edge_weight_for_dijkstra because we also need to
    catch positive non-unit weights (the Rust path treats weight=1.5
    as unweighted).
    """
    if not isinstance(weight, str):
        return False
    for _, _, attrs in G.edges(data=True):
        if not isinstance(attrs, dict) or weight not in attrs:
            continue
        try:
            if float(attrs[weight]) != 1.0:
                return True
        except (TypeError, ValueError):
            return True
    return False


def _should_delegate_bellman_ford_to_networkx(weight):
    return callable(weight)


def _should_delegate_floyd_warshall_to_networkx(weight):
    return callable(weight)


def _should_delegate_astar_to_networkx(weight, cutoff=None):
    return callable(weight) or cutoff is not None


def _should_delegate_negative_edge_cycle_to_networkx(G, weight, heuristic):
    return (
        G.is_directed()
        or callable(weight)
        or not isinstance(heuristic, bool)
        or not heuristic
    )


def _raise_translated_networkx_exception(exc):
    import networkx as nx

    if isinstance(exc, nx.NetworkXException):
        translated_type = globals().get(type(exc).__name__)
        if (
            isinstance(translated_type, type)
            and issubclass(translated_type, Exception)
            and translated_type is not type(exc)
        ):
            raise translated_type(*exc.args) from exc
    raise exc


def _call_networkx_for_parity(name, G, /, *args, **kwargs):
    import networkx as nx

    # br-parityrec: if the user configured the nx dispatcher to route to
    # franken_networkx (``nx.config.backend_priority = ["franken_networkx"]``),
    # then calling `getattr(nx, name)(...)` re-enters the dispatcher and
    # bounces right back into this helper — infinite recursion. Forcing
    # ``backend="networkx"`` here bypasses dispatch so parity fallbacks
    # always reach nx's pure-Python implementation. nx's `_dispatchable`
    # decorator honours an explicit `backend` kwarg even when the function
    # is already dispatched.
    kwargs.setdefault("backend", "networkx")
    try:
        result = getattr(nx, name)(_networkx_graph_for_parity(G), *args, **kwargs)
    except Exception as exc:
        _raise_translated_networkx_exception(exc)

    if isinstance(result, Iterator):
        def _wrapped_iterator():
            try:
                yield from result
            except Exception as exc:
                _raise_translated_networkx_exception(exc)

        return _wrapped_iterator()

    return result


def _complement_via_nx(G):
    """Private helper (br-zzcm9): run nx.complement on a MultiGraph and
    rebuild the result as a fnx.MultiGraph/MultiDiGraph. Kept behind an
    underscored name so the public ``complement`` wrapper stays
    PY_WRAPPER in the coverage classifier.
    """
    from franken_networkx.readwrite import _from_nx_graph

    nx_result = _call_networkx_for_parity("complement", G)
    return _from_nx_graph(nx_result)


def _random_generator_subset(seq, m, rng):
    """Return m unique elements from a repeated-node population."""
    targets = set()
    while len(targets) < m:
        targets.add(rng.choice(seq))
    return targets


def _call_networkx_submodule_for_parity(submodule_path, name, G, /, *args, **kwargs):
    """Same contract as ``_call_networkx_for_parity`` but resolves the
    callable from a dotted nx submodule path (e.g.
    ``"algorithms.community"``) for functions that upstream nx does
    not re-export at the top level.
    """
    import importlib

    submodule = importlib.import_module(f"networkx.{submodule_path}")
    # br-parityrec: mirror the top-level helper's dispatch-bypass. Without
    # this, `nx.config.backend_priority = ["franken_networkx"]` causes the
    # submodule call to re-enter fnx → infinite recursion.
    kwargs.setdefault("backend", "networkx")
    try:
        result = getattr(submodule, name)(
            _networkx_graph_for_parity(G), *args, **kwargs
        )
    except Exception as exc:
        _raise_translated_networkx_exception(exc)

    if isinstance(result, Iterator):
        def _wrapped_iterator():
            try:
                yield from result
            except Exception as exc:
                _raise_translated_networkx_exception(exc)

        return _wrapped_iterator()

    return result


def _validate_shortest_path_length_source_query(G, source, weight, method):
    if weight is None:
        if source not in G:
            raise NodeNotFound(f"Source {source} is not in G")
        return

    hash(source)

    if source in G:
        return

    if method == "dijkstra":
        raise NodeNotFound(f"Node {source} not found in graph")

    raise NodeNotFound(f"Source {source} not in G")


def average_shortest_path_length(G, weight=None, method=None):
    """Return the average shortest path length.

    Matches ``networkx.average_shortest_path_length`` signature.
    """
    if method not in (None, "unweighted", "dijkstra", "bellman-ford"):
        raise ValueError(f"method not supported: {method}")
    # br-asplint: nx returns literal int 0 for the single-node graph
    # (no divisions happen on that code path); fnx's Rust-native path
    # returns 0.0 float. Match nx's exact type so isinstance(..., int)
    # checks downstream don't diverge.
    if G.number_of_nodes() == 1:
        return 0
    if weight is not None and method in (None, "dijkstra") and _should_delegate_dijkstra_to_networkx(G, weight):
        kwargs = {"weight": weight}
        if method is not None:
            kwargs["method"] = method
        return _call_networkx_for_parity("average_shortest_path_length", G, **kwargs)
    return _raw_average_shortest_path_length(G, weight=weight, method=method)


def dijkstra_path(G, source, target, weight="weight"):
    if _should_delegate_dijkstra_to_networkx(G, weight):
        return _call_networkx_for_parity(
            "dijkstra_path", G, source, target, weight=weight
        )
    if source not in G:
        raise NodeNotFound(f"Node {source} not found in graph")
    if target not in G:
        raise NetworkXNoPath(f"No path to {target}.")
    try:
        return _raw_dijkstra_path(G, source, target, weight=weight)
    except NetworkXNoPath as exc:
        raise NetworkXNoPath(f"No path to {target}.") from exc


def _path_length_preserving_weight_type(G, path, weight):
    if weight is None:
        return len(path) - 1

    total = 0
    if G.is_multigraph():
        for node, neighbor in itertools.pairwise(path):
            total += min(attrs.get(weight, 1) for attrs in G[node][neighbor].values())
        return total

    for node, neighbor in itertools.pairwise(path):
        total += G[node][neighbor].get(weight, 1)
    return total


def bellman_ford_path(G, source, target, weight="weight"):
    if _should_delegate_bellman_ford_to_networkx(weight):
        return _call_networkx_for_parity(
            "bellman_ford_path", G, source, target, weight=weight
        )
    if source not in G:
        raise NodeNotFound(f"Source {source} not in G")
    if target not in G:
        raise NetworkXNoPath(f"Target {target} cannot be reached from given sources")
    try:
        return _raw_bellman_ford_path(G, source, target, weight=weight)
    except NetworkXNoPath as exc:
        raise NetworkXNoPath(
            f"Target {target} cannot be reached from given sources"
        ) from exc
    except NetworkXUnbounded as exc:
        # br-r37-c1-wtjho: the Rust impl says "Negative cost cycle
        # detected."; nx uses "Negative cycle detected." (no "cost").
        # Re-raise with nx's exact wording for drop-in error matching.
        if "cost cycle" in str(exc):
            raise NetworkXUnbounded("Negative cycle detected.") from exc
        raise


def shortest_path(G, source=None, target=None, weight=None, method="dijkstra"):
    if method not in ("dijkstra", "bellman-ford"):
        raise ValueError(f"method not supported: {method}")
    if _path_query_has_missing_nodes(G, source=source, target=target):
        return _call_networkx_for_parity(
            "shortest_path",
            G,
            source=source,
            target=target,
            weight=weight,
            method=method,
        )
    if weight is not None:
        if method == "dijkstra" and _should_delegate_dijkstra_to_networkx(G, weight):
            return _call_networkx_for_parity(
                "shortest_path",
                G,
                source=source,
                target=target,
                weight=weight,
                method=method,
            )
        if method == "bellman-ford" and _should_delegate_bellman_ford_to_networkx(weight):
            return _call_networkx_for_parity(
                "shortest_path",
                G,
                source=source,
                target=target,
                weight=weight,
                method=method,
            )
    result = _raw_shortest_path(G, source=source, target=target, weight=weight, method=method)
    if source is None and target is None and isinstance(result, dict):
        # networkx returns a generator of (source, paths_dict) pairs when both
        # endpoints are omitted (dispatches to all_pairs_*). The Rust native
        # path materializes the full dict-of-dicts; convert to match contract.
        return ((src, paths) for src, paths in result.items())
    if source is not None and target is None and isinstance(result, dict):
        # br-r37-c1-62jy2: nx returns the dict in distance-order (BFS
        # for unweighted, Dijkstra for weighted) from source. Reorder.
        try:
            lengths = shortest_path_length(
                G, source=source, target=None, weight=weight, method=method,
            )
            if isinstance(lengths, dict):
                order = _reorder_by_distance(dict(lengths), G=G, source=source)
                result = {k: result[k] for k in order if k in result}
        except Exception:
            pass
    return result


def shortest_path_length(G, source=None, target=None, weight=None, method="dijkstra"):
    """Return shortest path length between source and target.

    If *source* and *target* are both None, return an iterator over
    ``(node, dict)`` pairs for all nodes.
    If only *source* is given, return a dict mapping target to length.
    If both are given, return a single number.
    Matches ``networkx.shortest_path_length``.
    """
    if method not in ("dijkstra", "bellman-ford"):
        raise ValueError(f"method not supported: {method}")
    if _path_query_has_missing_nodes(G, source=source, target=target):
        return _call_networkx_for_parity(
            "shortest_path_length",
            G,
            source=source,
            target=target,
            weight=weight,
            method=method,
        )

    if weight is not None:
        if method == "dijkstra" and _should_delegate_dijkstra_to_networkx(G, weight):
            return _call_networkx_for_parity(
                "shortest_path_length",
                G,
                source=source,
                target=target,
                weight=weight,
                method=method,
            )
        if method == "bellman-ford" and _should_delegate_bellman_ford_to_networkx(weight):
            return _call_networkx_for_parity(
                "shortest_path_length",
                G,
                source=source,
                target=target,
                weight=weight,
                method=method,
            )

    if source is not None and target is not None:
        if weight is not None and method == "bellman-ford":
            return bellman_ford_path_length(G, source, target, weight=weight)
        if weight is not None:
            return dijkstra_path_length(G, source, target, weight=weight)
        return _shortest_path_length_raw(G, source, target, weight=weight)

    if source is not None:
        _validate_shortest_path_length_source_query(G, source, weight, method)
        if weight is not None:
            if method == "bellman-ford":
                return dict(single_source_bellman_ford_path_length(G, source, weight=weight))
            return dict(single_source_dijkstra_path_length(G, source, weight=weight))
        return dict(single_source_shortest_path_length(G, source))

    if target is not None:
        if weight is not None:
            if method == "bellman-ford":
                if G.is_directed():
                    return dict(
                        single_source_bellman_ford_path_length(
                            G.reverse(), target, weight=weight
                        )
                    )
                return dict(single_source_bellman_ford_path_length(G, target, weight=weight))
            if G.is_directed():
                all_pairs = dict(all_pairs_dijkstra_path_length(G, weight=weight))
                return {node: dists[target] for node, dists in all_pairs.items() if target in dists}
            return dict(single_source_dijkstra_path_length(G, target, weight=weight))
        return dict(single_target_shortest_path_length(G, target))
        
    if weight is not None:
        if method == "bellman-ford":
            all_pairs = dict(all_pairs_bellman_ford_path_length(G, weight=weight))
        else:  # dijkstra
            all_pairs = dict(all_pairs_dijkstra_path_length(G, weight=weight))
    else:
        # all_pairs_shortest_path_length now returns a generator of pairs;
        # materialise once to support repeated source-key lookups below.
        all_pairs = dict(all_pairs_shortest_path_length(G))
    return ((node, all_pairs[node]) for node in G.nodes())


def has_path(G, source, target):
    if _path_query_has_missing_nodes(G, source=source, target=target):
        return _call_networkx_for_parity("has_path", G, source, target)
    return _raw_has_path(G, source, target)


# Algorithm functions — connectivity
from franken_networkx._fnx import (
    articulation_points as _raw_articulation_points,
    bridges as _raw_bridges,
    connected_components as _raw_connected_components,
    edge_connectivity as _raw_edge_connectivity,
    is_connected,
    minimum_node_cut as _raw_minimum_node_cut,
    node_connectivity as _raw_node_connectivity,
    number_connected_components,
)


def minimum_node_cut(
    G, s=None, t=None, flow_func=None, *, backend=None, **backend_kwargs
):
    """Return the minimum node cut separating s from t.

    br-mncutG: first parameter is ``G`` to match nx exactly — the Rust
    binding exposed it as lowercase ``g``, breaking
    ``minimum_node_cut(G=graph)`` kwarg-style drop-in calls.

    br-r37-c1-5jbv9: when multiple equally-small cuts exist, the Rust
    binding picked a different (but equally valid) cut from nx — the
    choice depends on internal adj-iteration / DFS-augmenting-path
    traversal. Delegate to nx so the chosen cut matches its
    ``connectivity_augmentation``-aware contract exactly.
    """
    _validate_backend_dispatch_keywords("minimum_node_cut", backend, backend_kwargs)
    return _call_networkx_for_parity(
        "minimum_node_cut", G, s=s, t=t, flow_func=flow_func,
    )


def connected_components(G):
    """Generate connected components.

    Yields sets of nodes, one set per component. Matches the upstream
    ``networkx.connected_components`` contract (generator of sets), not
    the Rust-native list-of-list shape (franken_networkx-v1nwd).
    """
    for component in _raw_connected_components(G):
        yield set(component)


def articulation_points(G):
    """Yield articulation points of ``G``.

    Matches upstream's generator contract (franken_networkx-v1nwd).

    br-r37-c1-9kyjl: nx yields APs in DFS-discovery order; the Rust
    binding emits them sorted/canonically. Delegate so iteration order
    matches nx exactly.
    """
    yield from _call_networkx_for_parity("articulation_points", G)


def bridges(G, root=None):
    """Generate all bridges in a graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    root : node, optional
        A node in the graph. If specified, only the bridges in the
        connected component containing root are yielded.

    Yields
    ------
    edge
        Bridges in the graph.
    """
    if root is not None:
        yield from _call_networkx_for_parity("bridges", G, root=root)
        return
    if G.is_multigraph():
        # br-zzcm9: a parallel edge pair is never a bridge — removing
        # one leaves the other connecting u and v, so connectivity is
        # preserved. The Rust native bridges pass treats the simple
        # projection, which misreports parallel pairs as bridges.
        for u, v in _raw_bridges(G):
            if len(G[u][v]) == 1:
                yield (u, v)
        return
    # br-r37-c1-h83lo: nx yields bridges in DFS-discovery order; the
    # Rust binding emits them in canonical/alphabetical order.
    # Delegate so iteration order matches nx.
    yield from _call_networkx_for_parity("bridges", G)


def is_tree(G, *, backend=None, **backend_kwargs):
    """Return True if ``G`` is a tree.

    A tree is a connected graph with ``n - 1`` edges and no cycles. On a
    MultiGraph, parallel edges create cycles, so br-zzcm9 requires we
    count parallels rather than relying on the simple-projection native
    path (which overcounts nodes-without-parallels as trees).
    """
    _validate_backend_dispatch_keywords("is_tree", backend, backend_kwargs)
    if G.is_multigraph():
        n = G.number_of_nodes()
        m = G.number_of_edges()  # multigraph counts parallels
        if n == 0:
            raise NetworkXPointlessConcept("G has no nodes.")
        return m == n - 1 and is_connected(G)
    return _raw_is_tree(G)


def is_forest(G, *, backend=None, **backend_kwargs):
    """Return True if ``G`` is a forest (disjoint union of trees).

    MultiGraph parallels create cycles (br-zzcm9); verify each
    connected component is a tree counting parallels.
    """
    _validate_backend_dispatch_keywords("is_forest", backend, backend_kwargs)
    if G.is_multigraph():
        if G.number_of_nodes() == 0:
            raise NetworkXPointlessConcept("G has no nodes.")
        for component in connected_components(G):
            sub = G.subgraph(component)
            # |E| = |V| - 1 and connected → tree
            if sub.number_of_edges() != sub.number_of_nodes() - 1:
                return False
        return True
    return _raw_is_forest(G)


def complement(G):
    """Return the graph complement of ``G``.

    For MultiGraph inputs (br-zzcm9), delegate to the upstream nx
    implementation since the Rust native complement rejects them with
    TypeError; nx's complement on a MultiGraph returns a MultiGraph
    with the non-edges (between each pair of distinct nodes, one edge
    per missing pair — matches a simple-graph complement structure).
    """
    if G.is_multigraph():
        return _complement_via_nx(G)
    return _raw_complement(G)


def node_connectivity(G, s=None, t=None, flow_func=None):
    """Return the node connectivity of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    s : node, optional
        Source node.
    t : node, optional
        Target node.
    flow_func : function, optional
        A function for computing the maximum flow between a pair of nodes.

    Returns
    -------
    int
        The node connectivity of G.
    """
    if len(G) == 0:
        # Match nx's contract: connectivity is undefined for the null
        # graph (br-r37-c1-turq0). The Rust impl silently returned 0.
        raise NetworkXPointlessConcept(
            "Connectivity is undefined for the null graph."
        )
    if flow_func is not None:
        return _call_networkx_for_parity(
            "node_connectivity",
            G,
            s=s,
            t=t,
            flow_func=flow_func,
        )
    # Multigraphs with parallel edges bump the min-degree bound above
    # the simple-graph κ = n−1 ceiling (a node with k parallel edges to a
    # neighbour contributes k to its degree). networkx uses that bound
    # when every node pair is adjacent, so on e.g. K3 with parallel edges
    # it returns the higher min-degree value; the Rust path collapses
    # parallel edges and returns the simple-graph answer. Delegate
    # multigraph inputs to networkx to preserve parity.
    if G.is_multigraph():
        return _call_networkx_for_parity(
            "node_connectivity",
            G,
            s=s,
            t=t,
        )
    return _raw_node_connectivity(G, s=s, t=t)


def edge_connectivity(G, s=None, t=None, flow_func=None, cutoff=None):
    """Return the edge connectivity of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph.
    s : node, optional
        Source node.
    t : node, optional
        Target node.
    flow_func : function, optional
        A function for computing the maximum flow between a pair of nodes.
    cutoff : int, optional
        If specified, stop computing when connectivity is found to be at least cutoff.

    Returns
    -------
    int
        The edge connectivity of G.
    """
    if len(G) == 0:
        # Match nx's contract: connectivity is undefined for the null
        # graph (br-r37-c1-turq0). The Rust impl silently returned 0.
        raise NetworkXPointlessConcept(
            "Connectivity is undefined for the null graph."
        )
    if flow_func is not None:
        return _call_networkx_for_parity(
            "edge_connectivity",
            G,
            s=s,
            t=t,
            flow_func=flow_func,
            cutoff=cutoff,
        )
    # Multigraphs: the Rust implementation collapses parallel edges and
    # returns the simple-graph edge-connectivity (and as a float), whereas
    # networkx counts parallel edges and returns an int. Delegate to keep
    # parity with nx on MultiGraph / MultiDiGraph inputs.
    if G.is_multigraph():
        return _call_networkx_for_parity(
            "edge_connectivity",
            G,
            s=s,
            t=t,
            cutoff=cutoff,
        )
    # edge_connectivity is a structural graph property — it counts edges,
    # not flow capacity. The Rust dispatcher incorrectly honours any
    # ``capacity`` edge attribute and returns the weighted max-flow
    # value instead (franken_networkx-8ud1m). Strip any capacity attrs
    # into a scrubbed copy so the underlying max-flow reduces to unit
    # capacities and the returned integer is the edge cardinality.
    has_capacity = any(
        "capacity" in d for _, _, d in G.edges(data=True)
    )
    if has_capacity:
        scrubbed = type(G)()
        scrubbed.graph.update(dict(G.graph))
        scrubbed.add_nodes_from((n, dict(d)) for n, d in G.nodes(data=True))
        if G.is_multigraph():
            scrubbed.add_edges_from(
                (u, v, key, {k: val for k, val in d.items() if k != "capacity"})
                for u, v, key, d in G.edges(keys=True, data=True)
            )
        else:
            scrubbed.add_edges_from(
                (u, v, {k: val for k, val in d.items() if k != "capacity"})
                for u, v, d in G.edges(data=True)
            )
        G = scrubbed
    # Rust returns a float via the max-flow pipeline; networkx returns an
    # int because edge_connectivity is a cardinality. Coerce to int when
    # the value is exactly integral (it always is for unit capacities).
    result = _raw_edge_connectivity(G, s=s, t=t, cutoff=cutoff)
    if isinstance(result, float) and result.is_integer():
        return int(result)
    return result


def local_edge_connectivity(
    G,
    s,
    t,
    flow_func=None,
    auxiliary=None,
    residual=None,
    cutoff=None,
):
    """Return the local edge connectivity between ``s`` and ``t``."""
    _validate_flow_func_selector(flow_func)
    return edge_connectivity(
        G,
        s=s,
        t=t,
        cutoff=cutoff,
    )


def local_node_connectivity(
    G,
    s,
    t,
    flow_func=None,
    auxiliary=None,
    residual=None,
    cutoff=None,
):
    """Return the local node connectivity between ``s`` and ``t``."""
    _validate_flow_func_selector(flow_func)
    del auxiliary, residual
    return node_connectivity(G, s=s, t=t, cutoff=cutoff)


