# Algorithm functions — matching
from franken_networkx._fnx import (
    max_weight_matching as _raw_max_weight_matching,
    maximal_matching,
    min_edge_cover as _raw_min_edge_cover,
    min_weight_matching as _raw_min_weight_matching,
)


def min_weight_matching(G, weight="weight"):
    """Compute a minimum-weight matching in the graph.

    Returns a set of edges (2-tuples).

    br-r37-c1-fs3bl: same family pattern as br-r37-c1-kpnc8
    (max_weight_matching). The Rust binding returned matched pairs
    with different tuple directions than nx — the matching choice
    itself was correct (same nodes paired), but per-pair tuples
    flipped (e.g. ``(d, e)`` vs ``(e, d)``). Drop-in code comparing
    the result against a reference set broke. Delegate to nx so the
    chosen matching and per-pair tuple direction match nx exactly.

    Multigraph inputs project to a simple Graph (taking the
    *minimum* weight per parallel edge) before delegation, mirroring
    the max_weight_matching wrapper.
    """
    if G.is_multigraph():
        projected = (DiGraph if G.is_directed() else Graph)()
        projected.add_nodes_from(G.nodes(data=True))
        for u, v, data in G.edges(data=True):
            edge_weight = data.get(weight, 1)
            if projected.has_edge(u, v):
                if edge_weight < projected[u][v].get(weight, 1):
                    projected[u][v][weight] = edge_weight
            else:
                projected.add_edge(u, v, **{weight: edge_weight})
        target = projected
    else:
        target = G
    return _call_networkx_for_parity("min_weight_matching", target, weight=weight)


def max_weight_matching(G, maxcardinality=False, weight="weight"):
    """Compute a maximum-weight matching in the graph.

    Returns a set of edges (2-tuples).

    br-r37-c1-kpnc8: the Rust binding's matching returned tuples in a
    different direction than nx (e.g. (u, v) where nx returns (v, u))
    and on graphs with multiple equally-optimal matchings, picked a
    different valid choice from nx's DFS-augmenting-path traversal.
    Drop-in code that compared the matching against a reference set
    of (u, v) pairs broke. Delegate to nx so the chosen matching and
    the per-pair tuple direction match nx's contract exactly.

    nx's max_weight_matching is ``@not_implemented_for("multigraph")``,
    but the previous Rust binding accepted MultiGraph by collapsing
    parallel edges. Preserve that capability by projecting the
    MultiGraph to a simple Graph (taking the max ``weight`` per edge)
    before delegating.
    """
    if G.is_multigraph():
        projected = (DiGraph if G.is_directed() else Graph)()
        projected.add_nodes_from(G.nodes(data=True))
        for u, v, data in G.edges(data=True):
            edge_weight = data.get(weight, 1)
            if projected.has_edge(u, v):
                if edge_weight > projected[u][v].get(weight, 1):
                    projected[u][v][weight] = edge_weight
            else:
                projected.add_edge(u, v, **{weight: edge_weight})
        target = projected
    else:
        target = G
    return _call_networkx_for_parity(
        "max_weight_matching", target,
        maxcardinality=maxcardinality, weight=weight,
    )


def min_edge_cover(G, matching_algorithm=None):
    """Return a minimum edge cover of the graph.

    Parameters
    ----------
    G : graph
        An undirected graph (raises for directed/multigraph).
    matching_algorithm : function, optional
        A function taking ``G`` and returning either a set of 2-tuples
        (matching edges) or a dict mapping each matched node to its
        mate. Defaults to :func:`max_weight_matching` with
        ``maxcardinality=True``.

    Returns
    -------
    set
        Set of edges forming a minimum edge cover. Bipartite matching
        algorithms (dict-returning) produce both ``(u, v)`` and
        ``(v, u)`` directions per edge, matching nx's contract.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not G.edges() and G.number_of_nodes() > 0:
        raise NetworkXError(
            "Graph has a node with no edge incident on it, "
            "so no edge cover exists."
        )

    if matching_algorithm is None:
        matching = max_weight_matching(G, maxcardinality=True)
    else:
        matching = matching_algorithm(G)

    try:
        # bipartite algos return dict — convert
        min_cover = set(matching.items())
        bipartite_cover = True
    except AttributeError:
        min_cover = set(matching)
        bipartite_cover = False

    covered = {u for e in min_cover for u in e}
    uncovered = set(G.nodes()) - covered
    for v in uncovered:
        nbrs = iter(G.neighbors(v))
        u = next(nbrs)
        min_cover.add((u, v))
        if bipartite_cover:
            min_cover.add((v, u))
    return min_cover


# Algorithm functions — flow
from franken_networkx._fnx import (
    maximum_flow as _raw_maximum_flow,
    maximum_flow_value as _raw_maximum_flow_value,
    minimum_cut as _minimum_cut_raw,
    minimum_cut_value as _minimum_cut_value_raw,
)


def _all_flow_caps_integral(G, capacity):
    """Return True when every edge in G has an integer capacity under
    the given attr name (or the default 1). Used to decide whether the
    flow result can be coerced back to int for nx-type parity
    (br-flowt).
    """
    for _, _, data in G.edges(data=True):
        val = data.get(capacity, 1) if isinstance(data, dict) else 1
        if isinstance(val, bool) or not isinstance(val, int):
            return False
    return True


def _coerce_flow_value(value, all_int):
    if not all_int:
        return value
    if isinstance(value, float) and value.is_integer():
        return int(value)
    return value


def _coerce_flow_dict(flow_dict, all_int):
    if not all_int:
        return flow_dict
    out = {}
    for u, inner in flow_dict.items():
        out[u] = {v: _coerce_flow_value(w, True) for v, w in inner.items()}
    return out


def _flow_has_infinite_capacity(flowG, capacity):
    """br-flowinf: the Rust max-flow residual-network builder treated
    missing / +inf edge capacities as effectively 1 (or 0), so any
    graph with an uncapacitated edge had its max-flow value silently
    undervalued (e.g. s->a(cap=5)->t(no cap) returned 1 instead of 5).
    Detect that case up-front and route to nx for correctness.
    """
    import math as _math
    for _, _, attrs in flowG.edges(data=True):
        cap = attrs.get(capacity, float("inf"))
        if cap is None:
            return True
        try:
            cap_f = float(cap)
        except (TypeError, ValueError):
            return True
        if _math.isinf(cap_f) or _math.isnan(cap_f):
            return True
    return False


def maximum_flow(flowG, _s, _t, capacity="capacity", flow_func=None, **kwargs):
    """Compute the maximum flow and flow dict between ``_s`` and ``_t``.

    br-flowt: nx returns int when all capacities are ints; the Rust
    native always returns float. Coerce back to int when inputs are
    integer-typed so `isinstance(flow_value, int)` matches nx.
    """
    if flow_func is not None or kwargs or _flow_has_infinite_capacity(flowG, capacity):
        return _call_networkx_for_parity(
            "maximum_flow", flowG, _s, _t, capacity=capacity,
            flow_func=flow_func, **kwargs,
        )
    flow_value, flow_dict = _raw_maximum_flow(flowG, _s, _t, capacity)
    all_int = _all_flow_caps_integral(flowG, capacity)
    return _coerce_flow_value(flow_value, all_int), _coerce_flow_dict(flow_dict, all_int)


def maximum_flow_value(flowG, _s, _t, capacity="capacity", flow_func=None, **kwargs):
    """Return just the max-flow value. nx-int parity when all caps int."""
    if flow_func is not None or kwargs or _flow_has_infinite_capacity(flowG, capacity):
        return _call_networkx_for_parity(
            "maximum_flow_value", flowG, _s, _t, capacity=capacity,
            flow_func=flow_func, **kwargs,
        )
    return _coerce_flow_value(
        _raw_maximum_flow_value(flowG, _s, _t, capacity),
        _all_flow_caps_integral(flowG, capacity),
    )


def _validate_flow_func_selector(flow_func):
    if flow_func is not None and not callable(flow_func):
        raise NetworkXError("flow_func has to be callable.")
    return flow_func


def _flow_capacity_value(u, v, attrs, capacity):
    del u, v
    raw_value = attrs.get(capacity, float("inf"))
    if raw_value is None:
        return None

    return float(raw_value)


def _build_flow_residual_network(G, capacity):
    if G.is_multigraph():
        raise NetworkXError("MultiGraph and MultiDiGraph not supported (yet).")

    residual = DiGraph()
    if hasattr(residual, "__networkx_cache__"):
        residual.__networkx_cache__ = None
    residual.add_nodes_from(G)

    edge_list = []
    for u, v, attrs in G.edges(data=True):
        if u == v:
            continue
        edge_capacity = _flow_capacity_value(u, v, attrs, capacity)
        if edge_capacity is None or edge_capacity <= 0:
            continue
        edge_list.append((u, v, edge_capacity))

    inf = (
        3 * sum(edge_capacity for _, _, edge_capacity in edge_list if edge_capacity != float("inf"))
        or 1
    )

    if G.is_directed():
        for u, v, edge_capacity in edge_list:
            residual_capacity = min(edge_capacity, inf)
            if not residual.has_edge(u, v):
                residual.add_edge(u, v, capacity=residual_capacity)
                residual.add_edge(v, u, capacity=0)
            else:
                residual[u][v]["capacity"] = residual_capacity
    else:
        for u, v, edge_capacity in edge_list:
            residual_capacity = min(edge_capacity, inf)
            residual.add_edge(u, v, capacity=residual_capacity)
            residual.add_edge(v, u, capacity=residual_capacity)

    residual.graph["inf"] = inf
    return residual


def _edmonds_karp_core(residual, source, sink, cutoff):
    inf = residual.graph["inf"]

    def augment(path):
        flow = inf
        path_iter = iter(path)
        left = next(path_iter)
        for right in path_iter:
            attrs = residual.succ[left][right]
            flow = min(flow, attrs["capacity"] - attrs["flow"])
            left = right

        if flow * 2 > inf:
            raise NetworkXUnbounded("Infinite capacity path, flow unbounded above.")

        path_iter = iter(path)
        left = next(path_iter)
        for right in path_iter:
            residual.succ[left][right]["flow"] += flow
            residual.succ[right][left]["flow"] -= flow
            left = right

        return flow

    def bidirectional_bfs():
        pred = {source: None}
        queue_from_source = [source]
        succ = {sink: None}
        queue_from_sink = [sink]

        while True:
            next_queue = []
            if len(queue_from_source) <= len(queue_from_sink):
                for left in queue_from_source:
                    for right, attrs in residual.succ[left].items():
                        if right not in pred and attrs["flow"] < attrs["capacity"]:
                            pred[right] = left
                            if right in succ:
                                return right, pred, succ
                            next_queue.append(right)
                if not next_queue:
                    return None, None, None
                queue_from_source = next_queue
            else:
                for right in queue_from_sink:
                    for left, attrs in residual.pred[right].items():
                        if left not in succ and attrs["flow"] < attrs["capacity"]:
                            succ[left] = right
                            if left in pred:
                                return left, pred, succ
                            next_queue.append(left)
                if not next_queue:
                    return None, None, None
                queue_from_sink = next_queue

    flow_value = 0
    while flow_value < cutoff:
        meeting_node, pred, succ = bidirectional_bfs()
        if pred is None:
            break

        path = [meeting_node]
        cursor = meeting_node
        while cursor != source:
            cursor = pred[cursor]
            path.append(cursor)
        path.reverse()

        cursor = meeting_node
        while cursor != sink:
            cursor = succ[cursor]
            path.append(cursor)

        flow_value += augment(path)

    return flow_value


def edmonds_karp(
    G,
    source,
    sink,
    capacity="capacity",
    residual=None,
    value_only=False,
    cutoff=None,
):
    """Find a maximum single-commodity flow using the Edmonds-Karp algorithm."""
    del value_only

    if source not in G:
        raise NetworkXError(f"node {source} not in graph")
    if sink not in G:
        raise NetworkXError(f"node {sink} not in graph")
    if source == sink:
        raise NetworkXError("source and sink are the same node")

    if residual is None:
        residual = _build_flow_residual_network(G, capacity)

    for node in residual:
        for attrs in residual[node].values():
            attrs["flow"] = 0

    if cutoff is None:
        cutoff = float("inf")

    residual.graph["flow_value"] = _edmonds_karp_core(residual, source, sink, cutoff)
    residual.graph["algorithm"] = "edmonds_karp"
    return residual


def _call_networkx_flow_for_parity(name, G, /, *args, **kwargs):
    import networkx as nx

    try:
        return getattr(nx.algorithms.flow, name)(
            _networkx_graph_for_parity(G), *args, **kwargs
        )
    except Exception as exc:
        _raise_translated_networkx_exception(exc)


