try:
    from franken_networkx._fnx import minimum_cycle_basis as _raw_minimum_cycle_basis
except ImportError:
    _raw_minimum_cycle_basis = None


def cycle_basis(G, root=None):
    """Return a minimum cycle basis of the graph.

    Matches upstream NetworkX: raises NetworkXNotImplemented on
    multigraph inputs before the basis computation runs, rather than
    silently returning ``[]``.

    br-r37-c1-j5swc: nx emits cycle node lists in DFS-discovery order
    through the chord-completion path (e.g. ['b','a','c']), but the
    Rust binding returns cycles in canonical-node order
    (e.g. ['a','b','c']). Delegate to nx so cycle node ordering matches
    its algorithmic contract exactly.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if root is not None:
        return _call_networkx_for_parity("cycle_basis", G, root=root)
    return _call_networkx_for_parity("cycle_basis", G)


def all_shortest_paths(G, source, target, weight=None, method="dijkstra"):
    if weight is not None and method not in {"dijkstra", "bellman-ford"}:
        raise ValueError(f"method not supported: {method}")
    if weight is not None and method == "dijkstra" and _should_delegate_dijkstra_to_networkx(G, weight):
        kwargs = {"weight": weight}
        if method is not None:
            kwargs["method"] = method
        return _call_networkx_for_parity("all_shortest_paths", G, source, target, **kwargs)
    if weight is not None and method == "bellman-ford":
        if not G.is_directed() or _should_delegate_bellman_ford_to_networkx(weight):
            kwargs = {"weight": weight}
            if method is not None:
                kwargs["method"] = method
            return _call_networkx_for_parity(
                "all_shortest_paths", G, source, target, **kwargs
            )
    return _raw_all_shortest_paths(G, source, target, weight=weight, method=method)


def all_simple_paths(
    G, source, target, cutoff=None, *, backend=None, **backend_kwargs
):
    """Yield all simple paths from *source* to *target*.

    ``target`` may be a single node OR an iterable of target nodes (list
    / set / etc.) - networkx yields paths whose endpoint is *any* node
    in the iterable, in DFS order over a single traversal. The Rust binding
    only handles a scalar target, so iterable-target inputs delegate to
    NetworkX to preserve the exact emission order.

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).
    """
    _validate_backend_dispatch_keywords("all_simple_paths", backend, backend_kwargs)
    if G.is_multigraph():
        yield from _call_networkx_for_parity(
            "all_simple_paths", G, source, target, cutoff=cutoff
        )
        return

    if source not in G:
        raise NodeNotFound(f"source node {source} not in graph")

    try:
        target_is_node = target in G
    except TypeError:
        target_is_node = False

    if not target_is_node:
        try:
            iter(target)
        except TypeError:
            pass
        else:
            yield from _call_networkx_for_parity(
                "all_simple_paths", G, source, target, cutoff=cutoff
            )
            return
        raise NodeNotFound(f"target node {target} not in graph")

    # Scalar target — Rust fast path.
    if source == target:
        yield [source]
        return
    yield from _rust_all_simple_paths(G, source, target, cutoff=cutoff)


