# Algorithm functions — traversal (DFS) — wrapped for sort_neighbors support
from franken_networkx._fnx import (
    dfs_edges as _dfs_edges_raw,
    dfs_postorder_nodes as _dfs_postorder_nodes_raw,
    dfs_predecessors as _dfs_predecessors_raw,
    dfs_preorder_nodes as _dfs_preorder_nodes_raw,
    dfs_successors as _dfs_successors_raw,
    dfs_tree as _dfs_tree_raw,
)


def _py_bfs_edges(G, source, depth_limit=None, sort_neighbors=None, reverse=False):
    """Python-level BFS with sort_neighbors support."""
    from collections import deque

    visited = {source}
    queue = deque([(source, 0)])
    max_depth = depth_limit if depth_limit is not None else float("inf")
    if reverse and G.is_directed():
        neighbor_iter = G.predecessors
    else:
        neighbor_iter = G.neighbors
    while queue:
        node, depth = queue.popleft()
        if depth >= max_depth:
            continue
        nbrs = list(neighbor_iter(node))
        if sort_neighbors is not None:
            nbrs = list(sort_neighbors(nbrs))
        for neighbor in nbrs:
            if neighbor not in visited:
                visited.add(neighbor)
                yield (node, neighbor)
                queue.append((neighbor, depth + 1))


def _py_dfs_labeled_edges(G, source=None, depth_limit=None, sort_neighbors=None):
    """Python-level DFS labeled edges with sort_neighbors support."""
    nodes = G if source is None else [source]
    if depth_limit is None:
        depth_limit = len(G)

    get_children = (
        G.neighbors
        if sort_neighbors is None
        else lambda n: iter(sort_neighbors(G.neighbors(n)))
    )

    visited = set()
    for start in nodes:
        if start in visited:
            continue
        yield start, start, "forward"
        visited.add(start)
        stack = [(start, get_children(start))]
        depth_now = 1
        while stack:
            parent, children = stack[-1]
            for child in children:
                if child in visited:
                    yield parent, child, "nontree"
                else:
                    yield parent, child, "forward"
                    visited.add(child)
                    if depth_now < depth_limit:
                        stack.append((child, iter(get_children(child))))
                        depth_now += 1
                        break
                    else:
                        yield parent, child, "reverse-depth_limit"
            else:
                stack.pop()
                depth_now -= 1
                if stack:
                    yield stack[-1][0], parent, "reverse"
        yield start, start, "reverse"


def _py_dfs_edges(G, source=None, depth_limit=None, sort_neighbors=None):
    """Python-level DFS with sort_neighbors support."""
    for u, v, label in _py_dfs_labeled_edges(
        G, source=source, depth_limit=depth_limit, sort_neighbors=sort_neighbors
    ):
        if label == "forward" and u != v:
            yield (u, v)


def bfs_edges(G, source, reverse=False, depth_limit=None, sort_neighbors=None):
    """Yield edges in BFS order from source.

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).
    """
    try:
        if sort_neighbors is not None:
            yield from _py_bfs_edges(G, source, depth_limit, sort_neighbors, reverse=reverse)
            return
        yield from _bfs_edges_raw(G, source, reverse=reverse, depth_limit=depth_limit)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc


def dfs_edges(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Yield edges in DFS order from source.

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).
    """
    try:
        if sort_neighbors is not None:
            yield from _py_dfs_edges(G, source, depth_limit, sort_neighbors)
            return
        yield from _dfs_edges_raw(G, source=source, depth_limit=depth_limit)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc


_EDGE_TRAVERSAL_FORWARD = "forward"
_EDGE_TRAVERSAL_REVERSE = "reverse"


def edge_bfs(G, source=None, orientation=None):
    """Iterate edges in breadth-first-search order, matching NetworkX."""
    nbunch_nodes = _global_nbunch_nodes(G, source)
    nodes = list(G) if nbunch_nodes is None else nbunch_nodes
    if not nodes:
        return

    directed = G.is_directed()
    if orientation is None:
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr)

    elif not directed or orientation == "original":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key, _EDGE_TRAVERSAL_FORWARD)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr, _EDGE_TRAVERSAL_FORWARD)

    elif orientation == "reverse":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.pred[node].items():
                    for key in keydict:
                        yield (nbr, node, key, _EDGE_TRAVERSAL_REVERSE)

        else:

            def edges_from(node):
                for nbr in G.pred[node]:
                    yield (nbr, node, _EDGE_TRAVERSAL_REVERSE)

    elif orientation == "ignore":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key, _EDGE_TRAVERSAL_FORWARD)
                for nbr, keydict in G.pred[node].items():
                    for key in keydict:
                        yield (nbr, node, key, _EDGE_TRAVERSAL_REVERSE)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr, _EDGE_TRAVERSAL_FORWARD)
                for nbr in G.pred[node]:
                    yield (nbr, node, _EDGE_TRAVERSAL_REVERSE)

    else:
        raise NetworkXError("invalid orientation argument.")

    if directed:

        def edge_id(edge):
            return edge[:-1] if orientation is not None else edge

    else:

        def edge_id(edge):
            return (frozenset(edge[:2]),) + edge[2:]

    check_reverse = directed and orientation in ("reverse", "ignore")
    visited_nodes = set(nodes)
    visited_edges = set()
    queue = deque((node, edges_from(node)) for node in nodes)

    while queue:
        _parent, children_edges = queue.popleft()
        for edge in children_edges:
            child = edge[0] if check_reverse and edge[-1] == _EDGE_TRAVERSAL_REVERSE else edge[1]
            if child not in visited_nodes:
                visited_nodes.add(child)
                queue.append((child, edges_from(child)))
            current_edge_id = edge_id(edge)
            if current_edge_id not in visited_edges:
                visited_edges.add(current_edge_id)
                yield edge


def edge_dfs(G, source=None, orientation=None):
    """Iterate edges in depth-first-search order, matching NetworkX."""
    nbunch_nodes = _global_nbunch_nodes(G, source)
    nodes = list(G) if nbunch_nodes is None else nbunch_nodes
    if not nodes:
        return

    directed = G.is_directed()
    if orientation is None:
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr)

    elif not directed or orientation == "original":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key, _EDGE_TRAVERSAL_FORWARD)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr, _EDGE_TRAVERSAL_FORWARD)

    elif orientation == "reverse":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.pred[node].items():
                    for key in keydict:
                        yield (nbr, node, key, _EDGE_TRAVERSAL_REVERSE)

        else:

            def edges_from(node):
                for nbr in G.pred[node]:
                    yield (nbr, node, _EDGE_TRAVERSAL_REVERSE)

    elif orientation == "ignore":
        if G.is_multigraph():

            def edges_from(node):
                for nbr, keydict in G.adj[node].items():
                    for key in keydict:
                        yield (node, nbr, key, _EDGE_TRAVERSAL_FORWARD)
                for nbr, keydict in G.pred[node].items():
                    for key in keydict:
                        yield (nbr, node, key, _EDGE_TRAVERSAL_REVERSE)

        else:

            def edges_from(node):
                for nbr in G.adj[node]:
                    yield (node, nbr, _EDGE_TRAVERSAL_FORWARD)
                for nbr in G.pred[node]:
                    yield (nbr, node, _EDGE_TRAVERSAL_REVERSE)

    else:
        raise NetworkXError("invalid orientation argument.")

    if directed:

        def edge_id(edge):
            return edge[:-1] if orientation is not None else edge

    else:

        def edge_id(edge):
            return (frozenset(edge[:2]),) + edge[2:]

    check_reverse = directed and orientation in ("reverse", "ignore")
    visited_edges = set()
    visited_nodes = set()
    edges = {}

    for start_node in nodes:
        stack = [start_node]
        while stack:
            current_node = stack[-1]
            if current_node not in visited_nodes:
                edges[current_node] = edges_from(current_node)
                visited_nodes.add(current_node)

            try:
                edge = next(edges[current_node])
            except StopIteration:
                stack.pop()
            else:
                current_edge_id = edge_id(edge)
                if current_edge_id not in visited_edges:
                    visited_edges.add(current_edge_id)
                    stack.append(
                        edge[0]
                        if check_reverse and edge[-1] == _EDGE_TRAVERSAL_REVERSE
                        else edge[1]
                    )
                    yield edge


def bfs_predecessors(G, source, depth_limit=None, sort_neighbors=None):
    """Return (node, predecessor) pairs from BFS."""
    return (
        (child, parent)
        for parent, child in bfs_edges(
            G,
            source,
            depth_limit=depth_limit,
            sort_neighbors=sort_neighbors,
        )
    )


def bfs_successors(G, source, depth_limit=None, sort_neighbors=None):
    """Iterate (node, [successors]) pairs in BFS discovery order.

    Matches NetworkX's generator-of-pairs contract, with the source
    appearing first and subsequent parent nodes appearing in the order
    they were discovered by the BFS. Honours the ``sort_neighbors``
    callable when provided.
    """
    if sort_neighbors is not None:
        edge_source = _py_bfs_edges(G, source, depth_limit, sort_neighbors)
    else:
        # Build edge stream from bfs_edges which already emits in BFS
        # discovery order (matching upstream on both graph and digraph
        # inputs with the same neighbour-iteration order).
        edge_source = bfs_edges(G, source, depth_limit=depth_limit)

    current_parent = None
    current_children = None
    for parent, child in edge_source:
        if parent != current_parent:
            if current_parent is not None:
                yield current_parent, current_children
            current_parent = parent
            current_children = [child]
        else:
            current_children.append(child)
    if current_parent is not None:
        yield current_parent, current_children
    else:
        yield source, []


def bfs_tree(G, source, reverse=False, depth_limit=None, sort_neighbors=None):
    """Return BFS tree rooted at source."""
    # Upstream returns an nx.DiGraph; round-trip through the fnx readwrite
    # converter so callers see an fnx.DiGraph (franken_networkx-3ehfp).
    from franken_networkx.readwrite import _from_nx_graph

    nx_result = _call_networkx_for_parity(
        "bfs_tree",
        G,
        source,
        reverse=reverse,
        depth_limit=depth_limit,
        sort_neighbors=sort_neighbors,
    )
    return _from_nx_graph(nx_result)


def dfs_predecessors(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Return (node, predecessor) dict from DFS.

    br-r37-c1-20swv: the Rust _dfs_predecessors_raw returned the dict
    with keys in Rust-internal order rather than nx's DFS-discovery
    order (e.g. fnx {'d':'c','e':'d','b':'a','c':'b'} vs nx
    {'b':'a','c':'b','d':'c','e':'d'}). Build the dict by walking
    dfs_edges so iteration order matches nx exactly. Values
    (parent for each node) were already correct.
    """
    try:
        preds = {}
        for u, v in dfs_edges(G, source=source, depth_limit=depth_limit, sort_neighbors=sort_neighbors):
            preds[v] = u
        return preds
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc


def dfs_successors(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Return (node, [successors]) dict from DFS.

    br-r37-c1-20swv: same dict-key-order drift as
    ``dfs_predecessors``. Build via dfs_edges walk so the dict's
    iteration order matches nx's DFS-discovery contract.
    """
    try:
        from collections import defaultdict
        succs = defaultdict(list)
        for u, v in dfs_edges(G, source=source, depth_limit=depth_limit, sort_neighbors=sort_neighbors):
            succs[u].append(v)
        return dict(succs)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc


def dfs_preorder_nodes(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Yield nodes in DFS preorder from source."""
    try:
        if sort_neighbors is not None:
            for _, v, label in _py_dfs_labeled_edges(
                G, source=source, depth_limit=depth_limit, sort_neighbors=sort_neighbors
            ):
                if label == "forward":
                    yield v
            return
        nodes = _dfs_preorder_nodes_raw(G, source=source, depth_limit=depth_limit)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc
    yield from nodes


def dfs_postorder_nodes(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Yield nodes in DFS postorder from source."""
    try:
        if sort_neighbors is not None:
            for _, v, label in _py_dfs_labeled_edges(
                G, source=source, depth_limit=depth_limit, sort_neighbors=sort_neighbors
            ):
                if label == "reverse":
                    yield v
            return
        nodes = _dfs_postorder_nodes_raw(G, source=source, depth_limit=depth_limit)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc
    yield from nodes


def dfs_tree(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """Return DFS tree rooted at source."""
    try:
        if sort_neighbors is not None:
            T = DiGraph()
            if source is None:
                T.add_nodes_from(G)
            else:
                T.add_node(source)
            for u, v in _py_dfs_edges(G, source, depth_limit, sort_neighbors):
                T.add_edge(u, v)
            return T
        return _dfs_tree_raw(G, source=source, depth_limit=depth_limit)
    except NodeNotFound as exc:
        raise NetworkXError(str(exc)) from exc


# Algorithm functions — reciprocity (wrapped to match NetworkX API)
def overall_reciprocity(G, *, backend=None, **backend_kwargs):
    """Compute the reciprocity for the whole graph."""
    _validate_backend_dispatch_keywords(
        "overall_reciprocity", backend, backend_kwargs
    )
    if G.is_multigraph() and not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected multigraph type")

    n_all_edge = G.number_of_edges()
    if n_all_edge == 0:
        raise NetworkXError("Not defined for empty graphs")

    n_overlap_edge = (n_all_edge - G.to_undirected().number_of_edges()) * 2
    return n_overlap_edge / n_all_edge


def _reciprocity_value_for_node(G, node):
    pred = set(G.predecessors(node))
    succ = set(G.successors(node))
    overlap = pred & succ
    n_total = len(pred) + len(succ)
    if n_total == 0:
        return None
    return 2 * len(overlap) / n_total


def reciprocity(G, nodes=None, *, backend=None, **backend_kwargs):
    """Compute reciprocity for a directed graph.

    If *nodes* is None, return the overall reciprocity of the graph (float).
    If *nodes* is a single node, return the reciprocity for that node (float).
    If *nodes* is an iterable of nodes, return a dict mapping each node to
    its reciprocity.  Matches ``networkx.reciprocity``.
    """
    _validate_backend_dispatch_keywords("reciprocity", backend, backend_kwargs)
    if nodes is None:
        return overall_reciprocity(G)

    if G.is_multigraph() and not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected multigraph type")
    if not G.is_directed():
        raise AttributeError(f"'{type(G).__name__}' object has no attribute 'predecessors'")

    try:
        if nodes in G:
            reciprocity_value = _reciprocity_value_for_node(G, nodes)
            if reciprocity_value is None:
                raise NetworkXError("Not defined for isolated nodes.")
            return reciprocity_value
    except TypeError:
        pass

    try:
        iterator = iter(nodes)
    except TypeError:
        raise NetworkXError(f"Node {nodes} is not in the graph.") from None

    result = {}
    for node in iterator:
        if node not in G:
            continue
        result[node] = _reciprocity_value_for_node(G, node)
    return result


# Algorithm functions — Wiener index
def wiener_index(G, weight=None, *, backend=None, **backend_kwargs):
    """Returns the Wiener index of the given graph."""
    _validate_backend_dispatch_keywords("wiener_index", backend, backend_kwargs)
    connected = is_strongly_connected(G) if G.is_directed() else is_connected(G)
    if not connected:
        return float("inf")

    def _single_source_unweighted_lengths(source):
        lengths = {source: 0}
        queue = deque([source])
        while queue:
            node = queue.popleft()
            next_distance = lengths[node] + 1
            for neighbor in G.neighbors(node):
                if neighbor in lengths:
                    continue
                lengths[neighbor] = next_distance
                queue.append(neighbor)
        return lengths

    def _single_source_weighted_lengths(source):
        distances = {source: 0.0}
        queue = [(0.0, next(counter), source)]

        while queue:
            distance, _, node = heappop(queue)
            if distance > distances[node]:
                continue

            for neighbor in G.neighbors(node):
                edge_data = G.get_edge_data(node, neighbor)
                if G.is_multigraph():
                    edge_weight = min(
                        attrs.get(weight, 1) for attrs in edge_data.values()
                    )
                else:
                    edge_weight = edge_data.get(weight, 1)

                candidate = distance + edge_weight
                if candidate < distances.get(neighbor, float("inf")):
                    distances[neighbor] = candidate
                    heappush(queue, (candidate, next(counter), neighbor))

        return distances

    if weight is None:
        total = sum(sum(_single_source_unweighted_lengths(node).values()) for node in G)
    else:
        counter = count()
        total = sum(sum(_single_source_weighted_lengths(node).values()) for node in G)

    return total if G.is_directed() else total / 2

# Algorithm functions — maximum spanning tree
from franken_networkx._fnx import (
    maximum_spanning_tree as _raw_maximum_spanning_tree,
)
# (maximum_spanning_edges wrapper defined earlier at the tree import site)


def minimum_spanning_tree(G, weight="weight", algorithm="kruskal", ignore_nan=False):
    """Return a minimum spanning tree or forest of an undirected weighted graph.

    Parameters
    ----------
    G : undirected graph
        An undirected graph.
    weight : str, optional (default='weight')
        Edge attribute key to use as weight.
    algorithm : str, optional (default='kruskal')
        Algorithm to use: 'kruskal', 'prim', or 'boruvka'.
    ignore_nan : bool, optional (default=False)
        If True, edges with NaN weights are ignored.

    Returns
    -------
    Graph
        A minimum spanning tree or forest.
    """
    # br-r37-c1-ow5fy: nx's @not_implemented_for('directed') raises
    # NetworkXNotImplemented; the Rust binding silently returned a
    # Graph result. MST is undefined on directed graphs (use
    # minimum_spanning_arborescence). Surface the standard error.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    # br-mstcallable: the Rust _raw_minimum_spanning_tree requires
    # ``weight`` to be a str; nx accepts a callable
    # ``weight(u, v, d) -> float`` (used to derive weights on the fly).
    # Route non-str weight values through nx.
    # br-mstweightwrong: the Rust MST implementation also returns
    # suboptimal (non-minimum) spanning trees on weighted graphs in
    # specific graph-construction patterns (e.g. cycle_graph(5) with
    # weights set post-construction: fnx picks an edge with weight 5
    # over an available weight-2 edge). Delegate any graph that
    # carries the weight attr on at least one edge — unweighted
    # graphs still hit the Rust fast path.
    if algorithm != "kruskal" or ignore_nan or not isinstance(weight, str) or _mst_has_weight_edge_attr(G, weight):
        # br-r37-c1-rtak4: _call_networkx_for_parity returns an
        # nx.Graph unchanged; rehydrate as fnx.Graph so downstream
        # fnx.* calls (is_connected, is_tree, etc.) accept it.
        return _minimum_spanning_tree_via_parity(G, weight, algorithm, ignore_nan)
    return _raw_minimum_spanning_tree(G, weight=weight)


def _minimum_spanning_tree_via_parity(G, weight, algorithm, ignore_nan):
    """br-r37-c1-nhz31: private helper keeps the public
    ``minimum_spanning_tree`` classified as PY_WRAPPER in the
    coverage matrix.
    """
    nx_result = _nx.minimum_spanning_tree(
        _networkx_graph_for_parity(G),
        weight=weight,
        algorithm=algorithm,
        ignore_nan=ignore_nan,
    )
    from franken_networkx.readwrite import _from_nx_graph
    return _from_nx_graph(nx_result, create_using=type(G)())


def _mst_has_weight_edge_attr(G, weight):
    """Return True if any edge in ``G`` has the named weight attribute.

    br-mstweightwrong: used to detect weighted graphs so the Rust
    Kruskal path (which returns suboptimal MSTs in some cases) is
    bypassed in favour of nx's reference implementation.
    """
    if not isinstance(weight, str):
        return False
    for _, _, attrs in G.edges(data=True):
        if isinstance(attrs, dict) and weight in attrs:
            return True
    return False


def maximum_spanning_tree(G, weight="weight", algorithm="kruskal", ignore_nan=False):
    """Return a maximum spanning tree or forest of an undirected weighted graph.

    Parameters
    ----------
    G : undirected graph
        An undirected graph.
    weight : str, optional (default='weight')
        Edge attribute key to use as weight.
    algorithm : str, optional (default='kruskal')
        Algorithm to use: 'kruskal', 'prim', or 'boruvka'.
    ignore_nan : bool, optional (default=False)
        If True, edges with NaN weights are ignored.

    Returns
    -------
    Graph
        A maximum spanning tree or forest.
    """
    # br-r37-c1-ow5fy: same directed-rejection guard as
    # minimum_spanning_tree.
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    # br-mstcallable / br-mstweightwrong: same MST-quality issue as
    # minimum_spanning_tree — the Rust path returns suboptimal trees
    # on weighted inputs. Route any weighted graph through nx.
    # br-r37-c1-rtak4: rehydrate the nx.Graph result as fnx.Graph
    # (otherwise downstream fnx.* calls reject the foreign type).
    if algorithm != "kruskal" or ignore_nan or not isinstance(weight, str) or _mst_has_weight_edge_attr(G, weight):
        return _maximum_spanning_tree_via_parity(G, weight, algorithm, ignore_nan)
    return _raw_maximum_spanning_tree(G, weight=weight)


def _maximum_spanning_tree_via_parity(G, weight, algorithm, ignore_nan):
    """br-r37-c1-nhz31: private helper keeps the public
    ``maximum_spanning_tree`` classified as PY_WRAPPER in the
    coverage matrix.
    """
    nx_result = _nx.maximum_spanning_tree(
        _networkx_graph_for_parity(G),
        weight=weight,
        algorithm=algorithm,
        ignore_nan=ignore_nan,
    )
    from franken_networkx.readwrite import _from_nx_graph
    return _from_nx_graph(nx_result, create_using=type(G)())


def greedy_color(G, strategy="largest_first", interchange=False):
    """Color a graph using various greedy strategies.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    strategy : str or function, optional (default='largest_first')
        Greedy strategy to use. Options include 'largest_first',
        'smallest_last', 'independent_set', 'connected_sequential_bfs',
        'connected_sequential_dfs', 'saturation_largest_first', or a function.
    interchange : bool, optional (default=False)
        Use interchange optimization (only valid with 'saturation_largest_first').

    Returns
    -------
    dict
        Dictionary mapping nodes to colors (integers starting at 0).
    """
    if interchange or callable(strategy):
        return _call_networkx_for_parity(
            "greedy_color",
            G,
            strategy=strategy,
            interchange=interchange,
        )
    # br-r37-c1-vevfq: nx returns the dict in the strategy's processing
    # order (e.g. for 'largest_first': nodes sorted by degree desc).
    # The Rust binding returns dict keys in arbitrary internal order.
    # Delegate to nx so iteration order matches exactly. Values are
    # identical between the two implementations.
    return _call_networkx_for_parity(
        "greedy_color",
        G,
        strategy=strategy,
        interchange=interchange,
    )


# Algorithm functions — condensation (wrapped to match NetworkX API)
from franken_networkx._fnx import condensation as _condensation_raw


def condensation(G, scc=None):
    """Return the condensation of G.

    The condensation of a directed graph contracts each strongly connected
    component into a single node. The resulting graph is a DAG.

    Returns a DiGraph C where each node has a 'members' attribute (the set
    of original nodes in that SCC) and C.graph['mapping'] maps original
    nodes to SCC indices. This matches the NetworkX API.
    """
    if scc is not None:
        cond_dg = DiGraph()
        mapping = {}
        members = {}
        components = [set(component) for component in scc]

        for idx, component in enumerate(components):
            members[idx] = component
            for node in component:
                mapping[node] = idx

        missing = set(G.nodes()) - set(mapping)
        if missing:
            raise NetworkXError(
                f"condensation scc is missing graph nodes: {sorted(missing)!r}"
            )

        cond_dg.add_nodes_from(range(len(components)))
        for idx, member_set in members.items():
            cond_dg.nodes[idx]["members"] = member_set

        for u, v in G.edges():
            cu = mapping[u]
            cv = mapping[v]
            if cu != cv:
                cond_dg.add_edge(cu, cv)

        cond_dg.graph["mapping"] = mapping
        return cond_dg

    # Match NetworkX's labeling: number SCCs in the order returned by
    # strongly_connected_components (which is reverse topological order,
    # sinks first). The Rust _condensation_raw uses a different internal
    # numbering, so rebuild on top of the public SCC iterator to stay
    # bit-compatible with nx.condensation's node labels and edge tuples.
    components = [set(component) for component in strongly_connected_components(G)]
    mapping = {}
    members = {}
    for idx, component in enumerate(components):
        members[idx] = component
        for node in component:
            mapping[node] = idx
    cond_dg = DiGraph()
    cond_dg.add_nodes_from(range(len(components)))
    for idx, member_set in members.items():
        cond_dg.nodes[idx]["members"] = member_set
    for u, v in G.edges():
        cu = mapping[u]
        cv = mapping[v]
        if cu != cv:
            cond_dg.add_edge(cu, cv)
    cond_dg.graph["mapping"] = mapping
    return cond_dg


# Algorithm functions — all-pairs shortest paths
from franken_networkx._fnx import (
    all_pairs_shortest_path as _raw_all_pairs_shortest_path,
    all_pairs_shortest_path_length as _raw_all_pairs_shortest_path_length,
)


def all_pairs_shortest_path(G, cutoff=None, *, backend=None, **backend_kwargs):
    """Return an iterator of (source, shortest-paths-dict) pairs.

    Matches NetworkX's public contract: the underlying Rust
    implementation returns a dict; wrap it as a generator of pairs in
    source-insertion order so callers can consume it like nx's.
    """
    _validate_backend_dispatch_keywords(
        "all_pairs_shortest_path", backend, backend_kwargs
    )
    paths = _raw_all_pairs_shortest_path(G, cutoff)
    # Preserve graph node insertion order for the source axis.
    for source in G:
        if source in paths:
            # br-r37-c1-5ur50: each per-source inner dict iterates in
            # BFS-visit-from-source order matching nx (Rust dict yields
            # in arbitrary internal order).
            inner = paths[source]
            ordered = {n: inner[n] for n in _bfs_visit_order(G, source) if n in inner}
            yield source, ordered


def all_pairs_shortest_path_length(G, cutoff=None, *, backend=None, **backend_kwargs):
    """Return an iterator of (source, shortest-path-length-dict) pairs.

    Matches NetworkX's public contract — wraps the dict-returning
    Rust implementation as a generator of pairs.
    """
    _validate_backend_dispatch_keywords(
        "all_pairs_shortest_path_length", backend, backend_kwargs
    )
    lengths = _raw_all_pairs_shortest_path_length(G, cutoff)
    for source in G:
        if source in lengths:
            inner = lengths[source]
            # br-r37-c1-5ur50: BFS-visit-from-source order matching nx.
            ordered = {n: inner[n] for n in _bfs_visit_order(G, source) if n in inner}
            yield source, ordered

# Algorithm functions — graph predicates & utilities
from franken_networkx._fnx import (
    is_empty,
    non_neighbors,
    all_triangles as _rust_all_triangles,
    enumerate_all_cliques as _raw_enumerate_all_cliques,
    find_cliques_recursive as _raw_find_cliques_recursive,
    chordal_graph_cliques as _raw_chordal_graph_cliques,
    chordal_graph_treewidth as _rust_chordal_graph_treewidth,
    make_max_clique_graph as _rust_make_max_clique_graph,
    ring_of_cliques,
)


def chordal_graph_cliques(G):
    """br-isokw: ``G`` matches nx; Rust binding used ``g``.

    br-chordalcliquetypes: nx.chordal_graph_cliques yields a generator
    of frozensets (one per maximal clique of the chordal graph). The
    Rust binding returned a list of lists, breaking both the iterator
    contract (``iter(r) is r`` etc.) and the set-operation contract
    (users could not intersect / union the cliques directly). Convert
    each inner list to frozenset and yield via a generator.

    br-r37-c1-xd6xi: nx accepts MultiGraph inputs and returns the
    maximal cliques of the underlying simple graph (parallel edges
    collapsed). The previous fnx implementation incorrectly rejected
    MultiGraph with NetworkXNotImplemented, even though nx has no
    @not_implemented_for guard on this function. Project the
    MultiGraph to a simple Graph before delegating to the Rust core
    so the algorithm matches nx's behavior on multigraph inputs.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        # br-r37-c1-xd6xi: nx accepts MultiGraph (no @not_implemented_for
        # decorator). On multigraphs without parallels nx returns
        # cliques of the underlying simple graph; on multigraphs with
        # parallels nx raises NetworkXError("Input graph is not
        # chordal."). Delegate to nx so both behaviours match exactly.
        return _call_networkx_for_parity("chordal_graph_cliques", G)
    cliques = _raw_chordal_graph_cliques(G)
    def _gen():
        for c in cliques:
            yield frozenset(c)
    return _gen()


# br-ringlabels: the Rust ring_of_cliques used string labels like
# "0_0", "0_1", ... which broke drop-in parity — nx uses integer
# labels 0..n*k-1 with clique-bridge edges specifically at
# (i*k + 1, (i+1)*k % (n*k)). Shadow the Rust binding with a Python
# wrapper that mirrors nx's labelling + validation messages.
_rust_ring_of_cliques = ring_of_cliques  # keep reference in case anything internal needs it


def ring_of_cliques(num_cliques, clique_size):
    """Defines a ring of cliques graph.

    br-ringlabels / br-ringvalid: match nx exactly — integer node
    labels 0..num_cliques*clique_size-1 and nx's validation messages.
    The Rust binding emitted string labels "i_j" and error messages
    using ``num_cliques`` / ``clique_size`` parameter names that
    diverged from nx's human-friendly wording.
    """
    import itertools as _itertools
    if num_cliques < 2:
        raise NetworkXError("A ring of cliques must have at least two cliques")
    if clique_size < 2:
        raise NetworkXError("The cliques must have at least two nodes")
    G = Graph()
    n_total = num_cliques * clique_size
    for i in range(num_cliques):
        edges = _itertools.combinations(
            range(i * clique_size, i * clique_size + clique_size), 2
        )
        G.add_edges_from(edges)
        G.add_edge(i * clique_size + 1, (i + 1) * clique_size % n_total)
    return G


def all_triangles(G, nbunch=None):
    """Yield unique triangles in an undirected graph."""
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    if nbunch is None:
        yield from _rust_all_triangles(G)
        return

    nbunch_nodes = _global_nbunch_nodes(G, nbunch)
    nbunch_lookup = dict.fromkeys(nbunch_nodes)
    relevant_nodes = itertools.chain(
        nbunch_lookup,
        (
            neighbor
            for node in nbunch_lookup
            for neighbor in G.neighbors(node)
            if neighbor not in nbunch_lookup
        ),
    )
    node_to_id = {node: index for index, node in enumerate(relevant_nodes)}

    for u in nbunch_lookup:
        u_id = node_to_id[u]
        # G.adj[u].keys() may return a dict_keyiterator on fnx (vs a
        # dict_keys view on nx); coerce to set() so intersection works.
        u_neighbors = set(G.adj[u].keys())
        for v in u_neighbors:
            v_id = node_to_id.get(v, -1)
            if v_id <= u_id:
                continue
            v_neighbors = set(G.adj[v].keys())
            for w in v_neighbors & u_neighbors:
                if node_to_id.get(w, -1) > v_id:
                    yield (u, v, w)


def chordal_graph_treewidth(G):
    """Return the treewidth of a chordal graph."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.number_of_nodes() == 0:
        return -2
    return _rust_chordal_graph_treewidth(G)


def find_cliques(G, nodes=None):
    """Yield all maximal cliques in an undirected graph.

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).

    br-r37-c1-g71v3: the Rust binding's Bron-Kerbosch yielded cliques
    in a different iteration order from nx, and within each clique
    returned nodes in canonical/sorted order rather than nx's pivot-
    based discovery order. Delegate the ``nodes=None`` case to nx so
    both the clique-iteration and intra-clique node orderings match
    its documented contract exactly.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    if nodes is None:
        yield from _call_networkx_for_parity("find_cliques", G)
        return

    if len(G) == 0:
        return

    adjacency = {u: {v for v in G[u] if v != u} for u in G}
    current_clique = nodes[:]
    candidates = set(G)

    for node in current_clique:
        if node not in candidates:
            raise ValueError(f"The given `nodes` {nodes} do not form a clique")
        candidates &= adjacency[node]

    if not candidates:
        yield current_clique[:]
        return

    subgraph = candidates.copy()
    stack = []
    current_clique.append(None)

    pivot = max(subgraph, key=lambda node: len(candidates & adjacency[node]))
    extension = candidates - adjacency[pivot]

    try:
        while True:
            if extension:
                selected = extension.pop()
                candidates.remove(selected)
                current_clique[-1] = selected
                selected_neighbors = adjacency[selected]
                subgraph_selected = subgraph & selected_neighbors
                if not subgraph_selected:
                    yield current_clique[:]
                else:
                    candidates_selected = candidates & selected_neighbors
                    if candidates_selected:
                        stack.append((subgraph, candidates, extension))
                        current_clique.append(None)
                        subgraph = subgraph_selected
                        candidates = candidates_selected
                        pivot = max(
                            subgraph, key=lambda node: len(candidates & adjacency[node])
                        )
                        extension = candidates - adjacency[pivot]
            else:
                current_clique.pop()
                subgraph, candidates, extension = stack.pop()
    except IndexError:
        pass


def enumerate_all_cliques(G):
    """Yield all cliques (not just maximal) in an undirected graph.

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).
    """
    yield from _raw_enumerate_all_cliques(G)


def find_cliques_recursive(G, nodes=None):
    """Yield all maximal cliques in an undirected graph (recursive).

    Generator function so the returned object is a true generator
    matching nx's contract (br-r37-c1-682kr).

    br-r37-c1-g71v3: same iteration-order drift as find_cliques —
    delegate the ``nodes=None`` case to nx for parity.
    """
    if nodes is None:
        yield from _call_networkx_for_parity("find_cliques_recursive", G)
        return
    yield from find_cliques(G, nodes=nodes)


def number_of_cliques(G, nodes=None, cliques=None):
    """Return the number of maximal cliques each node is part of."""
    if cliques is None:
        if G.is_directed():
            raise NetworkXNotImplemented("not implemented for directed type")
        cliques = find_cliques(G)

    if nodes is None:
        nodes = list(G.nodes())

    if not isinstance(nodes, list):
        return sum(1 for clique in cliques if nodes in clique)

    clique_counts = Counter()
    for clique in cliques:
        clique_counts.update(clique)
    return {node: clique_counts[node] for node in nodes}


def node_clique_number(G, nodes=None, cliques=None, separate_nodes=False):
    """Return the size of the largest maximal clique containing each node."""
    if cliques is None:
        if G.is_directed():
            raise NetworkXNotImplemented("not implemented for directed type")
        cliques = list(find_cliques(G))
        if nodes is not None:
            if nodes in G:
                return max(len(clique) for clique in cliques if nodes in clique)
            try:
                requested_nodes = []
                for node in nodes:
                    if node not in G:
                        raise NodeNotFound(f"Source {node} is not in G")
                    requested_nodes.append(node)
                return {
                    node: max(len(clique) for clique in cliques if node in clique)
                    for node in requested_nodes
                }
            except TypeError:
                return {node: 0 for node in nodes}

    if nodes in G:
        return max(len(clique) for clique in cliques if nodes in clique)

    size_for_node = defaultdict(int)
    for clique in cliques:
        clique_size = len(clique)
        for node in clique:
            if size_for_node[node] < clique_size:
                size_for_node[node] = clique_size
    if nodes is None:
        return size_for_node
    return {node: size_for_node[node] for node in nodes}

