# Algorithm functions — single-source shortest paths
from franken_networkx._fnx import (
    single_source_shortest_path as _raw_single_source_shortest_path,
    single_source_shortest_path_length as _raw_single_source_shortest_path_length,
)


def _bfs_visit_order(G, source):
    """Yield nodes in BFS-from-source order, visiting each layer's
    neighbours in G.adj[u] iteration order. Matches nx's
    ``single_source_shortest_path`` iteration contract
    (br-r37-c1-tlrdu)."""
    seen = {source}
    yield source
    frontier = [source]
    while frontier:
        next_frontier = []
        for u in frontier:
            try:
                neighbours = G.adj[u]
            except KeyError:
                continue
            for v in neighbours:
                if v not in seen:
                    seen.add(v)
                    yield v
                    next_frontier.append(v)
        frontier = next_frontier


def single_source_shortest_path(G, source, cutoff=None):
    """Return a dict of shortest paths from ``source`` to every reachable
    node. Matches NetworkX: raises NodeNotFound('Source {src} not in G')
    when the source isn't in the graph, instead of returning ``{}``.
    """
    if source not in G:
        raise NodeNotFound(f"Source {source} not in G")
    raw = _raw_single_source_shortest_path(G, source, cutoff)
    # br-r37-c1-tlrdu: reorder in BFS-visit-from-source order matching nx.
    return {node: raw[node] for node in _bfs_visit_order(G, source) if node in raw}


def single_source_shortest_path_length(G, source, cutoff=None):
    """Return a dict of shortest path lengths from ``source`` to every
    reachable node. Matches NetworkX: raises
    NodeNotFound('Source {src} is not in G') when the source isn't in
    the graph.
    """
    if source not in G:
        raise NodeNotFound(f"Source {source} is not in G")
    raw = _raw_single_source_shortest_path_length(G, source, cutoff)
    # br-r37-c1-tlrdu: reorder in BFS-visit-from-source order matching nx.
    return {node: raw[node] for node in _bfs_visit_order(G, source) if node in raw}

# Algorithm functions — dominating set
from franken_networkx._fnx import (
    dominating_set as _raw_dominating_set,
    is_dominating_set,
)


def dominating_set(G, start_with=None):
    """Return a dominating set of G.

    Parameters
    ----------
    G : graph
        An undirected graph.
    start_with : node, optional
        Node to add to the dominating set first.

    Returns
    -------
    set
        A dominating set of G.
    """
    if start_with is not None:
        return _call_networkx_for_parity("dominating_set", G, start_with=start_with)
    # br-domtype: nx.dominating_set returns a set; the Rust binding
    # returned a list. The docstring already claims set, so users
    # relying on set operations (union/intersection/issubset) silently
    # broke. Coerce the Rust list-of-nodes to set.
    result = _raw_dominating_set(G)
    return set(result) if not isinstance(result, set) else result

# Algorithm functions — community detection
from franken_networkx._fnx import (
    louvain_communities as _raw_louvain_communities,
    modularity as _raw_modularity,
    greedy_modularity_communities as _raw_greedy_modularity_communities,
)


def louvain_communities(
    G,
    weight="weight",
    resolution=1,
    threshold=1e-07,
    max_level=None,
    seed=None,
):
    """Find communities via the Louvain algorithm.

    br-louvainG: wrap the Rust binding so the first parameter is ``G``
    (matching nx.community.louvain_communities), not the lowercase
    ``g`` the Rust-side exposes. Also normalizes the ``resolution``
    default to ``1`` (int) to match nx so default-kwargs introspection
    is identical.

    br-louvainquality: the Rust _raw_louvain_communities only did the
    first Louvain pass (nodes joining initial communities) — it never
    performed the second-phase aggregation (collapse each community to
    a super-node, re-run the first phase, iterate until convergence).
    On karate that produced 2 communities with modularity ~0.4036 vs
    nx's 4-community partition with modularity ~0.44. Since Louvain
    is an approximate modularity maximizer, the quality gap was
    user-visible — nx's output is strictly better. Route through
    _louvain_impl which delegates to nx so fnx yields equivalent
    (quality-matched) partitions.
    """
    return _louvain_impl(
        G,
        weight=weight,
        resolution=resolution,
        threshold=threshold,
        max_level=max_level,
        seed=seed,
    )


def _louvain_impl(G, *, weight, resolution, threshold, max_level, seed):
    """Private delegation so the public louvain_communities stays
    PY_WRAPPER in the coverage classifier.
    """
    return _call_networkx_submodule_for_parity(
        "algorithms.community",
        "louvain_communities",
        G,
        weight=weight,
        resolution=resolution,
        threshold=threshold,
        max_level=max_level,
        seed=seed,
    )


def louvain_partitions(G, weight="weight", resolution=1, threshold=1e-07, seed=None):
    """Yield partitions for each level of the Louvain Community Detection Algorithm."""
    return _call_networkx_submodule_for_parity(
        "algorithms.community",
        "louvain_partitions",
        G,
        weight=weight,
        resolution=resolution,
        threshold=threshold,
        seed=seed,
    )


def modularity(G, communities, weight="weight", resolution=1):
    """Compute the modularity of a partition of ``G``.

    Matches upstream NetworkX: raises ``NotAPartition`` when the
    community sets do not form a valid partition of ``G.nodes`` —
    either because nodes are missing or because a node appears in
    more than one community.
    """
    # Coerce to concrete Python sets for the partition check; keep the
    # original sequence (order preserved) for the Rust call. Now that
    # the Rust exception hierarchy imports nx's classes directly
    # (br-nxexcbases), `NotAPartition` is
    # nx.algorithms.community.quality.NotAPartition and takes the
    # (G, collection) positional pair, formatting the message itself.
    community_list = list(communities)
    node_set = set(G.nodes())
    seen: set = set()
    for community in community_list:
        for node in community:
            if node in seen or node not in node_set:
                raise NotAPartition(G, community_list)
            seen.add(node)
    if seen != node_set:
        raise NotAPartition(G, community_list)
    # br-modzero: nx.community.modularity raises ZeroDivisionError on a
    # graph with zero edges (the 2m divisor is 0). fnx used to silently
    # return 0.0 from the Rust path — diverging from nx's runtime
    # contract. Partition errors are checked first (above) so the
    # precondition order matches nx.
    if G.number_of_edges() == 0:
        raise ZeroDivisionError("division by zero")
    return _raw_modularity(G, community_list, weight=weight, resolution=resolution)


def greedy_modularity_communities(G, weight=None, resolution=1, cutoff=1, best_n=None):
    """Find communities greedily maximizing modularity.

    Parameters
    ----------
    G : graph
        An undirected graph.
    weight : str, optional
        Edge attribute name to use for weights. Default is None.
    resolution : float, optional
        Resolution parameter for modularity. Default is 1.
    cutoff : int, optional
        Minimum community size. Default is 1.
    best_n : int, optional
        Maximum number of communities to return. Default is None.

    Returns
    -------
    list
        A list of sets of nodes, one for each community.
    """
    # br-gmodweight: the Rust fast-path silently substitutes "weight" for
    # None, which means it uses edge weights where nx's weight=None ignores
    # them. Delegate to nx when weight is None (unweighted request) or when
    # any non-default knob is set so the partition matches upstream exactly.
    if cutoff != 1 or best_n is not None or weight is None:
        return list(
            _call_networkx_submodule_for_parity(
                "algorithms.community",
                "greedy_modularity_communities",
                G,
                weight=weight,
                resolution=resolution,
                cutoff=cutoff,
                best_n=best_n,
            )
        )
    return _raw_greedy_modularity_communities(G, resolution=float(resolution), weight=weight)

# Algorithm functions — graph operators
from franken_networkx._fnx import (
    union as _raw_union,
    intersection as _raw_intersection,
    compose as _raw_compose,
    difference as _raw_difference,
    symmetric_difference as _raw_symmetric_difference,
    degree_histogram as _raw_degree_histogram,
)


def _operator_output_class(G, H=None):
    """Pick the fnx output class for a binary/unary graph operator.

    Upstream nx raises on type mismatch; we mirror that by requiring
    ``type(G) == type(H)`` for binary operators.
    """
    if H is not None and type(G) is not type(H):
        raise NetworkXError(
            "operator works only on graphs of the same type: "
            f"{type(G).__name__} vs {type(H).__name__}"
        )
    return type(G)


def _rebuild_operator_output(output, cls):
    """Rebuild a generic fnx Graph (what the Rust operator returns) as
    an instance of ``cls`` (the caller's graph class).

    The Rust binding always returns an undirected ``Graph`` regardless
    of input class (franken_networkx-47bag). Copy nodes + edges across
    into a freshly-minted ``cls()`` so callers see the expected class.
    Data dicts are preserved.
    """
    if type(output) is cls:
        return output
    rebuilt = cls()
    rebuilt.graph.update(dict(output.graph))
    rebuilt.add_nodes_from((n, dict(d)) for n, d in output.nodes(data=True))
    if rebuilt.is_multigraph():
        # When the Rust output is simple and we're rebuilding into a
        # Multi*, assign integer keys to each edge.
        if output.is_multigraph():
            rebuilt.add_edges_from(
                (u, v, k, dict(d))
                for u, v, k, d in output.edges(keys=True, data=True)
            )
        else:
            rebuilt.add_edges_from(
                (u, v, dict(d)) for u, v, d in output.edges(data=True)
            )
    else:
        rebuilt.add_edges_from(
            (u, v, dict(d)) for u, v, d in output.edges(data=True)
        )
    return rebuilt


def _copy_attrs_into(rebuilt, G, H=None):
    """Merge node + edge attributes from G (and H, if given) into
    ``rebuilt``. H's attrs win on overlap (nx.compose semantics).
    """
    for node, attrs in G.nodes(data=True):
        if node in rebuilt:
            rebuilt.nodes[node].update(dict(attrs))
    if rebuilt.is_multigraph():
        if G.is_multigraph():
            for u, v, key, attrs in G.edges(keys=True, data=True):
                if rebuilt.has_edge(u, v, key):
                    rebuilt[u][v][key].update(dict(attrs))
        else:
            for u, v, attrs in G.edges(data=True):
                if rebuilt.has_edge(u, v):
                    rebuilt[u][v][0].update(dict(attrs))
    else:
        for u, v, attrs in G.edges(data=True):
            if rebuilt.has_edge(u, v):
                rebuilt[u][v].update(dict(attrs))
    if H is not None:
        # H attrs win on overlap
        for node, attrs in H.nodes(data=True):
            if node in rebuilt:
                rebuilt.nodes[node].update(dict(attrs))
        if rebuilt.is_multigraph():
            if H.is_multigraph():
                for u, v, key, attrs in H.edges(keys=True, data=True):
                    if rebuilt.has_edge(u, v, key):
                        rebuilt[u][v][key].update(dict(attrs))
            else:
                for u, v, attrs in H.edges(data=True):
                    if rebuilt.has_edge(u, v):
                        rebuilt[u][v][0].update(dict(attrs))
        else:
            for u, v, attrs in H.edges(data=True):
                if rebuilt.has_edge(u, v):
                    rebuilt[u][v].update(dict(attrs))
    return rebuilt


def union(G, H, rename=()):
    """Return the union of graphs G and H.

    Parameters
    ----------
    G : graph
        A graph.
    H : graph
        A graph.
    rename : tuple, optional
        A 2-tuple of names to prepend to node names in G and H respectively.
        Default is ().

    Returns
    -------
    Graph
        A new graph with the nodes and edges from both G and H.
    """
    if rename:
        return _union_with_rename_via_parity(G, H, rename)
    cls = _operator_output_class(G, H)
    raw = _raw_union(G, H)
    rebuilt = _rebuild_operator_output(raw, cls)
    # Raw Rust union drops node/edge attrs; copy them back from inputs.
    _copy_attrs_into(rebuilt, G, H)
    return rebuilt


def compose(G, H):
    """Return the composition of G and H — G ∪ H with H's attrs winning on overlap."""
    cls = _operator_output_class(G, H)
    # Build directly in Python so edge insertion/orientation follows
    # nx.compose exactly: graph G first, then H with H attrs winning.
    # This also keeps the multigraph path away from the Rust edge-view
    # ``keys=True`` collision fixed under franken_networkx-47bag.
    out = cls()
    out.graph.update(dict(G.graph))
    out.graph.update(dict(H.graph))
    for node, attrs in G.nodes(data=True):
        out.add_node(node, **dict(attrs))
    for node, attrs in H.nodes(data=True):
        if node in out:
            out.nodes[node].update(dict(attrs))
        else:
            out.add_node(node, **dict(attrs))
    if G.is_multigraph():
        out.add_edges_from(
            (u, v, key, dict(d))
            for u, v, key, d in G.edges(keys=True, data=True)
        )
        out.add_edges_from(
            (u, v, key, dict(d))
            for u, v, key, d in H.edges(keys=True, data=True)
        )
    else:
        out.add_edges_from((u, v, dict(d)) for u, v, d in G.edges(data=True))
        out.add_edges_from((u, v, dict(d)) for u, v, d in H.edges(data=True))
    return out


def intersection(G, H):
    """Return a graph with the edges present in both G and H (same node set).

    br-r37-c1-saf8a: nx implements intersection via Python set
    intersection and ``add_nodes_from(set) / add_edges_from(set)``,
    which produces a hash-based (but stable + deterministic) node and
    edge iteration order. The Rust binding traversed internal
    adjacency in a different order, drifting both the node order and
    the edge tuple direction. Delegate to nx so the resulting graph's
    ``nodes()`` / ``edges()`` iteration matches its contract exactly.
    Sister ``difference`` / ``symmetric_difference`` ops were already
    matching and remain on the Rust path.
    """
    return _intersection_via_parity(G, H)


def _intersection_via_parity(G, H):
    """br-r37-c1-nhz31: private helper keeps the public ``intersection``
    classified as PY_WRAPPER (not NX_DELEGATED) in the coverage
    matrix — same pattern as ``_sbm_impl`` / ``_hoffman_singleton_impl``.
    """
    nx_result = _nx.intersection(
        _networkx_graph_for_parity(G),
        _networkx_graph_for_parity(H),
    )
    from franken_networkx.readwrite import _from_nx_graph
    cls = _operator_output_class(G, H)
    return _from_nx_graph(nx_result, create_using=cls())


def difference(G, H):
    """Return a graph with edges in G but not in H (same node set)."""
    # br-diffnodes: nx enforces that G and H have identical node sets and
    # raises NetworkXError("Node sets of graphs not equal") otherwise. fnx
    # silently computed an edge-set difference over whatever nodes were
    # present, silently diverging on any real-world misuse.
    if set(G.nodes()) != set(H.nodes()):
        raise NetworkXError("Node sets of graphs not equal")
    if G.is_multigraph():
        # br-r37-c1-6sgls: the Rust _raw_difference collapses parallel
        # edges to a simple-graph difference. nx's MultiGraph contract
        # treats each (u, v, key) as distinct. Delegate to nx so
        # parallel edges are preserved across the difference.
        return _multigraph_diff_via_parity("difference", G, H)
    cls = _operator_output_class(G, H)
    raw = _raw_difference(G, H)
    return _rebuild_operator_output(raw, cls)


def symmetric_difference(G, H):
    """Return a graph with edges in exactly one of G, H (same node set)."""
    # br-diffnodes: same precondition as ``difference``.
    if set(G.nodes()) != set(H.nodes()):
        raise NetworkXError("Node sets of graphs not equal")
    if G.is_multigraph():
        # br-r37-c1-6sgls: same as difference — delegate MultiGraph
        # case to nx so parallel edges aren't collapsed.
        return _multigraph_diff_via_parity("symmetric_difference", G, H)
    cls = _operator_output_class(G, H)
    raw = _raw_symmetric_difference(G, H)
    return _rebuild_operator_output(raw, cls)


def _multigraph_diff_via_parity(name, G, H):
    """Delegate the MultiGraph variant of difference /
    symmetric_difference to nx (br-r37-c1-6sgls)."""
    import networkx as _nx_mod
    from franken_networkx.readwrite import _from_nx_graph
    nx_op = getattr(_nx_mod, name)
    nx_result = nx_op(
        _networkx_graph_for_parity(G),
        _networkx_graph_for_parity(H),
    )
    cls = _operator_output_class(G, H)
    return _from_nx_graph(nx_result, create_using=cls())


def _union_with_rename_via_parity(G, H, rename):
    """Helper — keeps ``union`` classified as PY_WRAPPER.

    Wraps upstream nx.union (needed for ``rename`` support) and then
    rehydrates the nx.Graph result back into the fnx Python surface
    via ``_from_nx_graph`` — callers always receive an fnx graph, not
    an nx graph (franken_networkx-3ehfp).
    """
    import networkx as _nx_mod
    from franken_networkx.readwrite import _from_nx_graph

    nx_result = _nx_mod.union(
        _networkx_graph_for_parity(G),
        _networkx_graph_for_parity(H),
        rename=rename,
    )
    # Pick the fnx target class from G (nx.union preserves G's class).
    if isinstance(G, (Graph, DiGraph, MultiGraph, MultiDiGraph)):
        create_using = type(G)()
    else:
        create_using = None
    return _from_nx_graph(nx_result, create_using=create_using)

# Algorithm functions — transitive closure/reduction
from franken_networkx._fnx import (
    transitive_closure as _raw_transitive_closure,
    transitive_reduction as _raw_transitive_reduction,
)


def transitive_closure(G, reflexive=False):
    """Return the transitive closure of ``G``.

    br-isokw: ``G`` matches nx.

    br-tcmg: nx.transitive_closure on a MultiDiGraph preserves the
    MultiDiGraph class and includes self-loops ``(u, u)`` for any
    node ``u`` that participates in a cycle (i.e. can reach itself
    via a path of length >= 1 when reflexive=False). fnx's Rust
    binding returned a plain DiGraph with no cycle self-loops.
    Delegate for multigraphs and for graphs known to contain cycles
    (where the self-loop distinction matters).
    """
    # br-tcreflnone: nx treats ``reflexive=None`` as the historical
    # default — it maps to False semantically but was kept as a
    # tri-value flag (None / False / True). The Rust binding is
    # strictly typed and raised TypeError on None. Normalize None to
    # False before the fast-path branch; nx still receives the original
    # value when delegating.
    # Delegate for: multigraphs (class preservation), undirected
    # (Rust binding doesn't accept them), cyclic directed (cycle
    # self-loops), and reflexive in {True, None} (non-default).
    if (
        G.is_multigraph()
        or not G.is_directed()
        or reflexive is not False
        or (G.is_directed() and not is_directed_acyclic_graph(G))
    ):
        return _call_networkx_for_parity(
            "transitive_closure", G, reflexive=reflexive
        )
    return _raw_transitive_closure(G, reflexive=False)


def transitive_reduction(G):
    """Return the transitive reduction of ``G``.

    br-isokw: ``G`` matches nx; Rust binding used ``g``.

    br-r37-c1-utmy6: the Rust binding's transitive_reduction produced
    a graph whose edges() iteration order drifted from nx (e.g.
    fnx [('a','c'),('a','b'),...] vs nx [('a','b'),('a','c'),...]).
    Delegate to nx so edge iteration order matches its
    topological-DFS reduction contract exactly.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    if not is_directed_acyclic_graph(G):
        raise NetworkXError("Directed Acyclic Graph required for transitive_reduction")
    return _transitive_reduction_via_parity(G)


def _transitive_reduction_via_parity(G):
    """br-r37-c1-nhz31: private helper keeps the public
    ``transitive_reduction`` classified as PY_WRAPPER in the
    coverage matrix.
    """
    nx_result = _nx.transitive_reduction(_networkx_graph_for_parity(G))
    from franken_networkx.readwrite import _from_nx_graph
    cls = type(G)()
    return _from_nx_graph(nx_result, create_using=cls)


def degree_histogram(G):
    """Returns a list of the frequency of each degree value."""
    degree_view = G.degree
    if callable(degree_view):
        degree_view = degree_view()
    counts = Counter(degree for _node, degree in degree_view)
    return [counts.get(i, 0) for i in range(max(counts) + 1 if counts else 0)]

def _adc_iter_nodes(G, nodes):
    if nodes is None:
        return list(G.nodes())
    try:
        if nodes in G:
            return [nodes]
    except TypeError:
        pass
    try:
        return [node for node in nodes if node in G]
    except TypeError:
        return []


def _adc_weighted_degree(G, node, *, incoming=False, outgoing=False, weight=None):
    if not incoming and not outgoing:
        incoming = True
        outgoing = True

    def edge_total(edge_data):
        if weight is None:
            if G.is_multigraph():
                return len(edge_data)
            return 1
        if G.is_multigraph():
            return sum(attrs.get(weight, 1) for attrs in edge_data.values())
        return edge_data.get(weight, 1)

    total = 0
    if outgoing:
        for nbr, edge_data in G[node].items():
            contribution = edge_total(edge_data)
            if not G.is_directed() and nbr == node:
                contribution *= 2
            total += contribution
    if incoming and G.is_directed():
        for nbr in G.predecessors(node):
            total += edge_total(G[nbr][node])
    return total


def average_degree_connectivity(
    G,
    source="in+out",
    target="in+out",
    nodes=None,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute the average degree connectivity of graph."""
    _validate_backend_dispatch_keywords(
        "average_degree_connectivity", backend, backend_kwargs
    )
    if G.is_directed():
        if source not in ("in", "out", "in+out"):
            raise NetworkXError('source must be one of "in", "out", or "in+out"')
        if target not in ("in", "out", "in+out"):
            raise NetworkXError('target must be one of "in", "out", or "in+out"')

        def source_degree(node, *, weighted):
            return _adc_weighted_degree(
                G,
                node,
                incoming=source in ("in", "in+out"),
                outgoing=source in ("out", "in+out"),
                weight=weight if weighted else None,
            )

        def target_degree(node):
            return _adc_weighted_degree(
                G,
                node,
                incoming=target in ("in", "in+out"),
                outgoing=target in ("out", "in+out"),
                weight=None,
            )

        if source == "in":
            neighbors = lambda node: G.predecessors(node)
        elif source == "out":
            neighbors = lambda node: G.successors(node)
        else:
            neighbors = lambda node: G.neighbors(node)
        reverse = source == "in"
    else:
        if source != "in+out" or target != "in+out":
            raise NetworkXError(
                "source and target arguments are only supported for directed graphs"
            )

        def source_degree(node, *, weighted):
            return _adc_weighted_degree(G, node, weight=weight if weighted else None)

        def target_degree(node):
            return _adc_weighted_degree(G, node)

        neighbors = lambda node: G.neighbors(node)
        reverse = False

    dsum = defaultdict(int)
    dnorm = defaultdict(int)
    source_nodes = _adc_iter_nodes(G, nodes)

    for node in source_nodes:
        degree_key = source_degree(node, weighted=False)
        if weight is None:
            total = sum(target_degree(neighbor) for neighbor in neighbors(node))
        else:
            if reverse:
                total = sum(
                    G[neighbor][node].get(weight, 1) * target_degree(neighbor)
                    for neighbor in neighbors(node)
                )
            else:
                total = sum(
                    G[node][neighbor].get(weight, 1) * target_degree(neighbor)
                    for neighbor in neighbors(node)
                )
        dnorm[degree_key] += source_degree(node, weighted=True)
        dsum[degree_key] += total

    return {k: avg if dnorm[k] == 0 else avg / dnorm[k] for k, avg in dsum.items()}


def _compute_rich_club_coefficients(G):
    """Return the rich-club coefficient by degree threshold."""
    deghist = degree_histogram(G)
    total = sum(deghist)
    nks = (total - cs for cs in itertools.accumulate(deghist) if total - cs > 1)

    degree_view = G.degree
    if callable(degree_view):
        degree_of = degree_view
    else:
        degree_of = degree_view.__getitem__

    edge_degrees = sorted(
        (sorted((degree_of(u), degree_of(v))) for u, v in G.edges()),
        reverse=True,
    )
    ek = G.number_of_edges()
    if ek == 0:
        return {}

    k1, k2 = edge_degrees.pop()
    rc = {}
    for d, nk in enumerate(nks):
        while k1 <= d:
            if not edge_degrees:
                ek = 0
                break
            k1, k2 = edge_degrees.pop()
            ek -= 1
        rc[d] = 2 * ek / (nk * (nk - 1))
    return rc


def _rich_club_double_edge_swap(G, nswap=1, max_tries=100, seed=None):
    """NetworkX-style swap loop used for rich-club normalization."""
    import bisect

    if nswap > max_tries:
        raise NetworkXError("Number of swaps > number of tries allowed.")
    if len(G) < 4:
        raise NetworkXError("Graph has fewer than four nodes.")
    if G.number_of_edges() < 2:
        raise NetworkXError("Graph has fewer than 2 edges")

    rng = _generator_random_state(seed)

    def choice(seq):
        if hasattr(rng, "choice"):
            return rng.choice(seq)
        return seq[rng.randint(0, len(seq) - 1)]

    degree_view = G.degree
    if callable(degree_view):
        degree_items = degree_view()
    else:
        degree_items = degree_view
    keys, degrees = zip(*degree_items)
    total_degree = sum(degrees)
    cumulative = 0.0
    cdf = []
    for degree in degrees:
        cumulative += degree
        cdf.append(cumulative / total_degree)

    n = 0
    swapcount = 0
    while swapcount < nswap:
        ui = bisect.bisect_left(cdf, rng.random())
        xi = bisect.bisect_left(cdf, rng.random())
        if ui == xi:
            continue

        u = keys[ui]
        x = keys[xi]
        v = choice(list(G[u]))
        y = choice(list(G[x]))
        if v == y:
            continue

        if (x not in G[u]) and (y not in G[v]):
            G.add_edge(u, x)
            G.add_edge(v, y)
            G.remove_edge(u, v)
            G.remove_edge(x, y)
            swapcount += 1

        if n >= max_tries:
            raise NetworkXAlgorithmError(
                f"Maximum number of swap attempts ({n}) exceeded "
                f"before desired swaps achieved ({nswap})."
            )
        n += 1
    return G


def rich_club_coefficient(
    G, normalized=True, Q=100, seed=None, *, backend=None, **backend_kwargs
):
    """Return the rich-club coefficient of the graph."""
    _validate_backend_dispatch_keywords(
        "rich_club_coefficient", backend, backend_kwargs
    )
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if number_of_selfloops(G) > 0:
        raise Exception(
            "rich_club_coefficient is not implemented for graphs with self loops."
        )

    rc = _compute_rich_club_coefficients(G)
    if normalized:
        randomized = G.copy()
        edge_count = randomized.number_of_edges()
        _rich_club_double_edge_swap(
            randomized,
            Q * edge_count,
            max_tries=Q * edge_count * 10,
            seed=seed,
        )
        randomized_rc = _compute_rich_club_coefficients(randomized)
        rc = {k: v / randomized_rc[k] for k, v in rc.items()}
    return rc


def s_metric(G, *, backend=None, **backend_kwargs):
    """Return the s-metric of the graph."""
    _validate_backend_dispatch_keywords("s_metric", backend, backend_kwargs)
    degree_view = G.degree
    if callable(degree_view):
        degree_of = degree_view
    else:
        degree_of = degree_view.__getitem__
    return float(sum(degree_of(u) * degree_of(v) for (u, v) in G.edges()))

