def _ancestors_descendants_missing_node_msg(G, source):
    kind = "digraph" if G.is_directed() else "graph"
    return f"The node {source} is not in the {kind}."


def ancestors(G, source):
    """Return all nodes having a path to ``source`` in ``G``.

    Matches nx (br-7f0fn): accepts undirected and multigraph inputs as
    well as DiGraph, returning all nodes in the connected / reachable
    set (excluding ``source`` itself). Raises NetworkXError if source
    isn't in G (message distinguishes graph vs digraph). Returns a
    plain ``set`` (not ``frozenset``).
    """
    if source not in G:
        raise NetworkXError(_ancestors_descendants_missing_node_msg(G, source))
    if G.is_directed():
        return set(_raw_ancestors(G, source))
    from collections import deque
    seen = {source}
    q = deque([source])
    while q:
        n = q.popleft()
        for nbr in G[n]:
            if nbr not in seen:
                seen.add(nbr)
                q.append(nbr)
    seen.discard(source)
    return seen


def descendants(G, source):
    """Return all nodes reachable from ``source`` in ``G``.

    Matches nx (br-7f0fn): on undirected / multigraph, returns the
    reachable node set (symmetric with ``ancestors``). Returns a
    plain ``set``.
    """
    if source not in G:
        raise NetworkXError(_ancestors_descendants_missing_node_msg(G, source))
    if G.is_directed():
        return set(_raw_descendants(G, source))
    from collections import deque
    seen = {source}
    q = deque([source])
    while q:
        n = q.popleft()
        for nbr in G[n]:
            if nbr not in seen:
                seen.add(nbr)
                q.append(nbr)
    seen.discard(source)
    return seen


def topological_sort(G):
    """Yield nodes in topological order.

    Matches nx's Kahn's-algorithm tie-break order: zero-in-degree nodes
    are queued in graph insertion order (br-codtrav). The Rust native
    uses a different tie-break, so we re-implement Kahn's in Python so
    the emitted order is byte-identical to nx's on DAG fixtures.

    Raises ``NetworkXUnfeasible`` on a cyclic graph for nx parity
    (br-zzcm7).
    """
    if not G.is_directed():
        raise NetworkXError("Topological sort not defined on undirected graphs.")
    from collections import deque

    # Count parallel edges as separate in-degree increments for
    # MultiDiGraph parity, then decrement once per outgoing edge (not
    # per unique successor) so parallels cancel out correctly.
    indegree = {v: 0 for v in G}
    for _, v in G.edges():
        indegree[v] += 1
    queue = deque(v for v in G if indegree[v] == 0)
    count = 0
    while queue:
        u = queue.popleft()
        yield u
        count += 1
        for _, v in G.edges(u):
            indegree[v] -= 1
            if indegree[v] == 0:
                queue.append(v)
    if count != len(G):
        raise NetworkXUnfeasible(
            "Graph contains a cycle or graph changed during iteration"
        )


def lexicographic_topological_sort(G, key=None):
    """Yield nodes in lexicographic topological order.

    Raises ``NetworkXUnfeasible`` on a cyclic graph for nx parity
    (br-zzcm7).
    """
    try:
        if key is None:
            yield from _raw_lexicographic_topological_sort(G)
        else:
            yield from _raw_lexicographic_topological_sort(G, key)
    except HasACycle as exc:
        raise NetworkXUnfeasible(
            "Graph contains a cycle or graph changed during iteration"
        ) from exc


def topological_generations(G):
    """Yield per-generation sets of nodes in topological order.

    Raises ``NetworkXUnfeasible`` on a cyclic graph for nx parity
    (br-zzcm7).
    """
    try:
        yield from _raw_topological_generations(G)
    except HasACycle as exc:
        raise NetworkXUnfeasible(
            "Graph contains a cycle or graph changed during iteration"
        ) from exc
    except NetworkXError as exc:
        # br-r37-c1-1ewpw: nx uses "Topological sort not defined on
        # undirected graphs." for both topological_sort AND
        # topological_generations. The Rust binding uses
        # "Topological generations not defined ...". Translate so
        # drop-in code matching the message text works.
        if "Topological generations not defined" in str(exc):
            raise NetworkXError(
                "Topological sort not defined on undirected graphs."
            ) from exc
        raise


def dag_longest_path(G, weight="weight", default_weight=1, topo_order=None):
    """Return the longest path in a DAG.

    Parameters
    ----------
    G : DiGraph
        A directed acyclic graph (DAG).
    weight : str, optional
        Edge attribute name to use for weights. Default is 'weight'.
    default_weight : int, optional
        Default weight for edges without the weight attribute. Default is 1.
    topo_order : iterable, optional
        Precomputed topological order of the nodes.

    Returns
    -------
    list
        The longest path as a list of nodes.

    br-r37-c1-sn6tm: nx's algorithm is tie-break-sensitive — it picks
    the FIRST predecessor by iteration order when two paths have equal
    length (``max(us, key=lambda x: x[0])`` returns the first max).
    Previously we delegated to nx via ``_call_networkx_for_parity``
    which converts through ``_fnx_to_nx``; that conversion emits edges
    in per-node adj iteration order (``_topo_emit_edges_by_adj``),
    which does NOT preserve the ``pred[v]`` insertion order users
    actually built. nx then saw a different tie-break and returned a
    different (but equally valid) longest path. Implementing the
    algorithm directly on fnx's native ``G.pred[v]`` view sidesteps the
    conversion loss and reproduces nx semantics exactly.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented(
            "not implemented for undirected type"
        )
    if len(G) == 0:
        return []

    if topo_order is None:
        topo_order = topological_sort(G)

    is_multi = G.is_multigraph()
    dist = {}  # {v: (length, u)}
    for v in topo_order:
        us = []
        pred_items = G.pred[v].items()
        for u, data in pred_items:
            if is_multi:
                # Pick the heaviest parallel edge between u and v.
                edge_weight = max(
                    (
                        attrs.get(weight, default_weight)
                        if isinstance(attrs, dict)
                        else default_weight
                        for attrs in data.values()
                    ),
                    default=default_weight,
                )
            else:
                edge_weight = (
                    data.get(weight, default_weight)
                    if isinstance(data, dict)
                    else default_weight
                )
            us.append((dist[u][0] + edge_weight, u))
        # nx's tie-break: max with key=x[0] returns the FIRST element
        # with the max first component (Python's max stability).
        maxu = max(us, key=lambda x: x[0]) if us else (0, v)
        dist[v] = maxu if maxu[0] >= 0 else (0, v)

    u = None
    v = max(dist, key=lambda x: dist[x][0])
    path = []
    while u != v:
        path.append(v)
        u = v
        v = dist[v][1]
    path.reverse()
    return path


def _dag_has_weight_edge_attr(G, weight):
    """Return True if any edge in ``G`` has the ``weight`` attribute
    set — used by dag_longest_path / dag_longest_path_length to decide
    whether to delegate to nx for correct weighted-path selection
    (the Rust fast path ignores edge weights).
    """
    if not isinstance(weight, str):
        return False
    for _, _, attrs in G.edges(data=True):
        if isinstance(attrs, dict) and weight in attrs:
            return True
    return False


def dag_longest_path_length(G, weight="weight", default_weight=1):
    """Return the length of the longest path in a DAG.

    Parameters
    ----------
    G : DiGraph
        A directed acyclic graph (DAG).
    weight : str, optional
        Edge attribute name to use for weights. Default is 'weight'.
    default_weight : int, optional
        Default weight for edges without the weight attribute. Default is 1.

    Returns
    -------
    int
        The length of the longest path.

    br-daglongundir: nx is @not_implemented_for('undirected') and
    raises NetworkXNotImplemented('not implemented for undirected type').
    The Rust binding raised NetworkXError with a different message —
    callers catching NetworkXNotImplemented would miss the signal.
    Gate on G.is_directed() so the exception class matches.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    return _call_networkx_for_parity(
        "dag_longest_path_length",
        G,
        weight=weight,
        default_weight=default_weight,
    )

