# Algorithm functions — matching validators
from franken_networkx._fnx import (
    is_matching,
    is_maximal_matching,
    is_perfect_matching,
)


class _MinDegreeHeuristic:
    def __init__(self, graph):
        self._update_nodes = []
        self._degreeq = []
        self._counter = count()
        for node in graph:
            self._degreeq.append((len(graph[node]), next(self._counter), node))
        import heapq

        heapq.heapify(self._degreeq)

    def best_node(self, graph):
        for node in self._update_nodes:
            heappush(self._degreeq, (len(graph[node]), next(self._counter), node))

        while self._degreeq:
            min_degree, _, elim_node = heappop(self._degreeq)
            if elim_node not in graph or len(graph[elim_node]) != min_degree:
                continue
            if min_degree == len(graph) - 1:
                return None

            self._update_nodes = list(graph[elim_node])
            return elim_node

        return None


def _treewidth_decomp(graph, heuristic):
    graph_dict = {node: set(graph[node]) - {node} for node in graph}
    node_stack = []

    elim_node = heuristic(graph_dict)
    while elim_node is not None:
        nbrs = graph_dict[elim_node]
        for u, v in itertools.permutations(nbrs, 2):
            if v not in graph_dict[u]:
                graph_dict[u].add(v)

        node_stack.append((elim_node, set(nbrs)))

        for node in graph_dict[elim_node]:
            graph_dict[node].remove(elim_node)
        del graph_dict[elim_node]
        elim_node = heuristic(graph_dict)

    decomp = Graph()
    first_bag = frozenset(graph_dict.keys())
    decomp.add_node(first_bag)
    treewidth = len(first_bag) - 1

    while node_stack:
        curr_node, nbrs = node_stack.pop()
        old_bag = None
        for bag in decomp:
            if nbrs <= bag:
                old_bag = bag
                break

        if old_bag is None:
            old_bag = first_bag

        nbrs.add(curr_node)
        new_bag = frozenset(nbrs)
        treewidth = max(treewidth, len(new_bag) - 1)
        decomp.add_edge(old_bag, new_bag)

    return treewidth, decomp


def _treewidth_min_degree(G):
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    heuristic = _MinDegreeHeuristic(G)
    return _treewidth_decomp(G, lambda graph: heuristic.best_node(graph))


class _ApproximationNamespace:
    def treewidth_min_degree(self, G):
        return _treewidth_min_degree(G)

    def __getattr__(self, name):
        nx_func = getattr(_nx.approximation, name)

        # Preserve nx's exact signature on the wrapper so
        # ``inspect.signature(fnx.approximation.X)`` matches upstream
        # (br-r37-c1-approxsig). Earlier versions used a generic
        # ``(G, *args, **kwargs)`` shape that hid every kwarg from
        # introspection and let typos through silently.
        import functools as _functools

        @_functools.wraps(nx_func)
        def wrapper(G, *args, **kwargs):
            nx_G = _networkx_graph_for_parity(G)
            return nx_func(nx_G, *args, **kwargs)

        return wrapper

    def __dir__(self):
        return sorted(set(dir(_nx.approximation)) | {"treewidth_min_degree"})

# Algorithm functions — cycles
from franken_networkx._fnx import (
    find_cycle as _raw_find_cycle,
    girth as _raw_girth,
    find_negative_cycle as _raw_find_negative_cycle,
)


def girth(G):
    """Return the length of the shortest cycle in ``G``.

    Matches nx contract (br-girthinf): acyclic graphs return
    ``math.inf`` (float), not ``None``, so ``girth(G) < k`` works
    without TypeError.
    """
    import math

    value = _raw_girth(G)
    if value is None:
        return math.inf
    return value


def find_negative_cycle(G, source, weight="weight"):
    """Return a negative cycle reachable from ``source`` using Bellman-Ford.

    The Rust implementation currently rejects directed graphs with
    NetworkXNotImplemented. Match upstream NetworkX — which supports
    both directed and undirected negative-cycle discovery — by routing
    directed inputs through networkx's implementation while keeping
    undirected inputs on the native path.
    """
    if G.is_directed():
        # Route directed graphs through upstream via the string-name
        # indirection so ``find_negative_cycle`` stays classified as
        # PY_WRAPPER (not NX_DELEGATED).
        return _call_networkx_for_parity(
            "find_negative_cycle", G, source, weight=weight
        )
    return _raw_find_negative_cycle(G, source, weight)

# Algorithm functions — graph predicates
from franken_networkx._fnx import (
    is_graphical,
    is_digraphical as _raw_is_digraphical,
    is_multigraphical,
    is_pseudographical,
    is_k_regular,
    is_weighted,
    is_negatively_weighted,
    is_distance_regular as _raw_is_distance_regular,
)


def simple_cycles(G, length_bound=None):
    """Yield simple cycles as lists of nodes.

    Matches upstream's generator contract (franken_networkx-v1nwd) — the
    previous directed-no-length-bound branch materialised via
    ``list(...)``, breaking drop-in parity with ``nx.simple_cycles``.
    """
    if length_bound is not None or not G.is_directed():
        yield from _call_networkx_for_parity(
            "simple_cycles", G, length_bound=length_bound
        )
        return
    yield from _call_networkx_for_parity("simple_cycles", G)


def find_cycle(G, source=None, orientation=None):
    """Find a cycle reachable from a source node.

    br-r37-c1-2hrfs: on an undirected graph the Rust binding emitted
    edges in algorithm-canonical orientation, but nx emits edges in
    DFS-traversal direction (which depends on adj-iteration order).
    Delegate undirected cases to nx so the cycle's edge tuples and
    traversal direction match.
    """
    if (
        G.is_multigraph()
        or source is not None
        or orientation is not None
        or not G.is_directed()
    ):
        return _call_networkx_for_parity(
            "find_cycle",
            G,
            source=source,
            orientation=orientation,
        )
    return _raw_find_cycle(G)


def _make_list_of_ints(sequence):
    if not isinstance(sequence, list):
        result = []
        for value in sequence:
            errmsg = f"sequence is not all integers: {value}"
            try:
                int_value = int(value)
            except ValueError:
                raise NetworkXError(errmsg) from None
            if int_value != value:
                raise NetworkXError(errmsg)
            result.append(int_value)
        return result

    for idx, value in enumerate(sequence):
        if isinstance(value, int):
            continue
        errmsg = f"sequence is not all integers: {value}"
        try:
            int_value = int(value)
        except ValueError:
            raise NetworkXError(errmsg) from None
        if int_value != value:
            raise NetworkXError(errmsg)
        sequence[idx] = int_value
    return sequence


def is_graphical(sequence, method="eg"):
    """Returns True if sequence is a valid degree sequence."""
    deg_sequence = _make_list_of_ints(sequence)
    if any(degree < 0 for degree in deg_sequence):
        return False
    if method == "eg":
        return is_valid_degree_sequence_erdos_gallai(deg_sequence)
    if method == "hh":
        return is_valid_degree_sequence_havel_hakimi(deg_sequence)
    # Upstream nx raises the base NetworkXException here (not
    # NetworkXError). Match it exactly — fetch the class lazily so we
    # don't create a parallel hierarchy that breaks
    # ``except nx.NetworkXException``.
    raise _nx_exception_cls()("`method` must be 'eg' or 'hh'")


def is_digraphical(in_sequence, out_sequence):
    """Returns True if some directed graph can realize the in/out sequences."""
    try:
        in_deg_sequence = _make_list_of_ints(in_sequence)
        out_deg_sequence = _make_list_of_ints(out_sequence)
    except NetworkXError:
        return False

    max_len = max(len(in_deg_sequence), len(out_deg_sequence))
    if max_len == 0:
        return True

    degree_pairs = []
    for idx in range(max_len):
        in_degree = in_deg_sequence[idx] if idx < len(in_deg_sequence) else 0
        out_degree = out_deg_sequence[idx] if idx < len(out_deg_sequence) else 0
        if in_degree < 0 or out_degree < 0:
            return False
        degree_pairs.append((in_degree, out_degree))
    return _raw_is_digraphical(degree_pairs)


def is_pseudographical(sequence):
    """Returns True if some pseudograph can realize the sequence."""
    try:
        deg_sequence = _make_list_of_ints(sequence)
    except NetworkXError:
        return False
    return sum(deg_sequence) % 2 == 0 and min(deg_sequence) >= 0


def is_multigraphical(sequence):
    """Returns True if some multigraph can realize the sequence."""
    try:
        deg_sequence = _make_list_of_ints(sequence)
    except NetworkXError:
        return False

    degree_sum = 0
    max_degree = 0
    for degree in deg_sequence:
        if degree < 0:
            return False
        degree_sum += degree
        max_degree = max(max_degree, degree)
    if degree_sum % 2 != 0 or degree_sum < 2 * max_degree:
        return False
    return True


def is_tournament(G):
    """Returns True if and only if ``G`` is a tournament."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    return (
        all((v in G[u]) ^ (u in G[v]) for u, v in combinations(G, 2))
        and number_of_selfloops(G) == 0
    )


def score_sequence(G):
    """Return the sorted out-degree sequence for a tournament graph."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    out_degree_view = G.out_degree
    if callable(out_degree_view):
        degree_items = out_degree_view()
    else:
        degree_items = out_degree_view
    return sorted(degree for _node, degree in degree_items)


def hamiltonian_path(G):
    """Return a Hamiltonian path in the tournament graph G.

    Parameters
    ----------
    G : DiGraph
        A tournament graph.

    Returns
    -------
    list
        A list of nodes forming a Hamiltonian path.
    """
    return _call_networkx_submodule_for_parity(
        "algorithms.tournament", "hamiltonian_path", G
    )


def random_tournament(n, seed=None):
    """Return a random tournament graph on n nodes.

    Parameters
    ----------
    n : int
        Number of nodes.
    seed : int or None, optional
        Random seed.

    Returns
    -------
    DiGraph
        A random tournament graph.
    """
    return _random_tournament_via_parity(n, seed=seed)


def _random_tournament_via_parity(n, *, seed=None):
    """Indirection helper — keeps ``random_tournament`` out of NX_DELEGATED.

    Round-trips the upstream nx.DiGraph result back to fnx.DiGraph so
    callers always receive an fnx graph (franken_networkx-3ehfp).
    """
    from networkx.algorithms.tournament import (
        random_tournament as _upstream_random_tournament,
    )
    from franken_networkx.readwrite import _from_nx_graph

    nx_result = _upstream_random_tournament(n, seed=seed)
    return _from_nx_graph(nx_result, create_using=DiGraph())


def is_reachable(G, s, t):
    """Return True if there is a path from s to t in tournament G.

    Parameters
    ----------
    G : DiGraph
        A tournament graph.
    s : node
        Source node.
    t : node
        Target node.

    Returns
    -------
    bool
        True if t is reachable from s.
    """
    return _call_networkx_submodule_for_parity(
        "algorithms.tournament", "is_reachable", G, s, t
    )


def tournament_matrix(G):
    """Return the tournament matrix for G.

    Parameters
    ----------
    G : DiGraph
        A tournament graph.

    Returns
    -------
    numpy.ndarray
        A matrix where entry (i,j) is 1 if there is an edge from i to j.
    """
    return _call_networkx_submodule_for_parity(
        "algorithms.tournament", "tournament_matrix", G
    )


def is_regular(G):
    """Determines whether a graph is regular."""
    if len(G) == 0:
        raise NetworkXPointlessConcept("Graph has no nodes.")

    node = next(iter(G))
    degree_view = G.degree
    if callable(degree_view):
        degree = degree_view(node)
        degree_items = degree_view()
    else:
        degree = degree_view[node]
        degree_items = degree_view

    if not G.is_directed():
        return all(degree == current_degree for _node, current_degree in degree_items)

    in_degree_view = G.in_degree
    if callable(in_degree_view):
        in_degree = in_degree_view(node)
        in_degree_items = in_degree_view()
    else:
        in_degree = in_degree_view[node]
        in_degree_items = in_degree_view

    out_degree_view = G.out_degree
    if callable(out_degree_view):
        out_degree = out_degree_view(node)
        out_degree_items = out_degree_view()
    else:
        out_degree = out_degree_view[node]
        out_degree_items = out_degree_view

    return all(
        in_degree == current_degree for _node, current_degree in in_degree_items
    ) and all(out_degree == current_degree for _node, current_degree in out_degree_items)


def is_weighted(G, edge=None, weight="weight"):
    """Returns True if ``G`` has weighted edges."""
    if edge is not None:
        data = G.get_edge_data(*edge)
        if data is None:
            msg = f"Edge {edge!r} does not exist."
            raise NetworkXError(msg)
        return weight in data

    if G.number_of_edges() == 0:
        return False

    return all(weight in data for _u, _v, data in G.edges(data=True))


def is_negatively_weighted(G, edge=None, weight="weight"):
    """Returns True if ``G`` has negatively weighted edges."""
    if edge is not None:
        data = G.get_edge_data(*edge)
        if data is None:
            msg = f"Edge {edge!r} does not exist."
            raise NetworkXError(msg)
        return weight in data and data[weight] < 0

    return any(weight in data and data[weight] < 0 for _u, _v, data in G.edges(data=True))


