    raw = _raw_all_pairs_dijkstra_path_length(G, weight=weight)
    for node in G.nodes():
        if node in raw:
            # br-r37-c1-6rphu: reorder inner dict by (distance, BFS).
            inner = dict(raw[node])
            order = _reorder_by_distance(inner, G=G, source=node)
            yield (node, {k: inner[k] for k in order})


