# ---------------------------------------------------------------------------
# Community detection — additional algorithms
# ---------------------------------------------------------------------------


def girvan_newman(G, most_valuable_edge=None):
    """Find communities in graph ``G`` using the Girvan-Newman method."""
    if G.number_of_edges() == 0:
        yield tuple(connected_components(G))
        return

    if most_valuable_edge is None:

        def most_valuable_edge(graph):
            betweenness = edge_betweenness_centrality(graph)
            return max(betweenness, key=betweenness.get)

    graph = G.copy().to_undirected()
    graph.remove_edges_from(list(selfloop_edges(graph)))
    while graph.number_of_edges() > 0:
        yield _without_most_valuable_edges(graph, most_valuable_edge)


def _without_most_valuable_edges(G, most_valuable_edge):
    """Remove edges until the number of connected components increases."""
    original_num_components = number_connected_components(G)
    num_new_components = original_num_components
    while num_new_components <= original_num_components:
        edge = most_valuable_edge(G)
        G.remove_edge(*edge)
        new_components = tuple(connected_components(G))
        num_new_components = len(new_components)
    return new_components


def k_clique_communities(G, k, cliques=None):
    """Find k-clique communities using the clique percolation method.

    A k-clique community is the union of all cliques of size k that can
    be reached through adjacent (sharing k-1 nodes) k-cliques.

    Parameters
    ----------
    G : Graph
        The input graph.
    k : int
        Size of the smallest clique.
    cliques : iterable of lists, optional
        Pre-computed cliques. If provided, delegates to NetworkX which
        handles the user-provided clique enumeration.

    Yields
    ------
    frozenset
        Each yielded set is a k-clique community.
    """
    if k < 2:
        raise ValueError("k must be >= 2")
    if cliques is not None:
        yield from _call_networkx_for_parity(
            "k_clique_communities", G, k, cliques=cliques
        )
        return
    for community in _fnx.k_clique_communities_rust(G, k):
        yield community


# ---------------------------------------------------------------------------
# Graph attribute helpers (high-frequency NetworkX utilities)
# ---------------------------------------------------------------------------


def _edge_attribute_dict(G, edge):
    if G.is_multigraph():
        u, v, key = edge
        try:
            return G[u][v][key]
        except KeyError:
            if G.is_directed():
                raise
            return G[v][u][key]

    u, v = edge
    try:
        return G[u][v]
    except KeyError:
        if G.is_directed():
            raise
        return G[v][u]


def set_node_attributes(G, values, name=None):
    """Set node attributes from a dictionary or scalar.

    Parameters
    ----------
    G : Graph
        The graph to modify.
    values : dict or scalar
        If a dict keyed by node, ``values[node]`` is the attribute value.
        If a dict keyed by node mapping to dicts, each inner dict is merged
        into the node's attributes. If a scalar, set it for all nodes.
    name : str, optional
        Attribute name. Required when *values* is a dict of scalars or a scalar.
    """
    if isinstance(values, Mapping):
        if name is not None:
            for node, value in values.items():
                if G.has_node(node):
                    G.nodes[node][name] = value
            return

        for node, attrs in values.items():
            if G.has_node(node):
                G.nodes[node].update(attrs)
        return

    if name is not None:
        for node in G.nodes():
            G.nodes[node][name] = values
        return

    values.items()


def get_node_attributes(G, name, default=None):
    """Return a dictionary of node attributes keyed by node.

    Parameters
    ----------
    G : Graph
        The input graph.
    name : str
        Attribute name.

    Returns
    -------
    dict
        ``{node: value}`` for nodes that have the attribute.
    """
    result = {}
    include_missing = default is not None
    for node in G.nodes():
        attrs = G.nodes[node]
        if name in attrs:
            result[node] = attrs[name]
        elif include_missing:
            result[node] = default
    return result


def set_edge_attributes(G, values, name=None):
    """Set edge attributes from a dictionary or scalar.

    Parameters
    ----------
    G : Graph
        The graph to modify.
    values : dict or scalar
        If a dict keyed by ``(u, v)``, sets the attribute per edge.
        If a scalar, sets it for all edges.
    name : str, optional
        Attribute name. Required when *values* is a scalar.
    """
    if isinstance(values, Mapping):
        if name is not None:
            for edge, value in values.items():
                try:
                    _edge_attribute_dict(G, edge)[name] = value
                except (KeyError, ValueError):
                    continue
            return

        for edge, attrs in values.items():
            try:
                _edge_attribute_dict(G, edge).update(attrs)
            except (KeyError, ValueError):
                continue
        return

    if name is not None:
        if G.is_multigraph():
            for u, v, key, attrs in G.edges(keys=True, data=True):
                attrs[name] = values
        else:
            for u, v, attrs in G.edges(data=True):
                attrs[name] = values
        return

    values.items()


def get_edge_attributes(G, name, default=None):
    """Return a dictionary of edge attributes keyed by ``(u, v)``.

    Parameters
    ----------
    G : Graph
        The input graph.
    name : str
        Attribute name.

    Returns
    -------
    dict
        ``{(u, v): value}`` for edges that have the attribute.
    """
    result = {}
    include_missing = default is not None
    if G.is_multigraph():
        for u, v, key, attrs in G.edges(keys=True, data=True):
            if name in attrs:
                result[(u, v, key)] = attrs[name]
            elif include_missing:
                result[(u, v, key)] = default
        return result

    for u, v, attrs in G.edges(data=True):
        if name in attrs:
            result[(u, v)] = attrs[name]
        elif include_missing:
            result[(u, v)] = default
    return result


def create_empty_copy(G, with_data=True):
    """Return an empty copy of *G* (same nodes, no edges).

    Parameters
    ----------
    G : Graph
        The input graph.
    with_data : bool, optional
        If True (default), preserve node attributes.

    Returns
    -------
    H : Graph
        A graph with the same nodes but no edges.
    """
    H = G.__class__()
    if with_data:
        H.graph.update(dict(G.graph))
        H.add_nodes_from((node, dict(attrs)) for node, attrs in G.nodes(data=True))
    else:
        H.add_nodes_from(G.nodes())
    return H


def number_of_selfloops(G):
    """Return the number of self-loop edges in *G*."""
    return sum(1 for _ in selfloop_edges(G))


def selfloop_edges(G, data=False, keys=False, default=None):
    """Return an iterator over self-loop edges.

    Parameters
    ----------
    G : Graph
        The input graph.
    data : string or bool, optional
        Return self-loop edges as ``(u, u)`` tuples when ``False``, or include
        edge data when ``True`` or an attribute value when set to a string.
    keys : bool, optional
        If True, include edge keys for multigraphs.
    default : Any, optional
        Default attribute value used when ``data`` names a missing attribute.

    Returns
    -------
    iterator
        Iterator over self-loop edges.
    """
    def adjacency_entries():
        for node in G.adj:
            nbrs = G.adj[node]
            if node in nbrs:
                yield node, nbrs

    if data is True:
        if G.is_multigraph():
            if keys is True:
                return (
                    (n, n, key, attrs)
                    for n, nbrs in adjacency_entries()
                    for key, attrs in nbrs[n].items()
                )
            return (
                (n, n, attrs)
                for n, nbrs in adjacency_entries()
                for attrs in nbrs[n].values()
            )
        return ((n, n, nbrs[n]) for n, nbrs in adjacency_entries())

    if data is not False:
        if G.is_multigraph():
            if keys is True:
                return (
                    (n, n, key, attrs.get(data, default))
                    for n, nbrs in adjacency_entries()
                    for key, attrs in nbrs[n].items()
                )
            return (
                (n, n, attrs.get(data, default))
                for n, nbrs in adjacency_entries()
                for attrs in nbrs[n].values()
            )
        return (
            (n, n, nbrs[n].get(data, default))
            for n, nbrs in adjacency_entries()
        )

    if G.is_multigraph():
        if keys is True:
            return (
                (n, n, key)
                for n, nbrs in adjacency_entries()
                for key in nbrs[n]
            )
        return (
            (n, n)
            for n, nbrs in adjacency_entries()
            for _ in range(len(nbrs[n]))
        )
    return ((n, n) for n, nbrs in adjacency_entries())


def nodes_with_selfloops(G):
    """Return nodes that have self-loops."""
    return (node for node in G.adj if node in G.adj[node])


def all_neighbors(graph, node):
    """Return all neighbors of *node* in *graph* (predecessors + successors on DiGraph).

    First parameter named ``graph`` to match networkx's public signature.
    For undirected graphs, equivalent to ``graph.neighbors(node)``.
    For directed graphs, returns predecessors followed by successors.
    """
    if graph.is_directed():
        return itertools.chain(graph.predecessors(node), graph.successors(node))
    return graph.neighbors(node)


def is_path(G, path):
    """Return whether or not the specified path exists in *G*."""
    try:
        return all(nbr in G[node] for node, nbr in itertools.pairwise(path))
    except (KeyError, TypeError):
        return False


def path_weight(G, path, weight):
    """Return the total cost associated with *path* using edge attribute *weight*."""
    if not is_path(G, path):
        raise NetworkXNoPath("path does not exist")

    cost = 0
    if G.is_multigraph():
        for node, nbr in itertools.pairwise(path):
            cost += min(attrs[weight] for attrs in G[node][nbr].values())
        return cost

    for node, nbr in itertools.pairwise(path):
        cost += G[node][nbr][weight]
    return cost


def add_path(G_to_add_to, nodes_for_path, **attr):
    """Add a path of edges to *G*."""
    G = G_to_add_to
    node_list = list(nodes_for_path)
    if not node_list:
        return
    G.add_node(node_list[0])
    for i in range(len(node_list) - 1):
        G.add_edge(node_list[i], node_list[i + 1], **attr)


def add_cycle(G_to_add_to, nodes_for_cycle, **attr):
    """Add a cycle of edges to *G*."""
    G = G_to_add_to
    node_list = list(nodes_for_cycle)
    if not node_list:
        return
    G.add_node(node_list[0])
    if len(node_list) == 1:
        G.add_edge(node_list[0], node_list[0], **attr)
        return
    for i in range(len(node_list) - 1):
        G.add_edge(node_list[i], node_list[i + 1], **attr)
    G.add_edge(node_list[-1], node_list[0], **attr)


def add_star(G_to_add_to, nodes_for_star, **attr):
    """Add a star of edges to *G* (first node is the center)."""
    G = G_to_add_to
    node_list = list(nodes_for_star)
    if not node_list:
        return
    center = node_list[0]
    G.add_node(center)
    for spoke in node_list[1:]:
        G.add_edge(center, spoke, **attr)


def _validate_product_graph_types(G, H, *, allow_directed=True, allow_multigraph=True):
    if G.is_directed() != H.is_directed():
        raise NetworkXError("G and H must be both directed or both undirected")
    if G.is_directed() and not allow_directed:
        raise NetworkXNotImplemented("not implemented for directed type")
    if (G.is_multigraph() or H.is_multigraph()) and not allow_multigraph:
        raise NetworkXNotImplemented("not implemented for multigraph type")


def _product_graph_class(G, H):
    if G.is_directed():
        return MultiDiGraph if (G.is_multigraph() or H.is_multigraph()) else DiGraph
    return MultiGraph if (G.is_multigraph() or H.is_multigraph()) else Graph


def _product_node_attrs(g_attrs, h_attrs):
    merged = {}
    for key in set(g_attrs) | set(h_attrs):
        merged[key] = (g_attrs.get(key), h_attrs.get(key))
    return merged


def _paired_edge_attrs(g_attrs, h_attrs):
    merged = {}
    for key in set(g_attrs) | set(h_attrs):
        merged[key] = (g_attrs.get(key), h_attrs.get(key))
    return merged


def _cross_product_edge_key(g_is_multigraph, h_is_multigraph, g_key, h_key):
    if g_is_multigraph and h_is_multigraph:
        return (g_key, h_key)
    if g_is_multigraph:
        return g_key
    if h_is_multigraph:
        return h_key
    return None


def cartesian_product(G, H):
    """Return the Cartesian product of *G* and *H*.

    The Cartesian product has node set ``V(G) x V(H)``. Two nodes
    ``(u1, v1)`` and ``(u2, v2)`` are adjacent iff ``u1 == u2`` and
    ``(v1, v2)`` is an edge in *H*, or ``v1 == v2`` and ``(u1, u2)``
    is an edge in *G*.
    """
    _validate_product_graph_types(G, H)
    P = _product_graph_class(G, H)()

    for g, g_attrs in G.nodes(data=True):
        for h, h_attrs in H.nodes(data=True):
            P.add_node((g, h), **_product_node_attrs(dict(g_attrs), dict(h_attrs)))

    if G.is_multigraph():
        for u, v, key, attrs in G.edges(keys=True, data=True):
            for h in H.nodes():
                # 4-tuple form avoids `key=key, **attrs` collision when attrs
                # contains a 'key' entry (franken_networkx-uphdr).
                P.add_edges_from([((u, h), (v, h), key, dict(attrs))])
    else:
        for u, v, attrs in G.edges(data=True):
            for h in H.nodes():
                P.add_edge((u, h), (v, h), **dict(attrs))

    if H.is_multigraph():
        for u, v, key, attrs in H.edges(keys=True, data=True):
            for g in G.nodes():
                P.add_edges_from([((g, u), (g, v), key, dict(attrs))])
    else:
        for u, v, attrs in H.edges(data=True):
            for g in G.nodes():
                P.add_edge((g, u), (g, v), **dict(attrs))

    return P


def tensor_product(G, H):
    """Return the tensor (categorical) product of *G* and *H*.

    Two nodes ``(u1, v1)`` and ``(u2, v2)`` are adjacent iff
    ``(u1, u2)`` is an edge in *G* AND ``(v1, v2)`` is an edge in *H*.
    """
    _validate_product_graph_types(G, H)
    P = _product_graph_class(G, H)()

    for g, g_attrs in G.nodes(data=True):
        for h, h_attrs in H.nodes(data=True):
            P.add_node((g, h), **_product_node_attrs(dict(g_attrs), dict(h_attrs)))

    if G.is_multigraph():
        g_edges = list(G.edges(keys=True, data=True))
    else:
        g_edges = [(u, v, None, attrs) for u, v, attrs in G.edges(data=True)]
    if H.is_multigraph():
        h_edges = list(H.edges(keys=True, data=True))
    else:
        h_edges = [(u, v, None, attrs) for u, v, attrs in H.edges(data=True)]

    for gu, gv, gk, g_attrs in g_edges:
        for hu, hv, hk, h_attrs in h_edges:
            edge_attrs = _paired_edge_attrs(dict(g_attrs), dict(h_attrs))
            if P.is_multigraph():
                edge_key = _cross_product_edge_key(G.is_multigraph(), H.is_multigraph(), gk, hk)
                # 4-tuple form avoids `key=edge_key, **edge_attrs`
                # collision when edge_attrs contains a 'key' entry
                # (franken_networkx-uphdr).
                P.add_edges_from([((gu, hu), (gv, hv), edge_key, dict(edge_attrs))])
                if not G.is_directed():
                    P.add_edges_from([((gu, hv), (gv, hu), edge_key, dict(edge_attrs))])
            else:
                P.add_edge((gu, hu), (gv, hv), **edge_attrs)
                if not G.is_directed():
                    P.add_edge((gu, hv), (gv, hu), **edge_attrs)

    return P


def strong_product(G, H):
    """Return the strong product of *G* and *H*.

    Union of Cartesian and tensor products.
    """
    _validate_product_graph_types(G, H)
    P = cartesian_product(G, H)

    if G.is_multigraph():
        g_edges = list(G.edges(keys=True, data=True))
    else:
        g_edges = [(u, v, None, attrs) for u, v, attrs in G.edges(data=True)]
    if H.is_multigraph():
        h_edges = list(H.edges(keys=True, data=True))
    else:
        h_edges = [(u, v, None, attrs) for u, v, attrs in H.edges(data=True)]

    for gu, gv, gk, g_attrs in g_edges:
        for hu, hv, hk, h_attrs in h_edges:
            edge_attrs = _paired_edge_attrs(dict(g_attrs), dict(h_attrs))
            if P.is_multigraph():
                edge_key = _cross_product_edge_key(G.is_multigraph(), H.is_multigraph(), gk, hk)
                # 4-tuple form avoids `key=edge_key, **edge_attrs`
                # collision when edge_attrs contains a 'key' entry
                # (franken_networkx-uphdr).
                P.add_edges_from([((gu, hu), (gv, hv), edge_key, dict(edge_attrs))])
                if not G.is_directed():
                    P.add_edges_from([((gu, hv), (gv, hu), edge_key, dict(edge_attrs))])
            else:
                P.add_edge((gu, hu), (gv, hv), **edge_attrs)
                if not G.is_directed():
                    P.add_edge((gu, hv), (gv, hu), **edge_attrs)

    return P


# ---------------------------------------------------------------------------
# Additional high-value utilities
# ---------------------------------------------------------------------------


def adjacency_matrix(G, nodelist=None, dtype=None, weight="weight"):
    """Return the adjacency matrix of *G* as a SciPy sparse array.

    This is an alias for ``to_scipy_sparse_array``.
    """
    return to_scipy_sparse_array(G, nodelist=nodelist, dtype=dtype, weight=weight)


def has_bridges(G, root=None):
    """Return True if graph *G* has at least one bridge.

    Parameters
    ----------
    G : graph
        An undirected graph.
    root : node, optional
        A node in the graph. If specified, only check the connected
        component containing root.

    Returns
    -------
    bool
        True if G has at least one bridge.
    """
    for _ in bridges(G, root=root):
        return True
    return False


def local_bridges(G, with_span=True, weight=None):
    """Yield local bridges in *G*.

    A local bridge is an edge (u, v) where u and v have no common neighbors.
    If ``with_span`` is True, yields ``(u, v, span)`` where span is the
    distance between u and v after virtually removing the edge.

    Matches the upstream ``@not_implemented_for("directed", "multigraph")``
    decorator (br-zzcm8) — directed and multigraph inputs raise
    NetworkXNotImplemented instead of silently projecting to simple
    graphs.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not with_span and weight is None:
        from franken_networkx._fnx import local_bridges_rust

        return iter(local_bridges_rust(G))

    def _generate():
        for u, v in G.edges():
            u_nbrs = set(G.neighbors(u))
            v_nbrs = set(G.neighbors(v))
            u_nbrs.discard(v)
            v_nbrs.discard(u)
            if u_nbrs & v_nbrs:
                continue  # common neighbor exists — not a local bridge
            if with_span:
                # Compute shortest path from u to v not using edge (u,v).
                # BFS/Dijkstra from u, but skip the direct u->v hop.
                from collections import deque

                if weight is None:
                    # Unweighted BFS avoiding direct (u,v) edge.
                    dist = {u: 0}
                    queue = deque([u])
                    found = False
                    while queue and not found:
                        curr = queue.popleft()
                        for nbr in G.neighbors(curr):
                            # Skip the direct u<->v edge.
                            if curr == u and nbr == v:
                                continue
                            if curr == v and nbr == u:
                                continue
                            if nbr not in dist:
                                dist[nbr] = dist[curr] + 1
                                if nbr == v:
                                    found = True
                                    break
                                queue.append(nbr)
                    span = dist.get(v, float("inf"))
                else:
                    # Weighted: Dijkstra avoiding direct (u,v) edge.
                    import heapq

                    dist = {u: 0}
                    heap = [(0, u)]
                    while heap:
                        d, curr = heapq.heappop(heap)
                        if d > dist.get(curr, float("inf")):
                            continue
                        if curr == v:
                            break
                        for nbr in G.neighbors(curr):
                            if curr == u and nbr == v:
                                continue
                            if curr == v and nbr == u:
                                continue
                            w = G[curr][nbr].get(weight, 1)
                            nd = d + w
                            if nd < dist.get(nbr, float("inf")):
                                dist[nbr] = nd
                                heapq.heappush(heap, (nd, nbr))
                    span = dist.get(v, float("inf"))
                yield (u, v, span)
            else:
                yield (u, v)

    return _generate()


def minimum_edge_cut(G, s=None, t=None, flow_func=None):
    """Return a minimum edge cut of *G*.

    br-r37-c1-5jbv9: when multiple equally-small cuts exist, the
    local (s, t)-partition-derived cut and the all-pairs candidate
    enumeration both depended on adj-iteration order, picking a
    different (but equally valid) cut than nx. Delegate to nx so
    the chosen cut and edge tuple direction match its
    s_t_minimum_cut traversal contract exactly.
    """
    return _call_networkx_for_parity(
        "minimum_edge_cut", G, s=s, t=t, flow_func=flow_func,
    )

    def cut_edges_for_partition(source_partition, sink_partition):
        source_set = set(source_partition)
        sink_set = set(sink_partition)
        cut_edges = set()
        if G.is_multigraph():
            for u, v, key in G.edges(keys=True):
                if G.is_directed():
                    if u in source_set and v in sink_set:
                        cut_edges.add((u, v, key))
                elif (u in source_set and v in sink_set) or (
                    u in sink_set and v in source_set
                ):
                    cut_edges.add((u, v, key))
            return cut_edges

        for u, v in G.edges():
            if G.is_directed():
                if u in source_set and v in sink_set:
                    cut_edges.add((u, v))
            elif (u in source_set and v in sink_set) or (
                u in sink_set and v in source_set
            ):
                cut_edges.add((u, v))
        return cut_edges

    if s is not None or t is not None:
        _, partition = minimum_cut(G, s, t)
        source_partition, sink_partition = partition
        return cut_edges_for_partition(source_partition, sink_partition)

    nodes = list(G.nodes())
    if len(nodes) < 2:
        return set()

    best_pair = None
    best_cut = None
    if G.is_directed():
        candidate_pairs = ((u, v) for u in nodes for v in nodes if u != v)
    else:
        candidate_pairs = (
            (nodes[left_index], nodes[right_index])
            for left_index in range(len(nodes))
            for right_index in range(left_index + 1, len(nodes))
        )

    for source, sink in candidate_pairs:
        candidate_cut = minimum_edge_cut(G, source, sink)
        candidate_key = (len(candidate_cut), (source, sink))
        if best_cut is None or candidate_key < (len(best_cut), best_pair):
            best_pair = (source, sink)
            best_cut = candidate_cut
            if not best_cut:
                break

    return best_cut if best_cut is not None else set()


def stochastic_graph(G, copy=True, weight="weight"):
    """Return the stochastic graph of *G* (row-normalized adjacency)."""
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")

    graph = _copy_graph_shallow(G) if copy else G
    degree = {node: 0 for node in graph.nodes()}
    if graph.is_multigraph():
        for u, _, _, attrs in graph.edges(keys=True, data=True):
            degree[u] += attrs.get(weight, 1)
    else:
        for u, _, attrs in graph.edges(data=True):
            degree[u] += attrs.get(weight, 1)
    for u, v, attrs in graph.edges(data=True):
        attrs[weight] = 0 if degree[u] == 0 else attrs.get(weight, 1) / degree[u]
    return graph


def _normalize_pagerank_vector(vector, nodes):
    total = math.fsum(vector.values())
    return {node: vector.get(node, 0) / total for node in nodes}


def _pagerank_outgoing_weights(G, node, weight):
    if G.is_multigraph():
        neighbor_weights = {}
        for nbr, keyed_attrs in G.succ[node].items():
            neighbor_weights[nbr] = math.fsum(
                1.0 if weight is None else attrs.get(weight, 1)
                for attrs in keyed_attrs.values()
            )
        return neighbor_weights

    return {
        nbr: 1.0 if weight is None else attrs.get(weight, 1)
        for nbr, attrs in G.succ[node].items()
    }


def pagerank(
    G,
    alpha=0.85,
    personalization=None,
    max_iter=100,
    tol=1.0e-6,
    nstart=None,
    weight="weight",
    dangling=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Return the PageRank of the nodes in graph ``G``."""
    _validate_backend_dispatch_keywords("pagerank", backend, backend_kwargs)

    # br-prwgt: the Rust pagerank silently ignores the weight parameter —
    # ``_raw_pagerank(G, weight="weight")`` always computes the unweighted
    # PageRank. Only route to the Rust fast-path when the caller asked for
    # unweighted (weight is None); any other case (including the default
    # ``weight="weight"``) must go through the pure-Python path below,
    # which honours the attribute correctly.
    if (
        personalization is None
        and nstart is None
        and dangling is None
        and weight is None
    ):
        return _raw_pagerank(
            G,
            alpha=alpha,
            personalization=None,
            max_iter=max_iter,
            tol=tol,
            nstart=None,
            weight=None,
            dangling=None,
        )

    if len(G) == 0:
        return {}

    directed_graph = G.to_directed()
    nodes = list(directed_graph)
    node_count = len(nodes)

    if nstart is None:
        current = dict.fromkeys(nodes, 1.0 / node_count)
    else:
        current = _normalize_pagerank_vector(nstart, nodes)

    if personalization is None:
        personalization_vector = dict.fromkeys(nodes, 1.0 / node_count)
    else:
        personalization_vector = _normalize_pagerank_vector(personalization, nodes)

    if dangling is None:
        dangling_weights = personalization_vector
    else:
        dangling_weights = _normalize_pagerank_vector(dangling, nodes)

    transition_weights = {}
    dangling_nodes = []
    for node in nodes:
        neighbor_weights = _pagerank_outgoing_weights(directed_graph, node, weight)
        total_weight = math.fsum(neighbor_weights.values())
        if total_weight == 0:
            transition_weights[node] = None
            dangling_nodes.append(node)
            continue
        transition_weights[node] = {
            nbr: neighbor_weight / total_weight
            for nbr, neighbor_weight in neighbor_weights.items()
        }

    for _ in range(max_iter):
        previous = current
        current = dict.fromkeys(nodes, 0.0)
        dangling_sum = alpha * math.fsum(previous[node] for node in dangling_nodes)

        for node in nodes:
            neighbor_weights = transition_weights[node]
            if not neighbor_weights:
                continue
            scaled_rank = alpha * previous[node]
            for nbr, neighbor_weight in neighbor_weights.items():
                current[nbr] += scaled_rank * neighbor_weight

        for node in nodes:
            current[node] += (
                dangling_sum * dangling_weights.get(node, 0)
                + (1.0 - alpha) * personalization_vector.get(node, 0)
            )

        error = math.fsum(abs(current[node] - previous[node]) for node in nodes)
        if error < node_count * tol:
            return current

    raise PowerIterationFailedConvergence(max_iter)


def closeness_centrality(
    G,
    u=None,
    distance=None,
    wf_improved=True,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute closeness centrality for nodes.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    u : node, optional
        Return only the value for node u.
    distance : edge attribute key, optional
        Use the specified edge attribute as the edge distance.
    wf_improved : bool, optional (default=True)
        If True, use Wasserman-Faust improved formula for disconnected graphs.

    Returns
    -------
    dict or float
        Dictionary of nodes with closeness centrality as value, or a single
        float if u is specified.
    """
    _validate_backend_dispatch_keywords("closeness_centrality", backend, backend_kwargs)

    # Delegate to NetworkX for unsupported parameters
    if u is not None or distance is not None or not wf_improved:
        return _call_networkx_for_parity(
            "closeness_centrality",
            G,
            u=u,
            distance=distance,
            wf_improved=wf_improved,
        )
    # Use fast Rust implementation for standard case
    return _raw_closeness_centrality(G)


def edge_betweenness_centrality(
    G,
    k=None,
    normalized=True,
    weight=None,
    seed=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute edge betweenness centrality for edges.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    k : int, optional
        Number of nodes to sample for approximation.
    normalized : bool, optional (default=True)
        If True, normalize by 2/(n(n-1)) for undirected or 1/(n(n-1)) for directed.
    weight : edge attribute key, optional
        Use the specified edge attribute as edge weight.
    seed : random state, optional
        Random seed for sampling when k is specified.

    Returns
    -------
    dict
        Dictionary of edges with betweenness centrality as value.
    """
    _validate_backend_dispatch_keywords(
        "edge_betweenness_centrality", backend, backend_kwargs
    )

    # Delegate to NetworkX for unsupported parameters
    if k is not None or not normalized or weight is not None or seed is not None:
        return _call_networkx_for_parity(
            "edge_betweenness_centrality",
            G,
            k=k,
            normalized=normalized,
            weight=weight,
            seed=seed,
        )
    # Use fast Rust implementation for standard case, then re-key the
    # dict in G.edges() iteration order to match nx's contract.
    # br-r37-c1-pi615: the Rust dict had keys in canonical (smaller-
    # first) edge order, but nx returns keys in G.edges() traversal
    # order with the tuple direction nx encountered. Values are
    # identical — only the dict key shape needed alignment.
    raw = _raw_edge_betweenness_centrality(G)
    reordered = {}
    for u, v in G.edges():
        if (u, v) in raw:
            reordered[(u, v)] = raw[(u, v)]
        elif (v, u) in raw:
            reordered[(u, v)] = raw[(v, u)]
    return reordered


def katz_centrality(
    G,
    alpha=0.1,
    beta=1.0,
    max_iter=1000,
    tol=1.0e-6,
    nstart=None,
    normalized=True,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Compute Katz centrality for nodes.

    Parameters
    ----------
    G : graph
        A NetworkX graph.
    alpha : float, optional (default=0.1)
        Attenuation factor.
    beta : float or dict, optional (default=1.0)
        Weight attributed to immediate neighborhood.
    max_iter : int, optional (default=1000)
        Maximum iterations for power iteration.
    tol : float, optional (default=1e-6)
        Convergence tolerance.
    nstart : dict, optional
        Starting value of centrality for each node.
    normalized : bool, optional (default=True)
        If True, normalize values.
    weight : edge attribute key, optional
        Use the specified edge attribute as edge weight.

    Returns
    -------
    dict
        Dictionary of nodes with Katz centrality as value.
    """
    _validate_backend_dispatch_keywords("katz_centrality", backend, backend_kwargs)

    # Delegate to NetworkX when non-default parameters are used
    if (
        alpha != 0.1
        or beta != 1.0
        or max_iter != 1000
        or tol != 1.0e-6
        or nstart is not None
        or not normalized
        or weight is not None
    ):
        return _call_networkx_for_parity(
            "katz_centrality",
            G,
            alpha=alpha,
            beta=beta,
            max_iter=max_iter,
            tol=tol,
            nstart=nstart,
            normalized=normalized,
            weight=weight,
        )
    # Use fast Rust implementation for standard case
    return _raw_katz_centrality(G)


def _make_power_iteration_failed_convergence(max_iter):
    error = PowerIterationFailedConvergence.__new__(PowerIterationFailedConvergence)
    Exception.__init__(
        error,
        error,
        f"power iteration failed to converge within {max_iter} iterations",
    )
    return error


def hits(
    G,
    max_iter=100,
    tol=1.0e-8,
    nstart=None,
    normalized=True,
    *,
    backend=None,
    **backend_kwargs,
):
    """Return HITS hubs and authorities values for nodes.

    br-hitsdelta: on karate_club_graph the values diverge from nx by
    ~1.6%, but experiments show the cause is karate_club_graph's
    edge-insertion-order mismatch (fnx's karate differs from nx's in
    node/edge ordering, affecting the SVD initial basis). On
    order-aligned graphs (explicit add_edge sequences) fnx.hits
    matches nx at machine precision. A full fix requires aligning
    fnx's karate_club_graph output exactly with nx. Queued as
    br-karateorder.
    """
    _validate_backend_dispatch_keywords("hits", backend, backend_kwargs)

    import numpy as np
    import scipy as sp

    if len(G) == 0:
        return {}, {}

    A = adjacency_matrix(G, nodelist=list(G), dtype=float)

    if nstart is not None:
        nstart = np.array(list(nstart.values()))
    if max_iter <= 0:
        raise _make_power_iteration_failed_convergence(max_iter)

    try:
        _, _, vt = sp.sparse.linalg.svds(A, k=1, v0=nstart, maxiter=max_iter, tol=tol)
    except sp.sparse.linalg.ArpackNoConvergence as exc:
        raise _make_power_iteration_failed_convergence(max_iter) from exc

    authorities = vt.flatten().real
    hubs = A @ authorities
    if normalized:
        hubs /= hubs.sum()
        authorities /= authorities.sum()

    return (
        dict(zip(G, map(float, hubs))),
        dict(zip(G, map(float, authorities))),
    )


# ---------------------------------------------------------------------------
# Graph structural algorithms — pure Python over Rust primitives
# ---------------------------------------------------------------------------


def ego_graph(G, n, radius=1, center=True, undirected=False, distance=None):
    """Return the ego graph of node *n* within *radius* hops.

    br-egoedgeord: always compute the node set in Python and copy
    edges in G's original insertion order. The Rust fast-path
    ``_fnx.ego_graph_rust`` re-orients every edge with the ego node
    first (so ``(2, 1), (2, 3)`` instead of ``(1, 2), (2, 3)`` on
    ``fnx.path_graph(5)``), diverging from nx which preserves the
    input graph's edge orientation.
    """
    # br-r37-c1-fauol: track BFS visit order (insertion order in
    # ``seen``) so the resulting ego graph's node order matches nx's
    # BFS-from-source ordering. Previously we collapsed to a set and
    # iterated arbitrary hash order.
    if distance is not None:
        # Weighted ego: include nodes within weighted distance <= radius.
        sp = dict(single_source_dijkstra_path_length(G, n, weight=distance))
        sp = {node: dist for node, dist in sp.items() if dist <= radius}
        ordered_nodes = list(sp.keys())  # already in distance order
        nodes_within = set(ordered_nodes)
    elif undirected and G.is_directed():
        # Treat directed graph as undirected for BFS.
        seen = {n: 0}
        queue = [n]
        while queue:
            next_queue = []
            for u in queue:
                depth = seen[u]
                if depth >= radius:
                    continue
                for v in G.successors(u):
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
                for v in G.predecessors(u):
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
            queue = next_queue
        ordered_nodes = list(seen.keys())
        nodes_within = set(ordered_nodes)
    else:
        # Plain BFS (directed or undirected) honouring radius.
        seen = {n: 0}
        queue = [n]
        while queue:
            next_queue = []
            for u in queue:
                depth = seen[u]
                if depth >= radius:
                    continue
                neighbors = (
                    G.successors(u) if G.is_directed() else G.neighbors(u)
                )
                for v in neighbors:
                    if v not in seen:
                        seen[v] = depth + 1
                        next_queue.append(v)
            queue = next_queue
        ordered_nodes = list(seen.keys())
        nodes_within = set(ordered_nodes)

    # br-r37-c1-fauol: nx.ego_graph uses G.subgraph(sp).copy(), which
    # iterates the result in G's original insertion order (filtered to
    # nodes_within). Match that contract instead of BFS-visit order.
    ordered_nodes = [node for node in G.nodes() if node in nodes_within]

    graph = G.__class__()
    graph.graph.update(dict(G.graph))
    for node in ordered_nodes:
        graph.add_node(node, **dict(G.nodes[node]))
    if G.is_multigraph():
        for u, v, key, data in G.edges(keys=True, data=True):
            if u in nodes_within and v in nodes_within:
                graph.add_edge(u, v, key=key, **data)
    else:
        for u, v, data in G.edges(data=True):
            if u in nodes_within and v in nodes_within:
                graph.add_edge(u, v, **data)
    if not center and n in graph:
        graph.remove_node(n)
    return graph


def core_number(G):
    """Return the core number for each node of ``G``.

    br-coremg: nx.core_number is @not_implemented_for('multigraph',
    'directed_multigraph') and raises NetworkXNotImplemented for any
    multigraph input (and has a self-loop guard). The Rust Rust
    core_number accepted MultiGraph input silently. Gate upfront.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    raw = _raw_core_number(G)
    # br-r37-c1-9fa26: the Rust binding returns the dict with keys
    # sorted; nx iterates in node-insertion order. Reorder so
    # ``for node, core in result.items():`` matches nx's contract.
    return {node: raw[node] for node in G.nodes() if node in raw}


def k_core(G, k=None, core_number=None):
    """Return the k-core of *G* (maximal subgraph with minimum degree >= k).

    br-coremg: same MG-rejection as core_number.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        core_number = _raw_core_number(G)
    if k is None:
        k = max(core_number.values()) if core_number else 0
    nodes = [n for n, c in core_number.items() if c >= k]
    return G.subgraph(nodes)


def k_shell(G, k=None, core_number=None):
    """Return the k-shell of *G* (nodes with core number exactly k)."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        core_number = _raw_core_number(G)
    if k is None:
        k = max(core_number.values()) if core_number else 0
    nodes = [n for n, c in core_number.items() if c == k]
    return G.subgraph(nodes)


def k_crust(G, k=None, core_number=None):
    """Return the k-crust of *G* (nodes with core number <= k)."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        core_number = _raw_core_number(G)
    if k is None:
        k = max(core_number.values()) if core_number else 0
    nodes = [n for n, c in core_number.items() if c <= k]
    return G.subgraph(nodes)


def k_corona(G, k, core_number=None):
    """Return the k-corona of *G* (k-core nodes with exactly k neighbors in k-core)."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if core_number is None:
        core_number = _raw_core_number(G)
    core_nodes = {n for n, c in core_number.items() if c >= k}
    corona_nodes = []
    for n in core_nodes:
        if core_number[n] == k:
            nbrs_in_core = sum(1 for nb in G.neighbors(n) if nb in core_nodes)
            if nbrs_in_core == k:
                corona_nodes.append(n)
    return G.subgraph(corona_nodes)


def line_graph(G, create_using=None):
    """Return the line graph of *G*.

    The line graph L(G) has a node for each edge in G. Two nodes in L(G)
    are adjacent iff the corresponding edges in G share an endpoint.
    """
    graph = _empty_graph_from_create_using(create_using, default=G.__class__)

    if G.is_directed():
        if G.is_multigraph():
            edge_iter = G.edges(keys=True)
        else:
            edge_iter = G.edges()

        for from_node in edge_iter:
            graph.add_node(from_node)
            head = from_node[1]
            if G.is_multigraph():
                for neighbor, keyed_attrs in G[head].items():
                    for key in keyed_attrs:
                        graph.add_edge(from_node, (head, neighbor, key))
            else:
                for neighbor in G[head]:
                    graph.add_edge(from_node, (head, neighbor))
        return graph

    node_index = {node: index for index, node in enumerate(G)}

    def canonical_edge(edge):
        return tuple(sorted(edge[:2], key=node_index.get)) + edge[2:]

    def edge_key(edge):
        return node_index[edge[0]], node_index[edge[1]]

    edges = set()
    for node in G:
        if G.is_multigraph():
            incident = [
                canonical_edge((node, neighbor, key))
                for neighbor, keyed_attrs in G[node].items()
                for key in keyed_attrs
            ]
        else:
            incident = [canonical_edge((node, neighbor)) for neighbor in G[node]]
        if len(incident) == 1:
            graph.add_node(incident[0])
        for index, left in enumerate(incident):
            for right in incident[index + 1 :]:
                edges.add(tuple(sorted((left, right), key=edge_key)))

    graph.add_edges_from(edges)
    return graph


def make_max_clique_graph(G, create_using=None):
    """Return the maximal-clique intersection graph of *G*."""
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    graph = _empty_graph_from_create_using(create_using, default=G.__class__)
    cliques = list(find_cliques(G))
    for index in range(len(cliques)):
        graph.add_node(index)
    for left_index, left in enumerate(cliques):
        left_nodes = set(left)
        for right_index in range(left_index + 1, len(cliques)):
            if left_nodes & set(cliques[right_index]):
                graph.add_edge(left_index, right_index)
    return graph


def power(G, k):
    """Return the k-th power of *G*.

    The k-th power G^k has the same nodes as G. Two nodes u, v are
    adjacent in G^k iff their shortest path distance in G is <= k.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if k <= 0:
        raise ValueError("k must be a positive integer")

    if isinstance(k, numbers.Integral):
        raw_graph = _fnx.power_rust(G, int(k))
        canonical_to_node = {str(node): node for node in G.nodes()}

        graph = G.__class__()
        for raw_node in raw_graph.nodes():
            graph.add_node(canonical_to_node.get(raw_node, raw_node))
        for raw_u, raw_v in raw_graph.edges():
            graph.add_edge(
                canonical_to_node.get(raw_u, raw_u),
                canonical_to_node.get(raw_v, raw_v),
            )
        return graph

    graph = G.__class__()
    graph.add_nodes_from(G)
    for node in G:
        seen = {}
        level = 1
        nextlevel = G[node]
        while nextlevel:
            thislevel = nextlevel
            nextlevel = {}
            for neighbor in thislevel:
                if neighbor == node:
                    continue
                if neighbor not in seen:
                    seen[neighbor] = level
                    nextlevel.update(G[neighbor])
            if k <= level:
                break
            level += 1
        graph.add_edges_from((node, neighbor) for neighbor in seen)
    return graph


def disjoint_union(G, H):
    """Return the disjoint union of *G* and *H*."""
    return disjoint_union_all([G, H])


def compose_all(graphs):
    """Return the composition of all graphs in the iterable."""
    graphs = list(graphs)
    if not graphs:
        raise ValueError("cannot apply compose_all to an empty list")
    _validate_same_graph_family(graphs)
    R = graphs[0].copy()
    for H in graphs[1:]:
        R.graph.update(H.graph)
        for n in H.nodes():
            R.add_node(n, **H.nodes[n])
        if R.is_multigraph():
            for u, v, key, d in H.edges(keys=True, data=True):
                R.add_edges_from([(u, v, key, dict(d))])
        else:
            for u, v, d in H.edges(data=True):
                R.add_edge(u, v, **d)
    return R


def union_all(graphs, rename=()):
    """Return the union of all graphs in the iterable.

    Parameters
    ----------
    graphs : iterable of Graph
        Graphs to union.
    rename : iterable of str or None, optional
        Prefixes to apply to node names of each graph. Shorter iterables
        leave the remaining graphs unchanged. Default ``()`` means no renaming.
    """
    graphs = list(graphs)
    if not graphs:
        raise ValueError("cannot apply union_all to an empty list")
    _validate_same_graph_family(graphs)

    R = graphs[0].__class__()
    rename_iter = itertools.chain(rename, itertools.repeat(None))
    for G, prefix in zip(graphs, rename_iter):
        R.graph.update(G.graph)

        def _rename(n, _prefix=prefix):
            return f"{_prefix}{n}" if _prefix is not None else n

        for n in G.nodes():
            new_n = _rename(n)
            if new_n in R:
                raise NetworkXError(
                    "The node sets of the graphs are not disjoint.\n"
                    "Use `rename` to specify prefixes for the graphs or use\n"
                    "disjoint_union(G1, G2, ..., GN)."
                )
            R.add_node(new_n, **G.nodes[n])
        if R.is_multigraph():
            for u, v, key, d in G.edges(keys=True, data=True):
                R.add_edges_from([(_rename(u), _rename(v), key, dict(d))])
        else:
            for u, v, d in G.edges(data=True):
                R.add_edge(_rename(u), _rename(v), **d)
    return R


# ---------------------------------------------------------------------------
# Spectral graph theory — numpy/scipy based
# ---------------------------------------------------------------------------


def laplacian_matrix(G, nodelist=None, weight="weight"):
    """Return the Laplacian matrix of *G* as a SciPy sparse array.

    ``L = D - A`` where D is the degree matrix and A is the adjacency matrix.

    Parameters
    ----------
    G : Graph
    nodelist : list, optional
    weight : str or None, optional

    Returns
    -------
    scipy.sparse array
    """
    import numpy as np
    import scipy.sparse

    A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight)
    # br-r37-c1-vqodq: mirror nx.laplacian_matrix exactly — use
    # dia_array with the row-sum vector so D inherits A's dtype.
    # The previous diags_array(... dtype=float) call forced float64
    # even on unweighted (int64) adjacency, which diverged from nx
    # and emitted a FutureWarning under recent scipy.
    n = A.shape[0]
    D = scipy.sparse.dia_array((A.sum(axis=1), 0), shape=(n, n)).tocsr()
    return D - A


def normalized_laplacian_matrix(G, nodelist=None, weight="weight"):
    """Return the normalized Laplacian matrix of *G*.

    ``L_norm = D^{-1/2} L D^{-1/2}`` where L is the Laplacian.

    Returns
    -------
    scipy.sparse array
    """
    import numpy as np
    import scipy.sparse

    A = to_scipy_sparse_array(G, nodelist=nodelist, weight=weight)
    n = A.shape[0]
    d = np.asarray(A.sum(axis=1)).flatten()
    # Avoid division by zero for isolated nodes
    d_inv_sqrt = np.zeros_like(d, dtype=float)
    nonzero = d > 0
    d_inv_sqrt[nonzero] = 1.0 / np.sqrt(d[nonzero])
    # Use sparse *arrays* so the result is a csr_array (matching nx).
    D_inv_sqrt = scipy.sparse.diags_array(d_inv_sqrt)
    I = scipy.sparse.eye_array(n)
    return (I - D_inv_sqrt @ A @ D_inv_sqrt).tocsr()


def laplacian_spectrum(G, weight="weight"):
    """Return the eigenvalues of the Laplacian matrix of *G*, sorted.

    Returns
    -------
    numpy.ndarray
    """
    import numpy as np

    L = laplacian_matrix(G, weight=weight)
    return np.sort(np.linalg.eigvalsh(L.toarray()))


def adjacency_spectrum(G, weight="weight"):
    """Return the eigenvalues of the adjacency matrix of *G*, sorted.

    Returns
    -------
    numpy.ndarray
    """
    import numpy as np

    A = to_numpy_array(G, weight=weight)
    return np.sort(np.linalg.eigvalsh(A))


def algebraic_connectivity(G, weight="weight", normalized=False, tol=1e-8, method="tracemin_pcg", seed=None):
    """Return the algebraic connectivity of *G*.

    The algebraic connectivity is the second-smallest eigenvalue of the
    Laplacian matrix (Fiedler value).

    br-algconnkwargs: accept ``tol``, ``method``, ``seed`` kwargs for
    nx signature parity. fnx's bespoke implementation uses a direct
    eigenvalue solver (``np.linalg.eigvalsh`` on the dense
    Laplacian), so these iterative-solver knobs are accepted for
    API parity but don't alter the numerics. A native iterative
    port is future work.

    Parameters
    ----------
    G : Graph
        Must be connected.
    weight : str or None, optional
    normalized : bool, optional
        Use normalized Laplacian if True.
    tol, method, seed : accepted for nx parity; unused here.

    Returns
    -------
    float
    """
    import numpy as np

    del tol, method, seed  # accepted for nx parity but not used

    # br-r37-c1-pb97z: nx raises NetworkXError on null/single-node
    # graphs; fnx silently returned 0.0. Match the documented contract.
    if len(G) < 2:
        raise NetworkXError("graph has less than two nodes.")

    if normalized:
        spectrum = np.sort(
            np.linalg.eigvalsh(normalized_laplacian_matrix(G, weight=weight).toarray())
        )
    else:
        spectrum = laplacian_spectrum(G, weight=weight)
    if len(spectrum) < 2:
        return 0.0
    return float(spectrum[1])


def fiedler_vector(
    G,
    weight="weight",
    normalized=False,
    tol=1e-08,
    method="tracemin_pcg",
    seed=None,
):
    """Return the Fiedler vector of *G*.

    The Fiedler vector is the eigenvector corresponding to the
    algebraic connectivity (second-smallest Laplacian eigenvalue).

    Parameters
    ----------
    G : Graph
    weight : str, optional
    normalized : bool, optional
    tol : float, optional
        Tolerance — accepted for nx parity; unused by the dense solver.
    method : str, optional
        Accepted for nx parity; the dense ``numpy.linalg.eigh`` solver
        ignores it.
    seed : int or Random, optional
        Accepted for nx parity; the dense solver is deterministic so
        ``seed`` has no effect.

    Returns
    -------
    numpy.ndarray
    """
    del tol, method, seed  # accepted for nx signature parity

    import numpy as np

    if normalized:
        L = normalized_laplacian_matrix(G, weight=weight).toarray()
    else:
        L = laplacian_matrix(G, weight=weight).toarray()
    eigenvalues, eigenvectors = np.linalg.eigh(L)
    return eigenvectors[:, 1]


# ---------------------------------------------------------------------------
# Additional matrix representations
# ---------------------------------------------------------------------------


def incidence_matrix(
    G, nodelist=None, edgelist=None, oriented=False, weight=None, *, dtype=None
):
    """Return the incidence matrix of *G* as a SciPy sparse array.

    Parameters
    ----------
    G : Graph
    nodelist : list, optional
    edgelist : list, optional
    oriented : bool, optional
        If True, use +1/-1 for edge endpoints. Default False (uses 1).
    weight : str or None, optional
    dtype : numpy dtype, optional
        The desired data-type for the array. Matches nx's keyword-only
        ``dtype`` argument.

    Returns
    -------
    scipy.sparse array
        Shape (n_nodes, n_edges).
    """
    import numpy as np
    import scipy.sparse

    if nodelist is None:
        nodelist = list(G.nodes())
    if edgelist is None:
        edgelist = list(G.edges())

    node_index = {n: i for i, n in enumerate(nodelist)}
    n_nodes = len(nodelist)
    n_edges = len(edgelist)

    row, col, data = [], [], []
    for j, (u, v) in enumerate(edgelist):
        if u in node_index:
            row.append(node_index[u])
            col.append(j)
            data.append(1 if not oriented else -1)
        if v in node_index:
            row.append(node_index[v])
            col.append(j)
            data.append(1)

    arr_dtype = float if dtype is None else dtype
    return scipy.sparse.coo_array(
        (np.array(data, dtype=arr_dtype), (np.array(row), np.array(col))),
        shape=(n_nodes, n_edges),
    ).tocsc()


