# ---------------------------------------------------------------------------
# Community graph generators
# ---------------------------------------------------------------------------


def caveman_graph(l, k):
    """Return a caveman graph of *l* cliques of size *k*.

    Parameters
    ----------
    l : int
        Number of cliques.
    k : int
        Size of each clique.

    Returns
    -------
    Graph
    """
    G = Graph()
    # Always materialise every node, even when a clique has size 1 and
    # thus contributes no edges. Previously the k=1 case collapsed to an
    # empty graph because the edge loop only added endpoints — nx adds
    # the `l` singletons.
    G.add_nodes_from(range(l * k))
    for i in range(l):
        base = i * k
        for u in range(k):
            for v in range(u + 1, k):
                G.add_edge(base + u, base + v)
    return G


def connected_caveman_graph(l, k):
    """Return a connected caveman graph.

    Like ``caveman_graph`` but with one edge rewired per clique to
    connect adjacent cliques in a ring. br-caveman: matches nx's
    ``G.remove_edge(start, start+1); G.add_edge(start, start-1 mod lk)``
    rewiring — previously only added the bridge without removing the
    within-clique edge, producing 3 extra edges per (l, k).
    """
    if k < 2:
        raise NetworkXError(
            "The size of cliques in a connected caveman graph must be at least 2."
        )

    G = caveman_graph(l, k)
    for start in range(0, l * k, k):
        G.remove_edge(start, start + 1)
        G.add_edge(start, (start - 1) % (l * k))
    return G


def random_tree(n, seed=None):
    """Return a uniformly random labeled tree on *n* nodes via Prüfer sequence.

    Parameters
    ----------
    n : int
        Number of nodes.
    seed : int or None, optional

    Returns
    -------
    Graph
    """
    import random as _random

    if n <= 0:
        return Graph()
    if n == 1:
        G = Graph()
        G.add_node(0)
        return G
    if n == 2:
        G = Graph()
        G.add_edge(0, 1)
        return G

    rng = _random.Random(seed)
    # Generate random Prüfer sequence of length n-2
    prufer = [rng.randint(0, n - 1) for _ in range(n - 2)]

    # Decode Prüfer sequence to tree edges
    degree = [1] * n
    for i in prufer:
        degree[i] += 1

    G = Graph()
    for i in range(n):
        G.add_node(i)

    for i in prufer:
        for j in range(n):
            if degree[j] == 1:
                G.add_edge(i, j)
                degree[i] -= 1
                degree[j] -= 1
                break

    # Connect the last two nodes with degree 1
    last_two = [j for j in range(n) if degree[j] == 1]
    if len(last_two) == 2:
        G.add_edge(last_two[0], last_two[1])

    return G


