# Additional shortest path variants
# ---------------------------------------------------------------------------


def dijkstra_predecessor_and_distance(G, source, cutoff=None, weight="weight"):
    """Return predecessors and distances from Dijkstra's algorithm.

    Parameters
    ----------
    G : Graph
    source : node
    cutoff : float, optional
        Maximum distance threshold.
    weight : str, optional

    Returns
    -------
    (pred, dist) : tuple of dicts

    br-r37-c1-0l76i: nx populates the predecessor dict in
    edge-relaxation insertion order during traversal (so pred[v]
    appears in the dict at the moment a tentative shortest path is
    found, not when the distance is finalized). The previous local
    implementation built ``pred = {node: predecessors[node] for
    node in distances}`` which forced pred-key order to match
    distances-iteration order, drifting from nx (e.g. nx's pred for
    weighted graph [(a,b,1),(b,c,2),(c,d,1),(a,d,5),(b,d,3)] is
    {a:[], b:[a], d:[b,c], c:[b]} — d lands before c because (b,d)
    is relaxed before c is popped). Delegate to nx so pred-dict
    iteration matches nx's algorithm-discovery contract.
    """
    return _call_networkx_for_parity(
        "dijkstra_predecessor_and_distance",
        G, source, cutoff=cutoff, weight=weight,
    )


def multi_source_dijkstra(G, sources, target=None, cutoff=None, weight="weight"):
    """Return shortest path lengths and paths from any source in *sources*."""
    if not sources:
        raise ValueError("sources must not be empty")
    # br-dijkignoreweight: the Rust multi_source_dijkstra inherits the
    # same weight-ignoring bug as single_source_dijkstra. Delegate any
    # weighted input to nx for correctness.
    if (
        callable(weight)
        or _should_delegate_dijkstra_to_networkx(G, weight)
        or _graph_has_nonunit_weight(G, weight)
    ):
        return _call_networkx_for_parity(
            "multi_source_dijkstra",
            G,
            sources,
            target=target,
            cutoff=cutoff,
            weight=weight,
        )
    dists, paths = _raw_multi_source_dijkstra(G, sources, weight=weight)
    if cutoff is not None:
        dists = {node: distance for node, distance in dists.items() if distance <= cutoff}
        paths = {node: path for node, path in paths.items() if node in dists}
    if target is not None:
        if target not in dists:
            raise NetworkXNoPath(f"No path to {target}.")
        return dists[target], paths[target]
    return dists, paths


def multi_source_dijkstra_path(G, sources, cutoff=None, weight="weight"):
    """Return shortest paths from any source to all reachable nodes.

    Parameters
    ----------
    G : Graph
    sources : iterable of nodes
    weight : str, optional

    Returns
    -------
    dict
        ``{target: path}`` where path starts from the nearest source.
    """
    _, paths = multi_source_dijkstra(G, sources, cutoff=cutoff, weight=weight)
    return paths


def multi_source_dijkstra_path_length(G, sources, cutoff=None, weight="weight"):
    """Return shortest path lengths from any source to all reachable nodes.

    Parameters
    ----------
    G : Graph
    sources : iterable of nodes
    weight : str, optional

    Returns
    -------
    dict
        ``{target: length}``
    """
    dists, _ = multi_source_dijkstra(G, sources, cutoff=cutoff, weight=weight)
    return dists


def single_source_all_shortest_paths(G, source, weight=None, method="dijkstra"):
    """Yield all shortest paths from source to every reachable target.

    Parameters
    ----------
    G : Graph
    source : node
    weight : str or callable or None, optional
    method : str, optional

    Yields
    ------
    (target, paths)
        ``paths`` is the list of all shortest paths from source to target.
    """
    yield from _call_networkx_for_parity(
        "single_source_all_shortest_paths",
        G,
        source,
        weight=weight,
        method=method,
    )


def all_pairs_all_shortest_paths(G, weight=None, method="dijkstra"):
    """Yield all shortest paths between all pairs.

    Parameters
    ----------
    G : Graph
    weight : str or None, optional
    method : str, optional

    Yields
    ------
    (source, paths_dict)
        Where paths_dict maps target -> list of shortest paths.
    """
    if weight is not None:
        yield from _call_networkx_for_parity(
            "all_pairs_all_shortest_paths", G, weight=weight, method=method
        )
        return
    result = _fnx.all_pairs_all_shortest_paths_rust(G)
    for source in G.nodes():
        paths_dict = {source: [[source]]}
        paths_dict.update(result.get(source, {}))
        yield (source, paths_dict)


def reconstruct_path(source, target, predecessors):
    """Reconstruct a path from *source* to *target*.

    Matches networkx's public signature
    ``reconstruct_path(source, target, predecessors)`` where
    ``predecessors`` is either the nested
    ``floyd_warshall_predecessor_and_distance`` dict
    (``predecessors[src][tgt] -> predecessor``) or a flat dict of
    ``{node: predecessor_list}`` (dijkstra-style output).
    """
    # Float-warshall style: predecessors is {src: {tgt: pred}}
    if (
        isinstance(predecessors, dict)
        and source in predecessors
        and isinstance(predecessors.get(source), dict)
    ):
        table = predecessors[source]
        if source == target:
            return []
        if target not in table:
            return []
        path = [target]
        current = target
        while current != source:
            current = table[current]
            path.append(current)
        path.reverse()
        return path

    # Dijkstra-style: predecessors is {node: [pred1, ...]}
    if source == target:
        return [source]
    path = [target]
    current = target
    while current != source:
        preds = predecessors.get(current, [])
        if not preds:
            return []
        current = preds[0] if isinstance(preds, (list, tuple)) else preds
        path.append(current)
    path.reverse()
    return path


def generate_random_paths(
    G,
    sample_size,
    path_length=5,
    index_map=None,
    weight="weight",
    seed=None,
    *,
    source=None,
):
    """Generate random paths by weighted random walks.

    Parameters
    ----------
    G : Graph
    sample_size : int
        Number of paths to generate.
    path_length : int, optional
        Maximum length of each path. Default 5.
    weight : str or None, optional
        Edge attribute used as the transition weight. Default
        ``"weight"`` to match networkx (br-r37-c1-rygbm follow-up:
        the previous fnx default of ``None`` silently dropped edge
        weights and produced a uniform random walk where nx produces
        a weighted one). Pass ``weight=None`` for the legacy uniform
        behaviour.
    seed : int or None, optional
    source : node or None, optional (keyword-only)
        Fixed starting node for every sampled walk. When ``None``
        (default), each walk starts from a uniformly random node.

    Yields
    ------
    list
        Each yield is a random walk path.
    """
    import random as _random

    rng = _random.Random(seed)
    nodes = list(G.nodes())
    if not nodes:
        return
    if source is not None and source not in G:
        raise NodeNotFound(f"Source {source} is not in G")

    is_multi = G.is_multigraph()

    def _weighted_choice(current):
        # Mirror nx.generate_random_paths' transition step: build a
        # weight vector over the current node's neighbours and sample
        # by that distribution.
        if is_multi:
            nbrs = []
            weights = []
            for nbr, keydict in G[current].items():
                # Multigraph: total weight across parallel edges.
                w = 0.0
                for _, attrs in keydict.items():
                    if weight is None:
                        w += 1.0
                    else:
                        w += float(attrs.get(weight, 1.0))
                if w > 0:
                    nbrs.append(nbr)
                    weights.append(w)
        else:
            nbrs = []
            weights = []
            for nbr, attrs in G[current].items():
                w = 1.0 if weight is None else float(attrs.get(weight, 1.0))
                if w > 0:
                    nbrs.append(nbr)
                    weights.append(w)
        if not nbrs:
            return None
        if weight is None:
            return rng.choice(nbrs)
        return rng.choices(nbrs, weights=weights, k=1)[0]

    for _ in range(sample_size):
        start = source if source is not None else rng.choice(nodes)
        path = [start]
        current = start
        for _ in range(path_length):
            nxt = _weighted_choice(current)
            if nxt is None:
                break
            path.append(nxt)
            current = nxt
        yield path


def johnson(G, weight="weight"):
    """All-pairs shortest paths using Johnson's algorithm.

    Johnson's algorithm handles graphs with negative edges (but no
    negative cycles) by reweighting edges via Bellman-Ford, then
    running Dijkstra from each node.

    Parameters
    ----------
    G : Graph or DiGraph
    weight : str, optional

    Returns
    -------
    dict of dicts
        ``result[u][v]`` is the shortest path from u to v.

    br-r37-c1-9l73c: the local
    ``dict(all_pairs_bellman_ford_path(...))`` short-circuit
    produced inner-dict keys in BF-tree-discovery order, which
    differed from nx's johnson algorithm-specific Dijkstra-from-
    node iteration order (e.g. inner[a] keys ['a','b','d','c'] vs
    nx ['a','b','c','d']). Delegate to nx so the inner-dict
    iteration order matches its contract exactly.
    """
    return _call_networkx_for_parity("johnson", G, weight=weight)


# ---------------------------------------------------------------------------
# Spectral & Matrix (numpy/scipy) — br-ulw
# ---------------------------------------------------------------------------


def bethe_hessian_matrix(G, r=None, nodelist=None):
    """Return the Bethe Hessian matrix: H(r) = (r^2-1)*I - r*A + D.

    br-bethedef: nx's default regularizer is
    ``r = sum(d_i^2)/sum(d_i) - 1`` (Le & Levina 2015). fnx used
    ``max(sqrt(mean(degree)), 1.0)`` which produced a different matrix
    whenever the default was requested — on path(5) fnx's r was
    ~1.265 (giving diag entry 2.6) vs nx's r=0.75 (giving diag 1.5625).
    Match nx's formula exactly.
    """
    import numpy as np
    import scipy.sparse

    # nx's bethe_hessian_matrix mixes weighted and unweighted quantities:
    # A and D come from the weighted adjacency (weight='weight'), but the
    # default regularizer r is computed from unweighted node degrees via
    # nx.degree(G). Match that mix exactly.
    if nodelist is None:
        nodelist = list(G.nodes())
    A = to_scipy_sparse_array(G, nodelist=nodelist, format="csr")
    n = A.shape[0]
    d = np.asarray(A.sum(axis=1)).flatten()
    # Use sparse *arrays* throughout (not legacy matrices) so the final
    # product preserves nx's csr_array return type.
    D = scipy.sparse.diags_array(d, dtype=float)
    if r is None:
        unweighted_degs = [G.degree(v) for v in nodelist]
        deg_sum = sum(unweighted_degs)
        if deg_sum > 0:
            r = sum(x * x for x in unweighted_degs) / deg_sum - 1
        else:
            r = 1.0
    I = scipy.sparse.eye_array(n)
    return ((r**2 - 1) * I - r * A + D).tocsr()


def bethe_hessian_spectrum(G, r=None):
    """Return sorted eigenvalues of the Bethe Hessian matrix."""
    import numpy as np

    H = bethe_hessian_matrix(G, r=r)
    return np.sort(np.linalg.eigvalsh(H.toarray()))


def google_matrix(
    G,
    alpha=0.85,
    personalization=None,
    nodelist=None,
    weight="weight",
    dangling=None,
):
    """Return the Google PageRank matrix: alpha*S + (1-alpha)*v*e^T.

    br-matsig: adds the ``dangling`` parameter nx exposes (weights used
    to redistribute mass from dangling nodes instead of the uniform
    teleport). Previously fnx rejected ``dangling=`` with a TypeError.
    """
    import numpy as np

    if nodelist is None:
        nodelist = list(G.nodes())
    n = len(nodelist)
    if n == 0:
        return np.array([[]])
    A = to_numpy_array(G, nodelist=nodelist, weight=weight)
    row_sums = A.sum(axis=1)

    if dangling is None:
        dangling_row = None
    else:
        dangling_row = np.array(
            [dangling.get(node, 0) for node in nodelist], dtype=float
        )
        total = dangling_row.sum()
        if total > 0:
            dangling_row = dangling_row / total

    S = np.zeros_like(A)
    for i in range(n):
        if row_sums[i] > 0:
            S[i, :] = A[i, :] / row_sums[i]
        elif dangling_row is not None:
            S[i, :] = dangling_row
        else:
            S[i, :] = 1.0 / n
    if personalization is None:
        v = np.ones(n) / n
    else:
        v = np.array([personalization.get(node, 0) for node in nodelist], dtype=float)
        s = v.sum()
        v = v / s if s > 0 else np.ones(n) / n
    return alpha * S + (1 - alpha) * np.outer(np.ones(n), v)


def normalized_laplacian_spectrum(G, weight="weight"):
    """Return sorted eigenvalues of the normalized Laplacian."""
    import numpy as np

    NL = normalized_laplacian_matrix(G, weight=weight)
    return np.sort(np.linalg.eigvalsh(NL.toarray()))


def directed_laplacian_matrix(
    G, nodelist=None, weight="weight", walk_type=None, alpha=0.95
):
    """Return the directed Laplacian matrix of G.

    br-dirlap: delegates to nx for numerical correctness and signature
    parity. The previous bespoke implementation (a) was missing the
    ``walk_type`` kwarg entirely and (b) always used the pagerank walk
    matrix regardless of the graph's strong connectivity, producing
    outputs that diverged from nx by ~16% on simple strongly-connected
    3-cycles. nx's implementation dispatches on ``walk_type`` —
    ``random`` / ``lazy`` / ``pagerank`` — with the default chosen from
    graph structure (random for strongly connected, pagerank otherwise).
    Reproducing this table in pure Python without drift is brittle;
    delegation is the right default.
    """
    return _call_networkx_for_parity(
        "directed_laplacian_matrix",
        G,
        nodelist=nodelist,
        weight=weight,
        walk_type=walk_type,
        alpha=alpha,
    )


def directed_combinatorial_laplacian_matrix(
    G, nodelist=None, weight="weight", walk_type=None, alpha=0.95
):
    """Return the directed combinatorial Laplacian: Phi*(I - P).

    br-dirlap: see ``directed_laplacian_matrix`` — same delegation
    rationale (missing walk_type kwarg + wrong stationary distribution
    on strongly-connected graphs).
    """
    return _call_networkx_for_parity(
        "directed_combinatorial_laplacian_matrix",
        G,
        nodelist=nodelist,
        weight=weight,
        walk_type=walk_type,
        alpha=alpha,
    )


def attr_matrix(
    G,
    edge_attr=None,
    node_attr=None,
    normalized=False,
    rc_order=None,
    dtype=None,
    order=None,
):
    """Construct a matrix from edge attributes.

    When *node_attr* is given, nodes are grouped by attribute value and the
    matrix has size ``len(unique_attr_values)`` with entries summed over
    nodes sharing the same attribute.  *rc_order* then specifies the
    ordering of attribute values, not nodes.
    """
    import numpy as np

    if node_attr is not None:
        # Group nodes by their node_attr value
        node_attrs = {n: G.nodes[n].get(node_attr, n) for n in G.nodes()}
        if rc_order is not None:
            labels = list(rc_order)
        else:
            labels = sorted(set(node_attrs.values()), key=str)
        label_idx = {lab: i for i, lab in enumerate(labels)}
        n = len(labels)
        M = np.zeros((n, n), dtype=dtype or np.float64, order=order or "C")
        for u, v, data in G.edges(data=True):
            lu, lv = node_attrs.get(u), node_attrs.get(v)
            if lu in label_idx and lv in label_idx:
                val = (
                    data.get(edge_attr, 1)
                    if edge_attr and isinstance(data, dict)
                    else 1
                )
                M[label_idx[lu], label_idx[lv]] += val
                if not G.is_directed():
                    M[label_idx[lv], label_idx[lu]] += val
        if normalized:
            rs = M.sum(axis=1)
            rs[rs == 0] = 1
            M = M / rs[:, np.newaxis]
        if rc_order is None:
            return M, labels
        return M
    else:
        nodelist = list(rc_order) if rc_order is not None else list(G.nodes())
        n = len(nodelist)
        idx = {node: i for i, node in enumerate(nodelist)}
        M = np.zeros((n, n), dtype=dtype or np.float64, order=order or "C")
        for u, v, data in G.edges(data=True):
            if u in idx and v in idx:
                val = (
                    data.get(edge_attr, 1)
                    if edge_attr and isinstance(data, dict)
                    else 1
                )
                M[idx[u], idx[v]] = val
                if not G.is_directed():
                    M[idx[v], idx[u]] = val
        if normalized:
            rs = M.sum(axis=1)
            rs[rs == 0] = 1
            M = M / rs[:, np.newaxis]
        if rc_order is None:
            return M, nodelist
        return M


# ---------------------------------------------------------------------------
# Min-cost flow algorithms (br-hp3)
# ---------------------------------------------------------------------------


def cost_of_flow(G, flowDict, weight="weight"):
    """Compute the cost of a given flow.

    Parameters
    ----------
    G : DiGraph
        Network with edge attribute *weight* as cost per unit flow.
    flowDict : dict of dicts
        ``flowDict[u][v]`` is the flow on edge (u, v).
    weight : str, optional
        Edge attribute name for cost. Default ``'weight'``.

    Returns
    -------
    float
        Total cost of the flow.
    """
    # br-costint: nx.cost_of_flow uses sum(G[u][v][weight]*flow[u][v])
    # which preserves int when all factors are int. fnx initialized
    # total=0.0 and cast weights via float(), always widening the
    # result. Keep nx's int-preservation by initializing total=0 and
    # using the raw weight value (with a 0 default) without float cast.
    total = 0
    for u in flowDict:
        for v, flow in flowDict[u].items():
            if flow > 0:
                data = G.get_edge_data(u, v)
                if isinstance(data, dict):
                    cost = data.get(weight, 0)
                else:
                    cost = 0
                total = total + flow * cost
    return total


def _mcf_inputs_all_integral(G, demand, capacity, weight):
    """br-mcfint: nx.min_cost_flow and nx.network_simplex preserve int
    flow values when every demand, capacity, and weight on the graph
    is an integer. fnx's Python implementation widens via ``float(...)``
    casts, so the flow dict comes back with float values. Detect the
    all-int-input case so callers can coerce the flow dict back to
    int for exact nx parity.
    """
    import numbers as _numbers
    for node in G.nodes():
        attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if isinstance(attrs, dict):
            d = attrs.get(demand, 0)
            if not isinstance(d, _numbers.Integral) or isinstance(d, bool):
                return False
    for _, _, attrs in G.edges(data=True):
        if not isinstance(attrs, dict):
            continue
        cap = attrs.get(capacity, 1)
        if not isinstance(cap, _numbers.Integral) or isinstance(cap, bool):
            # float('inf') is infinity; nx still produces int in that case
            # when capacities are effectively unbounded integrals elsewhere.
            # Treat +inf as non-integer only if it's not matched by other ints.
            return False
        w = attrs.get(weight, 0)
        if not isinstance(w, _numbers.Integral) or isinstance(w, bool):
            return False
    return True


def _coerce_flow_dict_to_int(flow_dict):
    """Coerce a dict-of-dicts flow to int values (used when _mcf_inputs_all_integral)."""
    out = {}
    for u, inner in flow_dict.items():
        out[u] = {v: (int(f) if isinstance(f, float) and f.is_integer() else f)
                  for v, f in inner.items()}
    return out


def min_cost_flow(G, demand="demand", capacity="capacity", weight="weight"):
    """Find minimum cost flow satisfying node demands.

    Uses the successive shortest paths algorithm with Bellman-Ford.

    Each node may have a ``demand`` attribute:
    - Negative demand = supply (source, has excess flow to send)
    - Positive demand = demand (sink, needs flow)
    - Zero or missing = transshipment node

    Parameters
    ----------
    G : DiGraph
    demand : str, optional
        Node attribute for supply/demand. Default ``'demand'``.
    capacity : str, optional
        Edge attribute for capacity. Default ``'capacity'``.
    weight : str, optional
        Edge attribute for cost per unit flow. Default ``'weight'``.

    Returns
    -------
    dict of dicts
        ``flowDict[u][v]`` is the optimal flow on edge (u, v).

    Raises
    ------
    NetworkXUnfeasible
        If no feasible flow exists.
    """
    if not G.is_directed():
        raise NetworkXError("min_cost_flow requires a directed graph")

    nodes = list(G.nodes())
    n = len(nodes)
    if n == 0:
        return {}

    # Extract demands
    node_demand = {}
    for node in nodes:
        attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if isinstance(attrs, dict):
            node_demand[node] = float(attrs.get(demand, 0))
        else:
            node_demand[node] = 0.0

    # Check feasibility: sum of demands must be zero
    total_demand = sum(node_demand.values())
    if abs(total_demand) > 1e-10:
        raise NetworkXUnfeasible(
            f"Total node demand is {total_demand}, must be zero for feasible flow"
        )

    # Initialize flow dict
    flow = {u: {} for u in nodes}
    for u, v in G.edges():
        flow.setdefault(u, {})[v] = 0

    # Build residual graph and run successive shortest paths
    # NetworkX convention: negative demand = supply, positive = demand
    sources = [n for n in nodes if node_demand[n] < 0]
    sinks = [n for n in nodes if node_demand[n] > 0]
    remaining_supply = {n: -node_demand[n] for n in sources}
    remaining_demand = {n: node_demand[n] for n in sinks}

    # Successive shortest paths: augment along shortest cost path
    for _ in range(n * n):  # upper bound on iterations
        # Find shortest path from any source with remaining supply
        # to any sink with remaining demand using Bellman-Ford on residual
        best_path = None
        best_cost = float("inf")
        best_source = None
        best_sink = None

        for source in sources:
            if remaining_supply.get(source, 0) <= 1e-10:
                continue

            # BFS/Bellman-Ford on residual graph
            dist = {source: 0.0}
            pred = {source: None}
            # Relaxation
            for _ in range(n):
                updated = False
                for u in nodes:
                    if u not in dist:
                        continue
                    # Forward edges
                    if hasattr(G, "successors"):
                        succs = list(G.successors(u))
                    else:
                        succs = list(G.neighbors(u))
                    for v in succs:
                        data = G.get_edge_data(u, v)
                        if not isinstance(data, dict):
                            continue
                        cap = float(data.get(capacity, float("inf")))
                        current_flow = flow.get(u, {}).get(v, 0)
                        residual_cap = cap - current_flow
                        if residual_cap > 1e-10:
                            edge_cost = float(data.get(weight, 0))
                            new_dist = dist[u] + edge_cost
                            if v not in dist or new_dist < dist[v] - 1e-10:
                                dist[v] = new_dist
                                pred[v] = (u, "forward")
                                updated = True
                    # Backward edges (reverse flow)
                    if hasattr(G, "predecessors"):
                        preds_list = list(G.predecessors(u))
                    else:
                        preds_list = []
                    for v in preds_list:
                        current_flow = flow.get(v, {}).get(u, 0)
                        if current_flow > 1e-10:
                            data = G.get_edge_data(v, u)
                            edge_cost = (
                                -float(data.get(weight, 0))
                                if isinstance(data, dict)
                                else 0.0
                            )
                            new_dist = dist[u] + edge_cost
                            if v not in dist or new_dist < dist[v] - 1e-10:
                                dist[v] = new_dist
                                pred[v] = (u, "backward")
                                updated = True
                if not updated:
                    break

            # Check reachable sinks
            for sink in sinks:
                if sink in dist and remaining_demand.get(sink, 0) > 1e-10:
                    if dist[sink] < best_cost:
                        best_cost = dist[sink]
                        best_path = pred
                        best_source = source
                        best_sink = sink

        if best_path is None:
            break

        # Find bottleneck along the path
        path_nodes = []
        current = best_sink
        while current is not None:
            path_nodes.append(current)
            p = best_path.get(current)
            if p is None:
                break
            current = p[0] if p else None
        path_nodes.reverse()

        bottleneck = min(remaining_supply[best_source], remaining_demand[best_sink])
        # Also check edge capacities along path
        for i in range(len(path_nodes) - 1):
            u, v = path_nodes[i], path_nodes[i + 1]
            info = best_path.get(v)
            if info and info[1] == "forward":
                data = G.get_edge_data(u, v)
                cap = (
                    float(data.get(capacity, float("inf")))
                    if isinstance(data, dict)
                    else float("inf")
                )
                residual = cap - flow.get(u, {}).get(v, 0)
                bottleneck = min(bottleneck, residual)
            elif info and info[1] == "backward":
                bottleneck = min(bottleneck, flow.get(v, {}).get(u, 0))

        if bottleneck <= 1e-10:
            break

        # Augment flow along path
        for i in range(len(path_nodes) - 1):
            u, v = path_nodes[i], path_nodes[i + 1]
            info = best_path.get(v)
            if info and info[1] == "forward":
                flow.setdefault(u, {})[v] = flow.get(u, {}).get(v, 0) + bottleneck
            elif info and info[1] == "backward":
                flow.setdefault(v, {})[u] = flow.get(v, {}).get(u, 0) - bottleneck

        remaining_supply[best_source] -= bottleneck
        remaining_demand[best_sink] -= bottleneck

    # Check if all demands are satisfied
    for source in sources:
        if remaining_supply.get(source, 0) > 1e-10:
            raise NetworkXUnfeasible("no flow satisfies all node demands")
    for sink in sinks:
        if remaining_demand.get(sink, 0) > 1e-10:
            raise NetworkXUnfeasible("no flow satisfies all node demands")

    # br-mcfint: preserve int flow values when every input is int
    # (nx contract).
    if _mcf_inputs_all_integral(G, demand, capacity, weight):
        flow = _coerce_flow_dict_to_int(flow)
    return flow


def min_cost_flow_cost(G, demand="demand", capacity="capacity", weight="weight"):
    """Return the cost of the minimum cost flow.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional

    Returns
    -------
    float
    """
    flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    return cost_of_flow(G, flow, weight=weight)


def max_flow_min_cost(G, s, t, capacity="capacity", weight="weight"):
    """Find a maximum flow of minimum cost from *s* to *t*.

    First finds maximum flow value, then finds the min-cost flow
    achieving that value.

    Parameters
    ----------
    G : DiGraph
    s, t : node
        Source and sink.
    capacity, weight : str, optional

    Returns
    -------
    dict of dicts
        Flow dictionary.

    br-mfmcsign: by nx convention, a negative demand means the node
    *supplies* that much flow. A source thus has ``demand=-maxFlow``
    and a sink has ``demand=+maxFlow``. The previous implementation
    used the reversed signs (``{s: max_val, t: -max_val}``), which
    inverted supply/demand — the solver then tried to push flow from
    t to s and raised NetworkXUnfeasible on every valid input.
    """
    # Get max flow value
    max_val = maximum_flow_value(G, s, t, capacity=capacity)

    # Set up demands per nx convention: source supplies (negative),
    # sink consumes (positive).
    H = G.copy()
    set_node_attributes(H, {s: -max_val, t: max_val}, name="demand")
    # Set demand=0 for all other nodes that don't already have one.
    for n in H.nodes():
        if n != s and n != t:
            attrs = H.nodes[n] if hasattr(H.nodes, "__getitem__") else {}
            if isinstance(attrs, dict) and "demand" not in attrs:
                attrs["demand"] = 0

    return min_cost_flow(H, capacity=capacity, weight=weight)


def capacity_scaling(
    G,
    demand="demand",
    capacity="capacity",
    weight="weight",
    heap=_BINARY_HEAP_DEFAULT,
):
    """Find minimum cost flow using capacity scaling.

    This is an alias for ``min_cost_flow`` — the successive shortest
    paths implementation provides the same optimality guarantees.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional
    heap : class, optional
        Heap class. Default ``networkx.utils.heaps.BinaryHeap`` so the
        introspectable signature matches nx exactly. The fnx
        implementation manages its own heap; the kwarg is accepted
        for API drop-in compatibility.

    Returns
    -------
    tuple
        ``(flowCost, flowDict)`` matching NetworkX's return signature.
    """
    flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    cost = cost_of_flow(G, flow, weight=weight)
    return cost, flow


def _validate_network_simplex_inputs(G, demand, capacity, weight):
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")

    if len(G) == 0:
        raise NetworkXError("graph has no nodes")

    total_demand = 0.0
    for node in G:
        node_attrs = G.nodes[node] if hasattr(G.nodes, "__getitem__") else {}
        if not isinstance(node_attrs, dict):
            continue
        node_demand = float(node_attrs.get(demand, 0))
        if math.isinf(node_demand):
            raise NetworkXError(f"node {node!r} has infinite demand")
        total_demand += node_demand

    for u, v, edge_attrs in G.edges(data=True):
        if not isinstance(edge_attrs, dict):
            continue
        edge_weight = float(edge_attrs.get(weight, 0))
        if math.isinf(edge_weight):
            raise NetworkXError(f"edge {(u, v)!r} has infinite weight")

        edge_capacity = float(edge_attrs.get(capacity, float("inf")))
        if edge_capacity < 0:
            raise NetworkXUnfeasible(f"edge {(u, v)!r} has negative capacity")

    if abs(total_demand) > 1e-10:
        raise NetworkXUnfeasible("total node demand is not zero")


def network_simplex(G, demand="demand", capacity="capacity", weight="weight"):
    """Find minimum cost flow using the network simplex algorithm.

    Returns both the cost and the flow dictionary.

    Parameters
    ----------
    G : DiGraph
    demand, capacity, weight : str, optional

    Returns
    -------
    (cost, flowDict) : tuple
    """
    _validate_network_simplex_inputs(G, demand, capacity, weight)
    flow = min_cost_flow(G, demand=demand, capacity=capacity, weight=weight)
    cost = cost_of_flow(G, flow, weight=weight)
    return (cost, flow)


def flow_hierarchy(G, weight=None):
    """Return the flow hierarchy of a directed graph.

    The flow hierarchy is the fraction of edges not in a cycle.

    Parameters
    ----------
    G : DiGraph
    weight : str or None, optional

    Returns
    -------
    float
        Value in [0, 1]. 1 means no edges are in cycles (DAG).
    """
    if not G.is_directed():
        # br-r37-c1-4elbw: nx raises NetworkXError with the exact text
        # "G must be a digraph in flow_hierarchy". The Rust binding
        # raised "flow_hierarchy requires a DiGraph", which broke
        # drop-in code matching nx's wording.
        raise NetworkXError("G must be a digraph in flow_hierarchy")
    return _fnx.flow_hierarchy_rust(G)


# ---------------------------------------------------------------------------
# Triad analysis (br-a59)
# ---------------------------------------------------------------------------

# 16 triad types in MAN notation
_TRIAD_TYPES = [
    "003",
    "012",
    "102",
    "021D",
    "021U",
    "021C",
    "111D",
    "111U",
    "030T",
    "030C",
    "201",
    "120D",
    "120U",
    "120C",
    "210",
    "300",
]


def triadic_census(G, nodelist=None):
    """Count the frequency of each of the 16 triad types.

    Parameters
    ----------
    G : DiGraph
    nodelist : optional list of nodes
        Restrict the triad count to triads containing at least one
        node from ``nodelist`` (nx parity — br-triadnode). When
        ``nodelist`` is None, counts all triads in the graph.

    Returns
    -------
    dict
        ``{triad_type: count}`` for all 16 types.
    """
    if not G.is_directed():
        raise NetworkXError("triadic_census requires a directed graph")
    if nodelist is None:
        raw = _fnx.triadic_census_rust(G)
        # br-r37-c1-v9m7b: nx returns the 16 triad types in canonical
        # MAN-notation order (matching the _TRIAD_TYPES constant); the
        # Rust binding yields them in arbitrary internal order. Reorder.
        return {t: raw.get(t, 0) for t in _TRIAD_TYPES}
    # br-triadnode: delegate the nodelist-filtered form to nx; the Rust
    # native doesn't yet accept a nodelist argument.
    return _call_networkx_for_parity("triadic_census", G, nodelist=nodelist)


def all_triads(G):
    """Generate all triads (3-node subgraphs) of a directed graph.

    Parameters
    ----------
    G : DiGraph

    Yields
    ------
    DiGraph
        Each yielded graph is a 3-node subgraph.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")

    nodes = list(G.nodes())
    n = len(nodes)

    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                yield G.subgraph([nodes[i], nodes[j], nodes[k]]).copy()


def triad_type(G):
    """Return the triad type of a 3-node directed graph.

    Parameters
    ----------
    G : DiGraph
        Must have exactly 3 nodes.

    Returns
    -------
    str
        One of the 16 MAN triad type codes.
    """
    nodes = list(G.nodes())
    if len(nodes) != 3:
        raise NetworkXError("triad_type requires exactly 3 nodes")
    return _fnx.triad_type_rust(G, nodes[0], nodes[1], nodes[2])


def is_triad(G):
    """Return True if *G* is a valid triad (3-node directed graph)."""
    return (
        G.is_directed()
        and G.number_of_nodes() == 3
        and not any((node, node) in G.edges() for node in G.nodes())
    )


def triads_by_type(G):
    """Group all triads of *G* by their type.

    Returns
    -------
    dict
        ``{triad_type: [list of triad subgraphs]}``

    br-triadsempty: nx.triads_by_type only includes keys for types
    that actually appear in the graph. fnx pre-populated all 16 triad
    types with empty lists, so iterating items / checking membership
    would diverge (fnx yields 16 entries; nx yields only non-empty
    counts). Drop empty buckets to match nx's sparse output.
    """
    result = {t: [] for t in _TRIAD_TYPES}
    for triad in all_triads(G):
        ttype = triad_type(triad)
        if ttype in result:
            result[ttype].append(triad)
    return {t: triads for t, triads in result.items() if triads}


# ---------------------------------------------------------------------------
# Edge swapping & rewiring (br-eo5)
# ---------------------------------------------------------------------------


def double_edge_swap(G, nswap=1, max_tries=100, seed=None):
    """Swap two edges while preserving the degree sequence.

    For each swap attempt, select edges (u,v) and (x,y) and replace
    with (u,x) and (v,y) if no self-loops or parallel edges result.

    Parameters
    ----------
    G : Graph
        Modified in place.
    nswap : int, optional
        Number of swaps to perform.
    max_tries : int, optional
        Maximum attempts per swap.
    seed : int or None, optional

    Returns
    -------
    G : Graph
        The modified graph.
    """
    import random as _random

    rng = _random.Random(seed)

    if G.number_of_edges() < 2:
        return G

    edges = list(G.edges())
    swaps_done = 0
    tries = 0

    while swaps_done < nswap and tries < nswap * max_tries:
        tries += 1
        e1 = edges[rng.randint(0, len(edges) - 1)]
        e2 = edges[rng.randint(0, len(edges) - 1)]
        u, v = e1
        x, y = e2
        if len({u, v, x, y}) < 4:
            continue
        # Try swap: (u,v), (x,y) → (u,x), (v,y)
        if not G.has_edge(u, x) and not G.has_edge(v, y) and u != x and v != y:
            G.remove_edge(u, v)
            G.remove_edge(x, y)
            G.add_edge(u, x)
            G.add_edge(v, y)
            edges = list(G.edges())
            swaps_done += 1

    return G


def directed_edge_swap(G, *, nswap=1, max_tries=100, seed=None):
    """Swap two directed edges while preserving in/out degree sequences.

    Select edges (u→v) and (x→y), replace with (u→y) and (x→v).

    Parameters
    ----------
    G : DiGraph
        Modified in place.
    nswap : int, optional
    max_tries : int, optional
    seed : int or None, optional

    Returns
    -------
    G : DiGraph
    """
    import random as _random

    rng = _random.Random(seed)

    if not G.is_directed():
        raise NetworkXError("directed_edge_swap requires a directed graph")
    if G.number_of_edges() < 2:
        return G

    edges = list(G.edges())
    swaps_done = 0
    tries = 0

    while swaps_done < nswap and tries < nswap * max_tries:
        tries += 1
        e1 = edges[rng.randint(0, len(edges) - 1)]
        e2 = edges[rng.randint(0, len(edges) - 1)]
        u, v = e1
        x, y = e2
        if u == x or v == y:
            continue
        if u == y or x == v:
            continue
        # Swap: (u→v), (x→y) → (u→y), (x→v)
        if not G.has_edge(u, y) and not G.has_edge(x, v):
            G.remove_edge(u, v)
            G.remove_edge(x, y)
            G.add_edge(u, y)
            G.add_edge(x, v)
            edges = list(G.edges())
            swaps_done += 1

    return G


# ---------------------------------------------------------------------------
# Graph predicates (br-5wd)
# ---------------------------------------------------------------------------


def is_valid_degree_sequence_erdos_gallai(deg_sequence):
    """Check if an integer sequence is a valid degree sequence (Erdos-Gallai).

    br-isokw: parameter name ``deg_sequence`` matches nx exactly so
    ``is_valid_degree_sequence_erdos_gallai(deg_sequence=[...])``
    kwarg-style drop-in calls work.

    The Erdos-Gallai theorem: a non-increasing sequence d_1 >= ... >= d_n
    is graphical iff sum(d_i) is even and for each k:
    sum(d_i, i=1..k) <= k*(k-1) + sum(min(d_i, k), i=k+1..n).
    """
    sequence = _make_list_of_ints(deg_sequence)
    seq = sorted(sequence, reverse=True)
    n = len(seq)
    if sum(seq) % 2 != 0:
        return False
    for k in range(1, n + 1):
        lhs = sum(seq[:k])
        rhs = k * (k - 1) + sum(min(d, k) for d in seq[k:])
        if lhs > rhs:
            return False
    return True


def is_valid_degree_sequence_havel_hakimi(deg_sequence):
    """Check if an integer sequence is a valid degree sequence (Havel-Hakimi).

    br-isokw: parameter name ``deg_sequence`` matches nx.

    Repeatedly removes the largest element d, subtracts 1 from the next
    d largest elements. If any become negative, not graphical.
    """
    sequence = _make_list_of_ints(deg_sequence)
    seq = list(sequence)
    while True:
        seq.sort(reverse=True)
        if not seq or seq[0] == 0:
            return True
        d = seq.pop(0)
        if d > len(seq):
            return False
        for i in range(d):
            seq[i] -= 1
            if seq[i] < 0:
                return False


def is_valid_joint_degree(joint_degrees):
    """Check if a joint degree dictionary is realizable."""
    degree_count = {}
    for degree in joint_degrees:
        if degree > 0:
            degree_size = sum(joint_degrees[degree].values()) / degree
            if not degree_size.is_integer():
                return False
            degree_count[degree] = degree_size

    for degree_left in joint_degrees:
        for degree_right in joint_degrees[degree_left]:
            edge_count = joint_degrees[degree_left][degree_right]
            if not float(edge_count).is_integer():
                return False

            if (
                degree_left != degree_right
                and edge_count > degree_count[degree_left] * degree_count[degree_right]
            ):
                return False
            if degree_left == degree_right:
                if edge_count > degree_count[degree_left] * (
                    degree_count[degree_left] - 1
                ):
                    return False
                if edge_count % 2 != 0:
                    return False
    return True


def is_strongly_regular(G):
    """Check if *G* is strongly regular.

    A graph is strongly regular srg(v,k,λ,μ) if it is k-regular and
    every pair of adjacent vertices has exactly λ common neighbors,
    and every pair of non-adjacent vertices has exactly μ common neighbors.

    br-srgdiam: nx.is_strongly_regular uses ``is_distance_regular(G)
    and diameter(G) == 2`` — the diameter-2 requirement excludes
    complete graphs (K_n has diameter 1) and C_3 (=K_3). The Rust
    _fnx.is_strongly_regular_rust implementation missed this
    requirement and classified every K_n (n>=3) as strongly regular,
    plus C_3 as True where nx returns False. Also enforce nx's
    directed/multigraph rejection explicitly.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    return is_distance_regular(G) and diameter(G) == 2


def is_at_free(G):
    """Check if *G* is asteroidal-triple-free (AT-free).

    An asteroidal triple is three nodes where between each pair there
    exists a path avoiding the neighborhood of the third.
    """
    return _fnx.is_at_free_rust(G)


def is_d_separator(G, x, y, z):
    """Check if node set *z* d-separates *x* from *y* in a DAG (Rust)."""
    from franken_networkx._fnx import is_d_separator_rust as _rust_dsep

    x, y, z = set(x), set(y), set(z)
    intersection = x.intersection(y) | x.intersection(z) | y.intersection(z)
    if intersection:
        raise NetworkXError(f"The sets are not disjoint, with intersection {intersection}")
    return _rust_dsep(G, list(x), list(y), list(z))


def is_minimal_d_separator(G, x, y, z, *, included=None, restricted=None):
    """Check if *z* is a minimal d-separator of *x* and *y*.

    Matches networkx's keyword-only ``included`` and ``restricted``
    constraints from PEP 3102 / nx's API:

    - ``included``: subset of *z* that must remain in any minimal
      d-separator (not removable when shrinking).
    - ``restricted``: superset that *z* and any reduction must stay
      within.

    When either constraint is given fnx delegates to networkx for
    correctness; the standalone path keeps the simple O(|z|) reducer.
    """
    if included is not None or restricted is not None:
        return _call_networkx_for_parity(
            "is_minimal_d_separator",
            G,
            x,
            y,
            z,
            included=included,
            restricted=restricted,
        )
    if not is_d_separator(G, x, y, z):
        return False
    z = set(z)
    for node in list(z):
        reduced = z - {node}
        if is_d_separator(G, x, y, reduced):
            return False
    return True


# ---------------------------------------------------------------------------
# Graph products (br-69m)
# ---------------------------------------------------------------------------


def corona_product(G, H):
    """Return the corona product of *G* and *H*.

    For each node v in G, add a copy of H and connect v to all nodes
    in that copy.

    Parameters
    ----------
    G, H : Graph

    Returns
    -------
    Graph
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    _validate_product_graph_types(G, H, allow_multigraph=True)

    P = _product_graph_class(G, H)()
    P.add_nodes_from(G.nodes())

    if G.is_multigraph():
        for u, v, key in G.edges(keys=True):
            P.add_edge(u, v, key=key)
    else:
        for u, v in G.edges():
            P.add_edge(u, v)

    for g in G.nodes():
        for h in H.nodes():
            P.add_node((g, h))
            P.add_edge(g, (g, h))
        if H.is_multigraph():
            # Match NetworkX's add_edges_from(H.edges.data()) behavior by letting the
            # product graph assign fresh integer keys for copied multiedges.
            for u, v, attrs in H.edges(data=True):
                P.add_edge((g, u), (g, v), **dict(attrs))
        else:
            for u, v, attrs in H.edges(data=True):
                P.add_edge((g, u), (g, v), **dict(attrs))

    return P


def modular_product(G, H):
    """Return the modular product of *G* and *H*.

    Two nodes (u1,v1) and (u2,v2) are adjacent iff:
    - u1-u2 is edge in G AND v1-v2 is edge in H, OR
    - u1-u2 is NOT edge in G AND v1-v2 is NOT edge in H (and u1≠u2, v1≠v2).
    """
    if G.is_directed() or H.is_directed():
        raise NetworkXNotImplemented("Modular product not implemented for directed graphs")
    if G.is_multigraph() or H.is_multigraph():
        raise NetworkXNotImplemented("Modular product not implemented for multigraphs")
    P = Graph()

    for g, g_attrs in G.nodes(data=True):
        for h, h_attrs in H.nodes(data=True):
            P.add_node((g, h), **_product_node_attrs(dict(g_attrs), dict(h_attrs)))

    g_nodes = list(G.nodes())
    h_nodes = list(H.nodes())
    for g_left_index, g_left in enumerate(g_nodes):
        for g_right in g_nodes[g_left_index + 1 :]:
            g_adjacent = G.has_edge(g_left, g_right)
            for h_left_index, h_left in enumerate(h_nodes):
                for h_right in h_nodes[h_left_index + 1 :]:
                    h_adjacent = H.has_edge(h_left, h_right)
                    if g_adjacent != h_adjacent:
                        continue
                    attrs = _paired_edge_attrs(
                        dict(G[g_left][g_right]) if g_adjacent else {},
                        dict(H[h_left][h_right]) if h_adjacent else {},
                    )
                    P.add_edge((g_left, h_left), (g_right, h_right), **attrs)
                    P.add_edge((g_left, h_right), (g_right, h_left), **attrs)

    return P


def rooted_product(G, H, root):
    """Return the rooted product of *G* and *H* at *root*.

    Replace each node v in G with a copy of H, connecting v's copy of
    *root* to the neighbors of v.
    """
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if root not in H:
        raise NodeNotFound("root must be a vertex in H")

    P = Graph()
    for g in G.nodes():
        for h in H.nodes():
            P.add_node((g, h))

    for g in G.nodes():
        for u, v in H.edges():
            P.add_edge((g, u), (g, v))

    for u, v in G.edges():
        P.add_edge((u, root), (v, root))

    return P


def lexicographic_product(G, H):
    """Return the lexicographic product of *G* and *H*.

    (u1,v1) and (u2,v2) are adjacent iff u1-u2 is an edge in G,
    OR u1==u2 and v1-v2 is an edge in H.
    """
    _validate_product_graph_types(G, H)
    P = _product_graph_class(G, H)()

    for g, g_attrs in G.nodes(data=True):
        for h, h_attrs in H.nodes(data=True):
            P.add_node((g, h), **_product_node_attrs(dict(g_attrs), dict(h_attrs)))

    if G.is_multigraph():
        for u, v, key, attrs in G.edges(keys=True, data=True):
            for hu in H.nodes():
                for hv in H.nodes():
                    # 4-tuple form avoids `key=key, **attrs` collision
                    # (franken_networkx-uphdr).
                    P.add_edges_from([((u, hu), (v, hv), key, dict(attrs))])
    else:
        for u, v, attrs in G.edges(data=True):
            for hu in H.nodes():
                for hv in H.nodes():
                    P.add_edge((u, hu), (v, hv), **dict(attrs))

    if H.is_multigraph():
        for u, v, key, attrs in H.edges(keys=True, data=True):
            for g in G.nodes():
                P.add_edges_from([((g, u), (g, v), key, dict(attrs))])
    else:
        for u, v, attrs in H.edges(data=True):
            for g in G.nodes():
                P.add_edge((g, u), (g, v), **dict(attrs))

    return P


# ---------------------------------------------------------------------------
# Advanced metrics & indices (br-jxl)
# ---------------------------------------------------------------------------


def estrada_index(G):
    """Return the Estrada index of *G*.

    br-estradaweighted: nx.estrada_index computes the index via
    ``sum(subgraph_centrality(G).values())``, which uses the UNWEIGHTED
    adjacency matrix (subgraph_centrality internally calls
    ``to_numpy_array(G, weight=None)``). fnx previously computed it via
    ``sum(exp(adjacency_spectrum(G)))`` — but ``adjacency_spectrum``
    defaults to the WEIGHTED adjacency. On karate_club_graph (which
    has weight attrs) this diverged massively: fnx=2.65e9 vs nx=1041.
    Match nx's formulation by summing subgraph_centrality, which
    mathematically equals sum(exp(eigenvalues of unweighted A)).
    """
    return float(sum(subgraph_centrality(G).values()))


def _simple_graph_weighted_shortest_path_lengths(G, source, weight):
    distances = {source: 0.0}
    counter = count()
    queue = [(0.0, next(counter), source)]

    while queue:
        distance, _, node = heappop(queue)
        if distance > distances[node]:
            continue

        for neighbor in G.neighbors(node):
            edge_weight = G.get_edge_data(node, neighbor).get(weight, 1)
            candidate = distance + edge_weight
            if candidate < distances.get(neighbor, float("inf")):
                distances[neighbor] = candidate
                heappush(queue, (candidate, next(counter), neighbor))

    return distances


def gutman_index(G, weight=None, *, backend=None, **backend_kwargs):
    """Return the Gutman index (degree-distance) of *G*.

    Sum over all pairs of deg(u)*deg(v)*dist(u,v).
    """
    _validate_backend_dispatch_keywords("gutman_index", backend, backend_kwargs)
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not is_connected(G):
        return float("inf")

    degrees = dict(G.degree)
    if weight is None:
        spl = shortest_path_length(G)
        return sum(
            dist * degrees[u] * degrees[v]
            for u, vinfo in spl
            for v, dist in vinfo.items()
        ) / 2

    return sum(
        dist * degrees[u] * degrees[v]
        for u in G
        for v, dist in _simple_graph_weighted_shortest_path_lengths(
            G, u, weight
        ).items()
    ) / 2


def schultz_index(G, weight=None, *, backend=None, **backend_kwargs):
    """Return the Schultz index of *G*.

    Sum over all pairs of (deg(u)+deg(v))*dist(u,v).
    """
    _validate_backend_dispatch_keywords("schultz_index", backend, backend_kwargs)
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not is_connected(G):
        return float("inf")

    degrees = dict(G.degree)
    if weight is None:
        spl = shortest_path_length(G)
        return sum(
            dist * (degrees[u] + degrees[v])
            for u, vinfo in spl
            for v, dist in vinfo.items()
        ) / 2

    return sum(
        dist * (degrees[u] + degrees[v])
        for u in G
        for v, dist in _simple_graph_weighted_shortest_path_lengths(
            G, u, weight
        ).items()
    ) / 2


def hyper_wiener_index(G, weight=None):
    """Return the hyper-Wiener index of *G*.

    (W + sum(dist^2)) / 2 where W is the Wiener index.

    ``weight`` is accepted for networkx signature parity. When set, the
    calculation delegates to networkx so edge weights are honoured; the
    native Rust path assumes unit-distance edges.
    """
    if weight is not None:
        return _call_networkx_for_parity("hyper_wiener_index", G, weight=weight)
    return _fnx.hyper_wiener_index_rust(G)


def resistance_distance(G, nodeA=None, nodeB=None, weight=None, invert_weight=True):
    """Return the resistance distance between nodes.

    Based on the pseudo-inverse of the Laplacian matrix.

    Parameters
    ----------
    G : Graph
    nodeA, nodeB : node, optional
        If both given, return a single float. Otherwise return dict of dicts.
    weight : str or None, optional
    invert_weight : bool, optional

    Returns
    -------
    float or dict of dicts
    """
    import numpy as np

    nodelist = list(G.nodes())
    n = len(nodelist)
    if n == 0:
        return {} if nodeA is None else 0.0

    L = laplacian_matrix(G, nodelist=nodelist, weight=weight or "weight").toarray()
    # Pseudo-inverse of Laplacian
    L_pinv = np.linalg.pinv(L)

    idx = {node: i for i, node in enumerate(nodelist)}

    if nodeA is not None and nodeB is not None:
        i, j = idx[nodeA], idx[nodeB]
        return float(L_pinv[i, i] + L_pinv[j, j] - 2 * L_pinv[i, j])

    result = {}
    for u in nodelist:
        result[u] = {}
        for v in nodelist:
            i, j = idx[u], idx[v]
            result[u][v] = float(L_pinv[i, i] + L_pinv[j, j] - 2 * L_pinv[i, j])
    return result


def kemeny_constant(G, *, weight=None, backend=None, **backend_kwargs):
    """Return the Kemeny constant of *G*.

    Sum of 1/(1-lambda_i) for non-zero eigenvalues of the transition matrix.
    """
    import numpy as np
    import scipy as sp

    _validate_backend_dispatch_keywords("kemeny_constant", backend, backend_kwargs)
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    if len(G) == 0:
        raise NetworkXError("Graph G must contain at least one node.")
    if not is_connected(G):
        raise NetworkXError("Graph G must be connected.")
    if is_negatively_weighted(G, weight=weight):
        raise NetworkXError("The weights of graph G must be nonnegative.")

    adjacency = adjacency_matrix(G, weight=weight)
    n, m = adjacency.shape
    degrees = np.asarray(adjacency.sum(axis=1)).flatten()
    with np.errstate(divide="ignore"):
        degree_scale = 1.0 / np.sqrt(degrees)
    degree_scale[np.isinf(degree_scale)] = 0
    diagonal = sp.sparse.dia_array((degree_scale, 0), shape=(m, n)).tocsr()
    normalized = diagonal @ (adjacency @ diagonal)

    eigenvalues = np.sort(sp.linalg.eigvalsh(normalized.todense()))
    return float(np.sum(1 / (1 - eigenvalues[:-1])))


def non_randomness(G, k=None, weight="weight"):
    """Compute the non-randomness of a graph."""
    import numpy as np

    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    # Upstream uses mixed exception classes here: empty/self-loops
    # raise NetworkXError, but the "not connected" branch raises the
    # *base* NetworkXException. Pick the base class up lazily from nx
    # so ``except nx.NetworkXException`` keeps working.
    if G.number_of_edges() == 0:
        raise NetworkXError("non_randomness not applicable to empty graphs")
    if not is_connected(G):
        raise _nx_exception_cls()("Non connected graph.")
    if len(list(selfloop_edges(G))) > 0:
        raise NetworkXError("Graph must not contain self-loops")

    n = G.number_of_nodes()
    m = G.number_of_edges()

    if k is None:
        k = len(tuple(label_propagation_communities(G)))

    p = (2 * k * m) / (n * (n - k))
    if not 1 <= k < n or not 0 < p < 1:
        raise ValueError(
            f"invalid number of communities for graph with {n} nodes and {m} edges: {k}"
        )

    eigenvalues = np.linalg.eigvals(to_numpy_array(G, weight=weight))
    nr = float(np.real(np.sum(eigenvalues[:k])))
    nr_rd = (nr - ((n - 2 * k) * p + k)) / math.sqrt(2 * k * p * (1 - p))
    return nr, nr_rd


class _KernighanLinHeap:
    def __init__(self):
        self._heap = []
        self._values = {}
        self._counter = count()

    def insert(self, key, value, allow_increase=False):
        current = self._values.get(key)
        if current is not None and value > current and not allow_increase:
            return
        self._values[key] = value
        heappush(self._heap, (value, next(self._counter), key))

    def pop(self):
        while self._heap:
            value, _, key = heappop(self._heap)
            current = self._values.get(key)
            if current is None or current != value:
                continue
            del self._values[key]
            return key, value
        raise KeyError("pop from an empty heap")

    def get(self, key):
        return self._values[key]

    def __contains__(self, key):
        return key in self._values

    def __bool__(self):
        return bool(self._values)


def _is_partition_of_graph(G, communities):
    nodes = set(G)
    seen = set()
    for community in communities:
        community_nodes = set(community)
        if seen & community_nodes:
            return False
        seen.update(community_nodes)
    return seen == nodes


def _kernighan_lin_sweep(edge_info, side):
    """Yield cumulative costs and node pairs for a KL sweep."""
    heap0, heap1 = cost_heaps = _KernighanLinHeap(), _KernighanLinHeap()
    for u, nbrs in edge_info.items():
        cost_u = sum(wt if side[v] else -wt for v, wt in nbrs.items())
        if side[u]:
            heap1.insert(u, cost_u)
        else:
            heap0.insert(u, -cost_u)

    def _update_heap_values(node):
        side_node = side[node]
        for nbr, wt in edge_info[node].items():
            side_nbr = side[nbr]
            if side_nbr == side_node:
                wt = -wt
            heap_nbr = cost_heaps[side_nbr]
            if nbr in heap_nbr:
                cost_nbr = heap_nbr.get(nbr) + 2 * wt
                heap_nbr.insert(nbr, cost_nbr, allow_increase=True)

    index = 0
    total_cost = 0
    while heap0 and heap1:
        u, cost_u = heap0.pop()
        _update_heap_values(u)
        v, cost_v = heap1.pop()
        _update_heap_values(v)
        total_cost += cost_u + cost_v
        index += 1
        yield total_cost, index, (u, v)


def kernighan_lin_bisection(G, partition=None, max_iter=10, weight="weight", seed=None):
    """Partition a graph into two blocks using the Kernighan-Lin algorithm."""
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    nodes = list(G)
    if partition is None:
        rng = _generator_random_state(seed)
        rng.shuffle(nodes)
        mid = len(nodes) // 2
        A, B = nodes[:mid], nodes[mid:]
    else:
        try:
            A, B = partition
        except (TypeError, ValueError) as err:
            raise NetworkXError("partition must be two sets") from err
        if not _is_partition_of_graph(G, [A, B]):
            raise NetworkXError("partition invalid")

    side = {node: (node in A) for node in nodes}

    if callable(weight):
        sum_weight = weight
    elif G.is_multigraph():
        sum_weight = lambda u, v, d: sum(dd.get(weight, 1) for dd in d.values())
    else:
        sum_weight = lambda u, v, d: d.get(weight, 1)

    edge_info = {
        u: {
            v: wt
            for v, d in G.adj[u].items()
            if (wt := sum_weight(u, v, d)) is not None
        }
        for u in G.adj
    }

    for _ in range(max_iter):
        costs = list(_kernighan_lin_sweep(edge_info, side))
        min_cost, min_index, _ = min(costs)
        if min_cost >= 0:
            break

        for _, _, (u, v) in costs[:min_index]:
            side[u] = 1
            side[v] = 0

    part1 = {u for u, s in side.items() if s == 0}
    part2 = {u for u, s in side.items() if s == 1}
    return part1, part2


def asyn_fluidc(G, k, max_iter=100, seed=None):
    """Return communities in G as detected by the Fluid Communities algorithm."""
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")
    if not isinstance(k, int):
        raise NetworkXError("k must be an integer.")
    if k <= 0:
        raise NetworkXError("k must be greater than 0.")
    if not is_connected(G):
        raise NetworkXError("Fluid Communities require connected Graphs.")
    if len(G) < k:
        raise NetworkXError("k cannot be bigger than the number of nodes.")
    if max_iter <= 0:
        raise ValueError(f"{max_iter=} must be greater than 0")

    rng = _generator_random_state(seed)
    max_density = 1.0
    vertices = list(G)
    rng.shuffle(vertices)
    communities = {node: index for index, node in enumerate(vertices[:k])}
    density = {}
    community_sizes = {}
    for node in communities:
        community_sizes[communities[node]] = 1
        density[communities[node]] = max_density

    iteration_count = 0
    should_continue = True
    while should_continue and iteration_count < max_iter:
        should_continue = False
        iteration_count += 1
        vertices = list(G)
        rng.shuffle(vertices)
        for vertex in vertices:
            community_counter = Counter()
            try:
                community_counter.update(
                    {communities[vertex]: density[communities[vertex]]},
                )
            except KeyError:
                pass

            for neighbor in G[vertex]:
                try:
                    community_counter.update(
                        {communities[neighbor]: density[communities[neighbor]]},
                    )
                except KeyError:
                    continue

            new_community = -1
            if community_counter:
                max_frequency = max(community_counter.values())
                best_communities = [
                    community
                    for community, frequency in community_counter.items()
                    if (max_frequency - frequency) < 0.0001
                ]
                try:
                    if communities[vertex] in best_communities:
                        new_community = communities[vertex]
                except KeyError:
                    pass

                if new_community == -1:
                    should_continue = True
                    new_community = rng.choice(best_communities)
                    try:
                        community_sizes[communities[vertex]] -= 1
                        density[communities[vertex]] = (
                            max_density / community_sizes[communities[vertex]]
                        )
                    except KeyError:
                        pass
                    communities[vertex] = new_community
                    community_sizes[communities[vertex]] += 1
                    density[communities[vertex]] = (
                        max_density / community_sizes[communities[vertex]]
                    )

    grouped = {}
    for node, community in communities.items():
        grouped.setdefault(community, set()).add(node)
    return iter(grouped.values())


def label_propagation_communities(G):
    """Generates community sets determined by label propagation."""
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    communities = _fnx.label_propagation_communities(G)
    return {index: set(community) for index, community in enumerate(communities)}.values()


def _call_networkx_community_for_parity(name, G, /, *args, **kwargs):
    import networkx as nx

    try:
        return getattr(nx.algorithms.community, name)(
            _networkx_graph_for_parity(G), *args, **kwargs
        )
    except Exception as exc:
        _raise_translated_networkx_exception(exc)


def fast_label_propagation_communities(G, *, weight=None, seed=None):
    """Generate community sets determined by fast label propagation."""
    return _call_networkx_community_for_parity(
        "fast_label_propagation_communities", G, weight=weight, seed=seed
    )


def is_partition(G, communities):
    """Return True if ``communities`` is a partition of the nodes of ``G``."""
    return _call_networkx_community_for_parity("is_partition", G, communities)


def leiden_communities(G, weight="weight", resolution=1, max_level=None, seed=None):
    """Find communities in G using the Leiden algorithm."""
    return _call_networkx_community_for_parity(
        "leiden_communities", G,
        weight=weight, resolution=resolution, max_level=max_level, seed=seed,
    )


def leiden_partitions(G, weight="weight", resolution=1, seed=None):
    """Yield partitions of G during Leiden community detection."""
    return _call_networkx_community_for_parity(
        "leiden_partitions", G,
        weight=weight, resolution=resolution, seed=seed,
    )


def edge_betweenness_partition(G, number_of_sets, *, weight=None):
    """Partition G using edge betweenness centrality."""
