# Advanced Centrality (br-v3y)
# ---------------------------------------------------------------------------


def _current_flow_pseudo_peripheral_node(G):
    """Return a pseudo-peripheral node for reverse Cuthill-McKee ordering."""
    def _ordered_path_lengths(source):
        distances = {source: 0}
        queue = deque([source])
        while queue:
            parent = queue.popleft()
            next_distance = distances[parent] + 1
            for child in G[parent]:
                if child not in distances:
                    distances[child] = next_distance
                    queue.append(child)
        return distances

    node = next(iter(G))
    longest_path = 0
    peripheral = node
    while True:
        path_lengths = _ordered_path_lengths(peripheral)
        eccentricity = max(path_lengths.values())
        if eccentricity <= longest_path:
            break
        longest_path = eccentricity
        farthest_nodes = (
            candidate
            for candidate, distance in path_lengths.items()
            if distance == eccentricity
        )
        peripheral = min(farthest_nodes, key=lambda candidate: G.degree[candidate])
    return peripheral


def _connected_cuthill_mckee_ordering(G, heuristic=None):
    """Yield the Cuthill-McKee ordering for a connected graph."""
    start = heuristic(G) if heuristic is not None else _current_flow_pseudo_peripheral_node(G)
    visited = {start}
    queue = deque([start])
    while queue:
        parent = queue.popleft()
        yield parent
        children = sorted(
            set(G[parent]) - visited,
            key=lambda candidate: G.degree[candidate],
        )
        visited.update(children)
        queue.extend(children)


def _reverse_cuthill_mckee_ordering(G, heuristic=None):
    """Yield the reverse Cuthill-McKee ordering for an undirected graph."""
    return reversed(list(_connected_cuthill_mckee_ordering(G, heuristic=heuristic)))


class _InverseLaplacian:
    def __init__(self, L, width=None, dtype=None):
        import numpy as np

        (n, _) = L.shape
        self.dtype = dtype
        self.n = n
        self.w = self.width(L) if width is None else width
        self.C = np.zeros((self.w, n), dtype=dtype)
        self.L1 = L[1:, 1:]
        self.init_solver(L)

    def init_solver(self, L):
        pass

    def solve(self, rhs):
        raise NetworkXError("Implement solver")

    def solve_inverse(self, row_index):
        raise NetworkXError("Implement solver")

    def get_rows(self, row_start, row_end):
        for row_index in range(row_start, row_end + 1):
            self.C[row_index % self.w, 1:] = self.solve_inverse(row_index)
        return self.C

    def get_row(self, row_index):
        self.C[row_index % self.w, 1:] = self.solve_inverse(row_index)
        return self.C[row_index % self.w]

    def width(self, L):
        import numpy as np

        max_width = 0
        for row_index, row in enumerate(L):
            offsets = np.nonzero(row)[-1]
            if len(offsets) == 0:
                continue
            span = offsets - row_index
            max_width = max(max_width, span.max() - span.min() + 1)
        return max_width


class _FullInverseLaplacian(_InverseLaplacian):
    def init_solver(self, L):
        import numpy as np

        self.IL = np.zeros(L.shape, dtype=self.dtype)
        self.IL[1:, 1:] = np.linalg.inv(self.L1.todense())

    def solve(self, rhs):
        return self.IL @ rhs

    def solve_inverse(self, row_index):
        return self.IL[row_index, 1:]


class _SuperLUInverseLaplacian(_InverseLaplacian):
    def init_solver(self, L):
        import scipy as sp

        self.lusolve = sp.sparse.linalg.factorized(self.L1.tocsc())

    def solve_inverse(self, row_index):
        import numpy as np

        rhs = np.zeros(self.n, dtype=self.dtype)
        rhs[row_index] = 1
        return self.lusolve(rhs[1:])

    def solve(self, rhs):
        import numpy as np

        solution = np.zeros(rhs.shape, dtype=self.dtype)
        solution[1:] = self.lusolve(rhs[1:])
        return solution


class _CGInverseLaplacian(_InverseLaplacian):
    def init_solver(self, L):
        import scipy as sp

        n = self.n - 1
        ilu = sp.sparse.linalg.spilu(self.L1.tocsc())
        self.M = sp.sparse.linalg.LinearOperator(shape=(n, n), matvec=ilu.solve)
        self._sp = sp

    def solve(self, rhs):
        import numpy as np

        solution = np.zeros(rhs.shape, dtype=self.dtype)
        solution[1:] = self._sp.sparse.linalg.cg(self.L1, rhs[1:], M=self.M, atol=0)[0]
        return solution

    def solve_inverse(self, row_index):
        import numpy as np

        rhs = np.zeros(self.n, dtype=self.dtype)
        rhs[row_index] = 1
        return self._sp.sparse.linalg.cg(self.L1, rhs[1:], M=self.M, atol=0)[0]


def _flow_matrix_row(G, weight=None, dtype=float, solver="lu"):
    """Yield rows of the current-flow matrix using local Laplacian helpers."""
    import numpy as np

    solvername = {
        "full": _FullInverseLaplacian,
        "lu": _SuperLUInverseLaplacian,
        "cg": _CGInverseLaplacian,
    }
    n = G.number_of_nodes()
    L = laplacian_matrix(G, nodelist=range(n), weight=weight).asformat("csc")
    L = L.astype(dtype)
    C = solvername[solver](L, dtype=dtype)
    w = C.w
    for u, v in sorted(tuple(sorted((u, v))) for u, v in G.edges()):
        B = np.zeros(w, dtype=dtype)
        c = G[u][v].get(weight, 1.0)
        B[u % w] = c
        B[v % w] = -c
        row = B @ C.get_rows(u, v)
        yield row, (u, v)


def current_flow_betweenness_centrality(
    G,
    normalized=True,
    weight=None,
    dtype=float,
    solver="full",
    *,
    backend=None,
    **backend_kwargs,
):
    """Current-flow betweenness centrality based on electrical current flow.

    br-cflowbetw: the Rust current_flow_betweenness_centrality_rust
    produced scores that differed from nx's by a factor of ~2.5x
    across karate_club_graph nodes, both normalized and unnormalized
    (fnx=0.189 vs nx=0.486 on node 0). That's well beyond numerical
    noise — a different normalization constant or different flow-
    splitting formula than nx's random-walk interpretation.
    Delegate to nx for exact parity; nx also supports solver and
    dtype kwargs that the Rust path silently ignored.
    """
    _validate_backend_dispatch_keywords(
        "current_flow_betweenness_centrality", backend, backend_kwargs
    )
    return _current_flow_betweenness_impl(
        G, normalized=normalized, weight=weight, dtype=dtype, solver=solver,
    )


def _current_flow_betweenness_impl(G, *, normalized, weight, dtype, solver):
    """Private delegation so public current_flow_betweenness stays
    PY_WRAPPER (br-cflowbetw).
    """
    return _call_networkx_for_parity(
        "current_flow_betweenness_centrality",
        G,
        normalized=normalized,
        weight=weight,
        dtype=dtype,
        solver=solver,
    )


def edge_current_flow_betweenness_centrality(
    G,
    normalized=True,
    weight=None,
    dtype=float,
    solver="full",
    *,
    backend=None,
    **backend_kwargs,
):
    """Edge variant of current-flow betweenness centrality."""
    _validate_backend_dispatch_keywords(
        "edge_current_flow_betweenness_centrality", backend, backend_kwargs
    )
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if not is_connected(G):
        raise NetworkXError("Graph not connected.")

    n = G.number_of_nodes()
    ordering = list(_reverse_cuthill_mckee_ordering(G))
    H = relabel_nodes(G, dict(zip(ordering, range(n))), copy=True)

    edges = (tuple(sorted((u, v))) for u, v in H.edges())
    betweenness = dict.fromkeys(edges, 0.0)
    if normalized:
        normalization = (n - 1.0) * (n - 2.0)
    else:
        normalization = 2.0

    for row, edge in _flow_matrix_row(H, weight=weight, dtype=dtype, solver=solver):
        pos = dict(zip(row.argsort()[::-1], range(1, n + 1)))
        for i in range(n):
            betweenness[edge] += (i + 1 - pos[i]) * row.item(i)
            betweenness[edge] += (n - i - pos[i]) * row.item(i)
        betweenness[edge] /= normalization

    return {(ordering[s], ordering[t]): value for (s, t), value in betweenness.items()}


def approximate_current_flow_betweenness_centrality(
    G,
    normalized=True,
    weight=None,
    dtype=float,
    solver="full",
    epsilon=0.5,
    kmax=10000,
    seed=None,
    *,
    sample_weight=1,
    backend=None,
    **backend_kwargs,
):
    """Approximate current-flow betweenness via random source-target sampling."""
    _validate_backend_dispatch_keywords(
        "approximate_current_flow_betweenness_centrality",
        backend,
        backend_kwargs,
    )
    return _call_networkx_for_parity(
        "approximate_current_flow_betweenness_centrality",
        G,
        normalized=normalized,
        weight=weight,
        dtype=dtype,
        solver=solver,
        epsilon=epsilon,
        kmax=kmax,
        seed=seed,
        sample_weight=sample_weight,
    )


def current_flow_closeness_centrality(
    G,
    weight=None,
    dtype=float,
    solver="lu",
    *,
    backend=None,
    **backend_kwargs,
):
    """Closeness centrality based on effective resistance (information centrality)."""
    _validate_backend_dispatch_keywords(
        "current_flow_closeness_centrality", backend, backend_kwargs
    )

    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")

    solvername = {
        "full": _FullInverseLaplacian,
        "lu": _SuperLUInverseLaplacian,
        "cg": _CGInverseLaplacian,
    }

    if not is_connected(G):
        raise NetworkXError("Graph not connected.")

    node_count = G.number_of_nodes()
    ordering = list(_reverse_cuthill_mckee_ordering(G))
    relabeled = relabel_nodes(G, dict(zip(ordering, range(node_count))))
    centrality = dict.fromkeys(relabeled, 0.0)

    laplacian = laplacian_matrix(
        relabeled,
        nodelist=range(node_count),
        weight=weight,
    ).asformat("csc")
    laplacian = laplacian.astype(dtype)
    inverse = solvername[solver](laplacian, width=1, dtype=dtype)

    for node in relabeled:
        row = inverse.get_row(node)
        for other in relabeled:
            centrality[node] += row.item(node) - 2 * row.item(other)
            centrality[other] += row.item(node)

    return {ordering[node]: 1 / value for node, value in centrality.items()}


def betweenness_centrality_subset(
    G,
    sources,
    targets,
    normalized=False,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Betweenness centrality restricted to source/target subsets."""
    _validate_backend_dispatch_keywords(
        "betweenness_centrality_subset",
        backend,
        backend_kwargs,
    )

    if weight is None and not G.is_multigraph():
        scores = _betweenness_centrality_subset_rust(
            G, list(sources), list(targets), normalized
        )
        return {node: scores.get(node, 0.0) for node in G}
    betweenness = dict.fromkeys(G, 0.0)
    for source in sources:
        if weight is None:
            stack, predecessors, sigma, _ = _single_source_shortest_path_basic_local(
                G, source
            )
        else:
            stack, predecessors, sigma, _ = _single_source_dijkstra_path_basic_local(
                G, source, weight
            )
        betweenness = _accumulate_subset_local(
            betweenness, stack, predecessors, sigma, source, targets
        )
    return _rescale_betweenness_local(
        betweenness,
        len(G),
        normalized=normalized,
        directed=G.is_directed(),
        endpoints=False,
    )


def edge_betweenness_centrality_subset(
    G,
    sources,
    targets,
    normalized=False,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Edge betweenness restricted to source/target subsets."""
    _validate_backend_dispatch_keywords(
        "edge_betweenness_centrality_subset",
        backend,
        backend_kwargs,
    )

    if weight is None and not G.is_multigraph():
        rust_scores = _edge_betweenness_centrality_subset_rust(
            G, list(sources), list(targets), normalized
        )
        betweenness = dict.fromkeys(G.edges(), 0.0)
        is_directed = G.is_directed()
        for (u, v), score in rust_scores.items():
            if (u, v) in betweenness:
                betweenness[(u, v)] = score
            elif not is_directed and (v, u) in betweenness:
                betweenness[(v, u)] = score
        return betweenness
    betweenness = dict.fromkeys(G, 0.0)
    betweenness.update(dict.fromkeys(G.edges(), 0.0))
    for source in sources:
        if weight is None:
            stack, predecessors, sigma, _ = _single_source_shortest_path_basic_local(
                G, source
            )
        else:
            stack, predecessors, sigma, _ = _single_source_dijkstra_path_basic_local(
                G, source, weight
            )
        betweenness = _accumulate_edges_subset_local(
            betweenness, stack, predecessors, sigma, source, targets
        )
    for node in G:
        del betweenness[node]
    betweenness = _rescale_betweenness_local(
        betweenness,
        len(G),
        normalized=normalized,
        directed=G.is_directed(),
    )
    if G.is_multigraph():
        return _add_edge_keys_local(G, betweenness, weight=weight)
    return betweenness


def edge_load_centrality(G, cutoff=False, *, backend=None, **backend_kwargs):
    """Load centrality for edges."""
    _validate_backend_dispatch_keywords("edge_load_centrality", backend, backend_kwargs)

    if cutoff is False:
        cutoff = None

    betweenness = {}
    for u, v in G.edges():
        betweenness[(u, v)] = 0.0
        betweenness[(v, u)] = 0.0
    for source in G:
        source_between = _edge_load_from_source_local(G, source, cutoff=cutoff)
        for edge, value in source_between.items():
            betweenness[edge] += value
    return betweenness


def laplacian_centrality(
    G,
    normalized=True,
    nodelist=None,
    weight="weight",
    walk_type=None,
    alpha=0.95,
    *,
    backend=None,
    **backend_kwargs,
):
    """Laplacian centrality: drop in Laplacian energy when node is removed."""
    _validate_backend_dispatch_keywords("laplacian_centrality", backend, backend_kwargs)
    return _call_networkx_for_parity(
        "laplacian_centrality",
        G,
        normalized=normalized,
        nodelist=nodelist,
        weight=weight,
        walk_type=walk_type,
        alpha=alpha,
    )


def percolation_centrality(
    G,
    attribute="percolation",
    states=None,
    weight=None,
    *,
    backend=None,
    **backend_kwargs,
):
    """Percolation centrality based on percolation states."""
    _validate_backend_dispatch_keywords(
        "percolation_centrality", backend, backend_kwargs
    )

    percolation = dict.fromkeys(G, 0.0)
    if states is None:
        states = {
            node: G.nodes[node].get(attribute, 1)
            for node in G
        }

    state_sum = sum(states.values())
    for source in G:
        if weight is None:
            stack, predecessors, sigma, _ = _single_source_shortest_path_basic_local(
                G, source
            )
        else:
            stack, predecessors, sigma, _ = _single_source_dijkstra_path_basic_local(
                G, source, weight
            )
        percolation = _accumulate_percolation_local(
            percolation, stack, predecessors, sigma, source, states, state_sum
        )

    for node in percolation:
        percolation[node] *= 1 / (len(G) - 2)
    return percolation


def information_centrality(
    G,
    weight=None,
    dtype=float,
    solver="lu",
    *,
    backend=None,
    **backend_kwargs,
):
    """Information centrality (same as current-flow closeness)."""
    _validate_backend_dispatch_keywords(
        "current_flow_closeness_centrality", backend, backend_kwargs
    )

    return current_flow_closeness_centrality(
        G,
        weight=weight,
        dtype=dtype,
        solver=solver,
    )


def second_order_centrality(G, weight="weight", *, backend=None, **backend_kwargs):
    """Second-order centrality based on random walk standard deviation."""
    _validate_backend_dispatch_keywords("second_order_centrality", backend, backend_kwargs)

    # br-r37-c1-u7ry8: the Rust fast path silently returned a value
    # dict on empty / disconnected graphs (zeros, NaNs, or {}). nx
    # raises NetworkXException with specific wording — mirror that
    # contract before any Rust dispatch so drop-in code that does
    # ``pytest.raises(NetworkXException, match='Non connected graph')``
    # triggers the same way under fnx. Single-isolated-node case is
    # the documented exception (returns {n: 0.0} on both libraries).
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    n_nodes = len(G)
    if n_nodes == 0:
        raise NetworkXException("Empty graph.")
    if n_nodes > 1 and not is_connected(G):
        raise NetworkXException("Non connected graph.")

    if (
        weight == "weight"
        and not _graph_has_edge_attribute(G, "weight")
    ):
        raw = _fnx.second_order_centrality_rust(G)
        # br-r37-c1-f6epo: the Rust binding returns the dict in
        # arbitrary internal order; nx iterates in node-insertion
        # order. Reorder so ``for node, score in result.items():``
        # matches nx's contract.
        return {node: raw[node] for node in G.nodes() if node in raw}

    import numpy as np

    nodelist = list(G.nodes())
    n = len(nodelist)

    if n == 1:
        return {nodelist[0]: 0.0}
    if any(data.get(weight, 0) < 0 for _, _, data in G.edges(data=True)):
        raise NetworkXError("Graph has negative edge weights.")

    directed = DiGraph(G)
    in_degree = dict(directed.in_degree(weight=weight))
    max_in_degree = max(in_degree.values())

    for node, degree in in_degree.items():
        if degree < max_in_degree:
            directed.add_edge(node, node, weight=max_in_degree - degree)

    transition = to_numpy_array(directed, nodelist=nodelist)
    transition /= transition.sum(axis=1)[:, np.newaxis]

    def _q_j_local(probabilities, column):
        restricted = probabilities.copy()
        restricted[:, column] = 0
        return restricted

    matrix = np.empty([n, n])
    identity = np.identity(n)
    ones = np.ones([n, 1])[:, 0]

    for idx in range(n):
        matrix[:, idx] = np.linalg.solve(identity - _q_j_local(transition, idx), ones)

    return dict(
        zip(
            nodelist,
            (
                float(np.sqrt(2 * np.sum(matrix[:, idx]) - n * (n + 1)))
                for idx in range(n)
            ),
        )
    )


def subgraph_centrality_exp(
    G,
    *,
    normalized=False,
    backend=None,
    **backend_kwargs,
):
    """Subgraph centrality via explicit scipy.linalg.expm."""
    _validate_backend_dispatch_keywords(
        "subgraph_centrality_exp",
        backend,
        backend_kwargs,
    )

    centrality = subgraph_centrality(G)
    if normalized:
        values = map(float, centrality.values())
        values.max()
    return centrality


def communicability_betweenness_centrality(G, *, backend=None, **backend_kwargs):
    """Betweenness centrality based on communicability."""
    _validate_backend_dispatch_keywords(
        "communicability_betweenness_centrality", backend, backend_kwargs
    )

    raw = _fnx.communicability_betweenness_centrality_rust(G, True)
    # br-r37-c1-pm78h: the Rust binding returns the dict in arbitrary
    # internal order; nx iterates in node-insertion order. Reorder so
    # ``for node, score in result.items():`` matches nx's contract.
    return {node: raw[node] for node in G.nodes() if node in raw}


def trophic_levels(G, weight="weight"):
    """Compute trophic levels in a directed graph (food web).

    br-trophdir: nx.trophic_levels / trophic_differences /
    trophic_incoherence_parameter are @not_implemented_for('undirected');
    fnx silently computed garbage (all-nodes at ~4.8e16) on Graph input.
    Reject undirected input with nx's exact exception type + message so
    the contract matches upstream.

    Default ``weight='weight'`` matches nx (br-r37-c1-rygbm). Earlier
    fnx default ``weight=None`` silently dropped edge weights.

    br-r37-c1-jk4ym: nx raises NetworkXError("no basal nodes") on
    an empty DiGraph; fnx returns {} for that edge case (no levels
    to compute). This is the project-wide convention for vacuous
    inputs.
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    if G.number_of_nodes() == 0:
        return {}
    return _call_networkx_for_parity("trophic_levels", G, weight=weight)


def trophic_differences(G, weight="weight"):
    """Compute trophic differences across edges.

    br-trophdir: see trophic_levels; reject undirected input.
    Default ``weight='weight'`` matches nx (br-r37-c1-rygbm).
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    return _call_networkx_for_parity("trophic_differences", G, weight=weight)


def trophic_incoherence_parameter(G, weight="weight", cannibalism=False):
    """Compute the trophic incoherence parameter (std of trophic differences).

    br-trophdir: see trophic_levels; reject undirected input.
    Default ``weight='weight'`` matches nx (br-r37-c1-rygbm).
    """
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    return _call_networkx_for_parity(
        "trophic_incoherence_parameter", G, weight=weight, cannibalism=cannibalism,
    )


def group_betweenness_centrality(
    G,
    C,
    normalized=True,
    weight=None,
    endpoints=False,
    *,
    backend=None,
    **backend_kwargs,
):
    """Betweenness centrality for a group of nodes C."""
    _validate_backend_dispatch_keywords(
        "group_betweenness_centrality", backend, backend_kwargs
    )

    if not G.is_directed() and weight is None and not endpoints:
        # Detect list-of-groups vs single group, mirroring the slow path
        # below (br-r37-c1-q49py): nx returns a list of per-group scores
        # when C is a list of groups, a scalar when C is a single group.
        # The Rust fast path always returns a scalar, so iterate when C
        # is a list of groups.
        list_of_groups = not any(element in G for element in C)
        if list_of_groups:
            scores = []
            for group in C:
                value = _fnx.group_betweenness_centrality_rust(G, list(group))
                if normalized:
                    scores.append(value)
                else:
                    remaining = len(G) - len(set(group))
                    scores.append(value * remaining * (remaining - 1) / 2)
            return scores
        value = _fnx.group_betweenness_centrality_rust(G, list(C))
        if normalized:
            return value
        remaining = len(G) - len(set(C))
        return value * remaining * (remaining - 1) / 2

    group_betweenness = []
    list_of_groups = True
    if any(element in G for element in C):
        C = [C]
        list_of_groups = False
    group_nodes = {node for group in C for node in group}
    missing_nodes = group_nodes - set(G.nodes())
    if missing_nodes:
        raise NodeNotFound(f"The node(s) {missing_nodes} are in C but not in G.")

    path_betweenness, sigma, distances = _group_preprocessing_local(
        G,
        group_nodes,
        weight,
    )

    for group in C:
        group = set(group)
        group_score = 0.0
        sigma_matrix = deepcopy(sigma)
        path_matrix = deepcopy(path_betweenness)
        next_sigma_matrix = deepcopy(sigma_matrix)
        next_path_matrix = deepcopy(path_matrix)
        for node in group:
            group_score += path_matrix[node][node]
            for left in group:
                for right in group:
                    distance_x_v_y = 0.0
                    distance_x_y_v = 0.0
                    distance_v_x_y = 0.0
                    if not (
                        sigma_matrix[left][right] == 0
                        or sigma_matrix[left][node] == 0
                        or sigma_matrix[node][right] == 0
                    ):
                        if distances[left][node] == distances[left][right] + distances[right][node]:
                            distance_x_y_v = (
                                sigma_matrix[left][right]
                                * sigma_matrix[right][node]
                                / sigma_matrix[left][node]
                            )
                        if distances[left][right] == distances[left][node] + distances[node][right]:
                            distance_x_v_y = (
                                sigma_matrix[left][node]
                                * sigma_matrix[node][right]
                                / sigma_matrix[left][right]
                            )
                        if distances[node][right] == distances[node][left] + distances[left][right]:
                            distance_v_x_y = (
                                sigma_matrix[node][left]
                                * sigma[left][right]
                                / sigma_matrix[node][right]
                            )
                    next_sigma_matrix[left][right] = sigma_matrix[left][right] * (
                        1 - distance_x_v_y
                    )
                    next_path_matrix[left][right] = (
                        path_matrix[left][right]
                        - path_matrix[left][right] * distance_x_v_y
                    )
                    if right != node:
                        next_path_matrix[left][right] -= (
                            path_matrix[left][node] * distance_x_y_v
                        )
                    if left != node:
                        next_path_matrix[left][right] -= (
                            path_matrix[node][right] * distance_v_x_y
                        )
            sigma_matrix, next_sigma_matrix = next_sigma_matrix, sigma_matrix
            path_matrix, next_path_matrix = next_path_matrix, path_matrix

        node_count = len(G)
        group_size = len(group)
        if not endpoints:
            scale = 0
            if G.is_directed():
                if is_strongly_connected(G):
                    scale = group_size * (2 * node_count - group_size - 1)
            elif is_connected(G):
                scale = group_size * (2 * node_count - group_size - 1)
            if scale == 0:
                for group_node in group:
                    for node in distances[group_node]:
                        if node != group_node:
                            scale += 1 if node in group else 2
            group_score -= scale

        if normalized:
            group_score *= 1 / ((node_count - group_size) * (node_count - group_size - 1))
        elif not G.is_directed():
            group_score /= 2

        group_betweenness.append(group_score)

    if list_of_groups:
        return group_betweenness
    return group_betweenness[0]


def group_closeness_centrality(G, S, weight=None, *, backend=None, **backend_kwargs):
    """Closeness centrality for a group of nodes S."""
    _validate_backend_dispatch_keywords(
        "group_closeness_centrality", backend, backend_kwargs
    )

    if not G.is_directed() and weight is None:
        return _fnx.group_closeness_centrality_rust(G, list(S))

    if G.is_directed():
        G = reverse(G)
    closeness = 0.0
    all_nodes = set(G)
    group = set(S)
    non_group_nodes = all_nodes - group
    if weight is None:
        shortest_path_lengths = {}
        for source in group:
            _, _, _, source_lengths = _single_source_shortest_path_basic_local(G, source)
            for node, distance in source_lengths.items():
                if node not in shortest_path_lengths or distance < shortest_path_lengths[node]:
                    shortest_path_lengths[node] = distance
    else:
        shortest_path_lengths = multi_source_dijkstra_path_length(G, group, weight=weight)
    for node in non_group_nodes:
        closeness += shortest_path_lengths.get(node, 0)
    try:
        return len(non_group_nodes) / closeness
    except ZeroDivisionError:
        return 0.0


# ---------------------------------------------------------------------------
# Traversal Extras (br-do1)
# ---------------------------------------------------------------------------


def bfs_beam_edges(G, source, value, width=None):
    """BFS with beam search.

    At each visited node, only the top-``width`` neighbours (ordered by
    ``value`` descending) are enqueued for further exploration. Matches
    networkx's implementation — the old fnx version filtered the whole
    frontier instead, which let far more edges slip through and
    diverged from nx by an order of magnitude on karate (32 vs 7).
    """
    if width is None:
        width = len(G)

    def successors(v):
        return iter(
            sorted(G.neighbors(v), key=value, reverse=True)[:width]
        )

    yield from generic_bfs_edges(G, source, successors)


def bfs_labeled_edges(G, sources):
    """BFS yielding NetworkX-style ``(u, v, label)`` triples.

    Signature matches networkx: ``sources`` is required and may be a single
    node or an iterable of nodes.
    """
    yield from _call_networkx_for_parity("bfs_labeled_edges", G, sources)


def dfs_labeled_edges(G, source=None, depth_limit=None, *, sort_neighbors=None):
    """DFS yielding NetworkX-style traversal event triples."""
    yield from _call_networkx_for_parity(
        "dfs_labeled_edges",
        G,
        source=source,
        depth_limit=depth_limit,
        sort_neighbors=sort_neighbors,
    )


def generic_bfs_edges(G, source, neighbors=None, depth_limit=None):
    """BFS with customizable neighbor function.

    br-r37-c1-lnqss: the Rust _fnx.generic_bfs_edges_rust default
    path yielded edges with adj iteration in a different order than
    nx (e.g. for adj[a]=[b,c], fnx returned (a,c),(a,b),... while
    nx yields (a,b),(a,c),...). Route through the Python path
    always, defaulting neighbors=G.neighbors when None — the
    Python branch already matches nx exactly.
    """
    if neighbors is None:
        neighbors = G.neighbors
    visited = {source}
    queue = [(source, 0)]
    while queue:
        next_queue = []
        for node, depth in queue:
            if depth_limit is not None and depth >= depth_limit:
                continue
            nbrs = list(neighbors(node))
            for nbr in nbrs:
                if nbr not in visited:
                    visited.add(nbr)
                    yield (node, nbr)
                    next_queue.append((nbr, depth + 1))
        queue = next_queue


# ---------------------------------------------------------------------------
# Utility Extras A (br-tnl)
# ---------------------------------------------------------------------------


def _lp_community_of(G, node, community):
    """br-shcomm: lift nx's NetworkXAlgorithmError when a node lacks
    the community attribute, matching the link-prediction contract.
    """
    attrs = G.nodes[node]
    try:
        return attrs[community]
    except (KeyError, TypeError) as err:
        raise NetworkXAlgorithmError(
            f"No community information available for Node {node}"
        ) from err


def cn_soundarajan_hopcroft(G, ebunch=None, community="community"):
    """Common Neighbor link prediction with community information.

    br-shcomm: nx raises NetworkXAlgorithmError when any node in ebunch
    lacks the community attribute. fnx previously treated missing
    community as None and silently computed a plain common-neighbor
    count without the bonus — a correctness trap for callers that
    assumed nx contract. Now raises the same error.
    """
    if ebunch is None:
        ebunch = non_edges(G)
    for u, v in ebunch:
        u_comm = _lp_community_of(G, u, community)
        v_comm = _lp_community_of(G, v, community)
        u_nbrs = set(G.neighbors(u))
        v_nbrs = set(G.neighbors(v))
        common = u_nbrs & v_nbrs
        score = len(common)
        if u_comm == v_comm:
            for w in common:
                if _lp_community_of(G, w, community) == u_comm:
                    score += 1
        yield (u, v, score)


def ra_index_soundarajan_hopcroft(G, ebunch=None, community="community"):
    """Resource Allocation link prediction with community information.

    br-shcomm: see cn_soundarajan_hopcroft — same missing-community
    contract. Also, nx's formula is simply sum(1/deg(w)) for common
    neighbors w whose community == Cu, when Cu==Cv; else 0. fnx's
    previous formula added a per-w bonus term that was never part of
    the nx definition, producing systematically larger scores.
    """
    if ebunch is None:
        ebunch = non_edges(G)
    for u, v in ebunch:
        u_comm = _lp_community_of(G, u, community)
        v_comm = _lp_community_of(G, v, community)
        if u_comm != v_comm:
            # br-shratype: nx returns int 0 here (no division on early
            # return); match exactly so type-sensitive callers don't
            # diverge.
            yield (u, v, 0)
            continue
        u_nbrs = set(G.neighbors(u))
        v_nbrs = set(G.neighbors(v))
        common = u_nbrs & v_nbrs
        score = 0
        for w in common:
            if _lp_community_of(G, w, community) == u_comm:
                deg_w = G.degree(w)
                if deg_w > 0:
                    score = score + 1 / deg_w
        yield (u, v, score)


def node_attribute_xy(G, attribute, nodes=None):
    """Yield (x, y) pairs of attribute values for edges.

    ``nodes`` restricts the source side: when given, only edges whose
    source is in ``nodes`` are emitted. Matches networkx's public
    signature ``node_attribute_xy(G, attribute, nodes=None)``.
    """
    node_filter = None if nodes is None else set(nodes)
    for u, nbrsdict in G.adjacency():
        if node_filter is not None and u not in node_filter:
            continue
        u_attrs = G.nodes[u] if hasattr(G.nodes, "__getitem__") else {}
        x = u_attrs.get(attribute) if isinstance(u_attrs, dict) else None
        if G.is_multigraph():
            for v, keys in nbrsdict.items():
                v_attrs = G.nodes[v] if hasattr(G.nodes, "__getitem__") else {}
                y = v_attrs.get(attribute) if isinstance(v_attrs, dict) else None
                for _ in keys:
                    yield (x, y)
        else:
            for v in nbrsdict:
                v_attrs = G.nodes[v] if hasattr(G.nodes, "__getitem__") else {}
                y = v_attrs.get(attribute) if isinstance(v_attrs, dict) else None
                yield (x, y)


def node_degree_xy(G, x="out", y="in", weight=None, nodes=None):
    """Yield (degree_x, degree_y) for each edge.

    br-r37-c1-6yimw: nx iterates ``xdeg(set(nodes))`` which yields
    nodes in hash-set order (since the implementation calls
    ``set(G)`` and iterates that). The previous fnx loop walked
    ``present_nodes`` (G.nodes()-insertion order), drifting tuple
    iteration order from nx. Replicate nx's exact algorithm.
    """
    node_set = set(G) if nodes is None else set(nodes)
    if G.is_directed():
        direction = {"out": G.out_degree, "in": G.in_degree}
        xdeg = direction[x]
        ydeg = direction[y]
    else:
        xdeg = ydeg = G.degree

    for u, degu in xdeg(node_set, weight=weight):
        # use G.edges to treat multigraphs correctly (each
        # parallel edge yields a separate tuple).
        neighbors = (nbr for _, nbr in G.edges(u) if nbr in node_set)
        for _, degv in ydeg(neighbors, weight=weight):
            yield degu, degv


def number_of_walks(G, walk_length, *, backend=None, **backend_kwargs):
    """Count walks of given length via adjacency matrix power."""
    import numpy as np

    _validate_backend_dispatch_keywords("number_of_walks", backend, backend_kwargs)
    if len(G) == 0:
        raise NetworkXError("Graph has no nodes or edges")
    if walk_length < 0:
        raise ValueError(f"`walk_length` cannot be negative: {walk_length}")
    if not isinstance(walk_length, numbers.Integral):
        raise ValueError("exponent must be an integer")

    A = to_numpy_array(G, weight=None)
    Ak = np.linalg.matrix_power(A.astype(int), walk_length)
    nodelist = list(G.nodes())
    result = {}
    for i, u in enumerate(nodelist):
        result[u] = {}
        for j, v in enumerate(nodelist):
            result[u][v] = int(Ak[i, j])
    return result


def recursive_simple_cycles(G):
    """Find all simple cycles using recursive DFS."""
    if not G.is_directed():
        raise NetworkXNotImplemented("not implemented for undirected type")
    return list(simple_cycles(G))


