def eulerize(G):
    """Add minimum edges to make G Eulerian. Returns copy with added edges.

    Finds odd-degree nodes, computes shortest paths between all pairs of them,
    finds minimum weight matching, and duplicates matched-path edges.
    """
    from itertools import combinations

    if len(G) == 0:
        raise NetworkXPointlessConcept("Cannot Eulerize null graph")
    if not is_connected(G):
        raise NetworkXError("G is not connected")

    odd_nodes = [v for v in G.nodes() if G.degree[v] % 2 == 1]
    if not odd_nodes:
        return G.copy()

    # Build a complete graph on odd-degree nodes weighted by shortest path length.
    odd_complete = Graph()
    for u, v in combinations(odd_nodes, 2):
        length = shortest_path_length(G, u, v, weight="weight")
        odd_complete.add_edge(u, v, weight=length)

    # Find minimum weight matching on the odd-degree complete graph.
    matching = min_weight_matching(odd_complete)

    # Duplicate edges along matched shortest paths.
    if G.is_directed():
        raise NetworkXError("G is directed")
    if G.is_multigraph():
        H = G.copy()
    else:
        H = MultiGraph(G)

    for u, v in matching:
        path = shortest_path(G, u, v, weight="weight")
        for i in range(len(path) - 1):
            # In a MultiGraph, adding an edge creates a new one
            if G.is_multigraph():
                # Just pick the first key/weight
                # Actually, NetworkX just copies the first key's attributes, or just {}
                H.add_edge(path[i], path[i + 1])
            else:
                H.add_edge(path[i], path[i + 1], **dict(G[path[i]][path[i + 1]]))

    return H


def moral_graph(G):
    """Return the moral graph of a DAG (marry co-parents, drop directions).

    For each node, connect all pairs of its predecessors (marry co-parents),
    then return the undirected version.
    """
    from itertools import combinations

    H = Graph()
    for node in G.nodes():
        H.add_node(node, **dict(G.nodes[node]))

    # Add existing edges as undirected.
    for u, v, data in G.edges(data=True):
        H.add_edge(u, v, **data)

    # Marry co-parents: for each node, connect all pairs of predecessors.
    for node in G.nodes():
        preds = list(G.predecessors(node))
        for u, v in combinations(preds, 2):
            if not H.has_edge(u, v):
                H.add_edge(u, v)

    return H


def equivalence_classes(iterable, relation):
    """Partition elements by an equivalence relation.

    br-r37-c1-8hshk: nx returns a ``set`` of frozensets (iterating in
    hash order); the local implementation returned a ``list`` of
    frozensets in input order. Drop-in code expecting the set return
    type or hash-based iteration broke. Match nx exactly.
    """
    elements = list(iterable)
    blocks = []
    for y in elements:
        for block in blocks:
            x = next(iter(block))
            if relation(x, y):
                block.add(y)
                break
        else:
            blocks.append({y})
    return {frozenset(block) for block in blocks}


def _node_order_key_local(node):
    return (type(node).__module__, type(node).__qualname__, repr(node))


def _minimum_cycle_basis_component_ordered_graph_local(G, component):
    ordered = _nx.Graph()
    component_nodes = set(component)

    for node in G:
        if node in component_nodes:
            ordered.add_node(node, **dict(G.nodes[node]))

    for u, v, data in G.edges(data=True):
        if u in component_nodes and v in component_nodes:
            ordered.add_edge(u, v, **dict(data))

    return ordered


def minimum_cycle_basis(G, weight=None):
    """Find minimum weight cycle basis.

    br-mincyclewt: the Rust _raw_minimum_cycle_basis returned
    SUBOPTIMAL (non-minimum-weight) cycle bases on weighted graphs.
    On K4 with weights ``abs(u-v)+1`` fnx returned a basis of total
    weight 25 where nx returned the correct weight-23 basis. The
    Rust implementation seems to ignore or misuse the edge weights.
    When a weight attribute is specified, delegate to nx's reference
    per-component implementation to guarantee a true minimum.
    Unweighted graphs (weight=None) still use the Rust fast path.
    """
    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    # br-mincyclewt: weighted inputs → delegate to nx for optimality.
    if weight is not None:
        return _minimum_cycle_basis_via_parity(G, weight)

    # br-rustlag: Rust symbol may be absent until the in-flight rebuild
    # lands; fall back to the per-component Python helper.
    if _raw_minimum_cycle_basis is None:
        return _minimum_cycle_basis_via_parity(G, weight)
    return _raw_minimum_cycle_basis(G, weight=weight)


def _minimum_cycle_basis_via_parity(G, weight):
    """Helper — delegate to upstream _min_cycle_basis on each component.

    Kept out of ``__all__`` so the classifier doesn't flag
    ``minimum_cycle_basis`` itself as NX_DELEGATED.
    """
    from networkx.algorithms.cycles import (
        _min_cycle_basis as _upstream_min_cycle_basis,
    )

    return sum(
        (
            _upstream_min_cycle_basis(
                _minimum_cycle_basis_component_ordered_graph_local(G, component),
                weight,
            )
            for component in connected_components(G)
        ),
        [],
    )


def chordless_cycles(G, length_bound=None):
    """Find all chordless (induced) cycles."""
    yield from _chordless_cycles_via_parity(G, length_bound=length_bound)


def _chordless_cycles_via_parity(G, *, length_bound=None):
    """Helper — keeps ``chordless_cycles`` classified as PY_WRAPPER.

    Imports upstream from the submodule so monkeypatches of the
    top-level ``nx.chordless_cycles`` don't intercept parity tests
    that assert fnx avoids the public delegation path.
    """
    from networkx.algorithms.cycles import (
        chordless_cycles as _upstream_chordless_cycles,
    )

    yield from _upstream_chordless_cycles(
        _networkx_graph_for_traversal_parity(G), length_bound=length_bound
    )


def to_undirected(graph):
    """Return a frozen live undirected view of *graph*.

    Parameter renamed from ``G`` to ``graph`` to match networkx's public
    signature ``to_undirected(graph)``.
    """
    return _generic_undirected_graph_view(graph)


def to_directed(graph):
    """Return a frozen live directed view of *graph*.

    Parameter renamed from ``G`` to ``graph`` to match networkx's public
    signature ``to_directed(graph)``.
    """
    return _generic_directed_graph_view(graph)


class _ReverseDirectedViewBase:
    adjlist_inner_dict_factory = dict
    adjlist_outer_dict_factory = dict
    edge_attr_dict_factory = dict
    graph_attr_dict_factory = dict
    node_attr_dict_factory = dict
    node_dict_factory = dict

    def __init__(self, graph):
        self._graph = graph
        self.graph = graph.graph
        self.frozen = True
        self.succ = _ReverseAdjacencyView(self)
        self.pred = _ReverseAdjacencyView(self, reverse=True)
        self.adj = self.succ

    def __iter__(self):
        return iter(self._graph)

    def __len__(self):
        return len(self._graph)

    def __contains__(self, node):
        return node in self._graph

    def __getitem__(self, node):
        # Match NetworkX: view[node] returns the reversed adjacency
        # mapping (i.e. self.succ[node] under the swapped-direction
        # semantics already baked into _ReverseAdjacencyView).
        return self.adj[node]

    def is_directed(self):
        return True

    def is_multigraph(self):
        return self._graph.is_multigraph()

    def to_directed_class(self):
        return MultiDiGraph if self.is_multigraph() else DiGraph

    def to_undirected_class(self):
        return MultiGraph if self.is_multigraph() else Graph

    def to_directed(self, as_view=False):
        """Materialise the reverse view as a concrete directed graph.

        Matches upstream NetworkX: returns a DiGraph / MultiDiGraph
        whose edges are the reversed edges of the underlying graph.
        `as_view` is accepted for API compatibility but behaves the
        same as False (already a reversed adjacency).
        """
        cls = self.to_directed_class()
        out = cls()
        out.graph.update(deepcopy(self.graph))
        out.add_nodes_from((n, self._graph.nodes[n]) for n in self._graph)
        if self.is_multigraph():
            for u, v, key, attrs in self._edges(data=True, keys=True):
                out.add_edges_from([(u, v, key, deepcopy(attrs))])
        else:
            for u, v, attrs in self._edges(data=True):
                out.add_edge(u, v, **deepcopy(attrs))
        return out

    def to_undirected(self, as_view=False):
        """Materialise the reverse view as a concrete undirected graph.

        Matches upstream NetworkX: collapses both directions of the
        reversed edges into an undirected Graph / MultiGraph.
        """
        cls = self.to_undirected_class()
        out = cls()
        out.graph.update(deepcopy(self.graph))
        out.add_nodes_from((n, self._graph.nodes[n]) for n in self._graph)
        if self.is_multigraph():
            for u, v, key, attrs in self._edges(data=True, keys=True):
                out.add_edges_from([(u, v, key, deepcopy(attrs))])
        else:
            for u, v, attrs in self._edges(data=True):
                out.add_edge(u, v, **deepcopy(attrs))
        return out

    def reverse(self, copy=True):
        """Return the underlying (un-reversed) directed graph.

        The reverse of a reverse-view is the original orientation.
        Matches upstream: copy=True returns a fresh DiGraph copy,
        copy=False returns the live underlying graph (no wrapper).
        """
        if copy:
            # Return a detached copy of the underlying directed graph.
            return self._graph.copy()
        return self._graph

    @property
    def nodes(self):
        """Expose the underlying graph's NodeView.

        reverse_view doesn't change node identity or attributes, only
        edge direction — so the NodeView is shared with the original
        graph. Matches upstream's callable NodeView surface (e.g.
        view.nodes.data(), view.nodes(data=True)).
        """
        return self._graph.nodes

    def nbunch_iter(self, nbunch=None):
        return self._graph.nbunch_iter(nbunch)

    def _nbunch(self, nbunch):
        if nbunch is None:
            return list(self._graph.nodes())
        if nbunch in self._graph:
            return [nbunch]
        try:
            return [node for node in nbunch if node in self._graph]
        except TypeError:
            return []

    def _edges(self, nbunch=None, data=False, keys=False, default=None):
        nodes = self._nbunch(nbunch)
        result = []
        if self._graph.is_multigraph():
            for source in nodes:
                for target, keyed_attrs in self._graph.pred[source].items():
                    for key, attrs in keyed_attrs.items():
                        if isinstance(data, str):
                            result.append(
                                (source, target, key, attrs.get(data, default))
                                if keys
                                else (source, target, attrs.get(data, default))
                            )
                        elif data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
        else:
            for source in nodes:
                for target, attrs in self._graph.pred[source].items():
                    if isinstance(data, str):
                        result.append((source, target, attrs.get(data, default)))
                    elif data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
        return result

    @property
    def edges(self):
        return _ReverseEdgeView(self)

    def out_edges(self, nbunch=None, data=False, keys=False):
        nodes = self._nbunch(nbunch)
        result = []
        adjacency = self.succ
        if self._graph.is_multigraph():
            for source in nodes:
                for target, keyed_attrs in adjacency[source].items():
                    for key, attrs in keyed_attrs.items():
                        if data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
        else:
            for source in nodes:
                for target, attrs in adjacency[source].items():
                    if data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
        return result

    def in_edges(self, nbunch=None, data=False, keys=False):
        nodes = self._nbunch(nbunch)
        result = []
        adjacency = self.pred
        if self._graph.is_multigraph():
            for target in nodes:
                for source, keyed_attrs in adjacency[target].items():
                    for key, attrs in keyed_attrs.items():
                        if data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
        else:
            for target in nodes:
                for source, attrs in adjacency[target].items():
                    if data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
        return result

    def degree(self, nbunch=None, weight=None):
        def edge_weight(attrs):
            return attrs.get(weight, 1)

        def node_degree(node):
            if self._graph.is_multigraph():
                if weight is None:
                    total = sum(len(keydict) for keydict in self.succ[node].values())
                    total += sum(len(keydict) for keydict in self.pred[node].values())
                    return total

                total = 0
                for keydict in self.succ[node].values():
                    for attrs in keydict.values():
                        total += edge_weight(attrs)
                for keydict in self.pred[node].values():
                    for attrs in keydict.values():
                        total += edge_weight(attrs)
                return total

            if weight is None:
                return len(self.succ[node]) + len(self.pred[node])

            total = 0
            for attrs in self.succ[node].values():
                total += edge_weight(attrs)
            for attrs in self.pred[node].values():
                total += edge_weight(attrs)
            return total

        if nbunch is None:
            return ((node, node_degree(node)) for node in self._graph)

        try:
            if nbunch in self._graph:
                return node_degree(nbunch)
        except TypeError:
            pass

        nodes = self._nbunch(nbunch)
        return ((node, node_degree(node)) for node in nodes)

    def subgraph(self, nodes):
        visible_nodes = set(self._nbunch(nodes))
        return _generic_filtered_graph_view(
            self,
            filter_node=lambda node: node in visible_nodes,
        )

    def edge_subgraph(self, edges):
        return edge_subgraph(self, edges)

    def copy(self, as_view=False):
        if as_view:
            return _generic_filtered_graph_view(self)

        copy_factory = getattr(self._graph, "_copy_type", None)
        result_type = copy_factory() if callable(copy_factory) else self._graph.__class__
        result = result_type()
        result.graph.update(dict(self.graph))
        result.add_nodes_from((node, dict(attrs)) for node, attrs in self.nodes(data=True))
        if self._graph.is_multigraph():
            # Use 4-tuple (u, v, key, attrs_dict) so an edge attribute literally
            # named "key" doesn't collide with add_edge's positional ``key=``
            # parameter (see franken_networkx-9x7r0).
            result.add_edges_from(
                (u, v, key, dict(attrs))
                for u, v, key, attrs in self.edges(keys=True, data=True)
            )
        else:
            result.add_edges_from(
                (u, v, dict(attrs)) for u, v, attrs in self.edges(data=True)
            )
        return result

    def number_of_nodes(self):
        return len(self._graph)

    def order(self):
        return self.number_of_nodes()

    def adjacency(self):
        return ((node, _ReverseNeighborMap(self, node)) for node in self._graph)

    def number_of_edges(self):
        return self._graph.number_of_edges()

    def size(self, weight=None):
        if weight is None:
            return self.number_of_edges()

        if self._graph.is_multigraph():
            return float(
                sum(attrs.get(weight, 1) for _, _, _, attrs in self.edges(keys=True, data=True))
            )
        return float(sum(attrs.get(weight, 1) for _, _, attrs in self.edges(data=True)))

    def has_node(self, node):
        return node in self._graph

    def has_edge(self, u, v, key=None):
        if self._graph.is_multigraph():
            return self._graph.has_edge(v, u, key)
        return self._graph.has_edge(v, u)

    def get_edge_data(self, u, v, *args, **kwargs):
        if self._graph.is_multigraph():
            key = kwargs.pop("key", None)
            default = kwargs.pop("default", None)
            if kwargs:
                unexpected = next(iter(kwargs))
                raise TypeError(f"get_edge_data() got an unexpected keyword argument '{unexpected}'")
            if len(args) > 2:
                raise TypeError(
                    f"get_edge_data() takes from 3 to 5 positional arguments but {len(args) + 3} were given"
                )
            if len(args) >= 1:
                key = args[0]
            if len(args) == 2:
                default = args[1]
            return self._graph.get_edge_data(v, u, key, default)

        if "key" in kwargs:
            raise TypeError("get_edge_data() got an unexpected keyword argument 'key'")
        default = kwargs.pop("default", None)
        if kwargs:
            unexpected = next(iter(kwargs))
            raise TypeError(f"get_edge_data() got an unexpected keyword argument '{unexpected}'")
        if len(args) > 1:
            raise TypeError(
                f"get_edge_data() takes from 3 to 4 positional arguments but {len(args) + 3} were given"
            )
        if args:
            default = args[0]
        return self._graph.get_edge_data(v, u, default)

    def neighbors(self, node):
        return self._graph.predecessors(node)

    def successors(self, node):
        return self._graph.predecessors(node)

    def predecessors(self, node):
        return self._graph.successors(node)

    def __getattr__(self, name):
        if name in _FILTERED_VIEW_MUTATORS:
            return _frozen
        raise AttributeError(name)


class _ReverseDirectedView(_ReverseDirectedViewBase, DiGraph):
    pass


class _ReverseMultiDirectedView(_ReverseDirectedViewBase, MultiDiGraph):
    pass


def _reverse_directed_view_for(graph):
    view_type = (
        _ReverseMultiDirectedView if graph.is_multigraph() else _ReverseDirectedView
    )
    return view_type(graph)


class _ReverseNeighborMap(Mapping):
    def __init__(self, view, node, *, reverse=False):
        self._view = view
        self._node = node
        self._reverse = reverse

    def _raw_neighbors(self):
        if self._reverse:
            return self._view._graph.succ[self._node]
        return self._view._graph.pred[self._node]

    def __iter__(self):
        return iter(self._raw_neighbors())

    def __len__(self):
        return len(self._raw_neighbors())

    def __getitem__(self, neighbor):
        return self._raw_neighbors()[neighbor]


class _ReverseAdjacencyView(Mapping):
    def __init__(self, view, *, reverse=False):
        self._view = view
        self._reverse = reverse

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        if node not in self._view._graph:
            raise KeyError(f"Key {node} not found")
        return _ReverseNeighborMap(self._view, node, reverse=self._reverse)


class _ReverseEdgeView:
    def __init__(self, view):
        self._view = view

    def __call__(self, nbunch=None, data=False, keys=False, default=None):
        return self._view._edges(nbunch=nbunch, data=data, keys=keys, default=default)

    def __iter__(self):
        return iter(self())

    def __len__(self):
        return self._view._graph.number_of_edges()

    def __contains__(self, edge):
        try:
            u, v = edge[:2]
        except (TypeError, ValueError):
            return False
        if u not in self._view._graph:
            return False
        # reverse_view iterates (u, v) where v is in the original graph's pred[u]
        # (original edge v -> u becomes reversed edge u -> v).
        return v in self._view._graph.pred[u]

    def __getitem__(self, edge):
        u, v = edge
        if u not in self._view._graph:
            raise KeyError(edge)
        pred_u = self._view._graph.pred[u]
        if v not in pred_u:
            raise KeyError(edge)
        return pred_u[v]

    def data(self, data=True, default=None, nbunch=None, keys=False):
        return self._view._edges(
            nbunch=nbunch, data=data, keys=keys, default=default
        )

    get = _adjacency_view_get
    keys = _adjacency_view_keys
    items = _adjacency_view_items
    values = _adjacency_view_values


_FILTERED_VIEW_MUTATORS = (
    "add_node",
    "add_nodes_from",
    "remove_node",
    "remove_nodes_from",
    "add_edge",
    "add_edges_from",
    "add_weighted_edges_from",
    "remove_edge",
    "remove_edges_from",
    "clear",
    "clear_edges",
    "update",
)


class _FilteredNeighborMap(Mapping):
    def __init__(self, view, node, *, reverse=False):
        self._view = view
        self._node = node
        self._reverse = reverse

    def _raw_neighbors(self):
        if self._view.is_directed():
            if self._reverse:
                return self._view._graph.pred[self._node]
            return self._view._graph.succ[self._node]
        return self._view._graph.adj[self._node]

    def _edge_visible(self, neighbor, key=None):
        if self._reverse:
            return self._view._edge_visible(neighbor, self._node, key)
        return self._view._edge_visible(self._node, neighbor, key)

    def __iter__(self):
        for neighbor, edge_data in self._raw_neighbors().items():
            if not self._view._node_visible(neighbor):
                continue
            if self._view.is_multigraph():
                if any(self._edge_visible(neighbor, key) for key in edge_data):
                    yield neighbor
            elif self._edge_visible(neighbor):
                yield neighbor

    def __len__(self):
        return sum(1 for _ in self)

    def __getitem__(self, neighbor):
        if not self._view._node_visible(neighbor):
            raise KeyError(f"Key {neighbor} not found")

        if self._view.is_multigraph():
            keydict = self._raw_neighbors()[neighbor]
            filtered = {
                key: attrs
                for key, attrs in keydict.items()
                if self._edge_visible(neighbor, key)
            }
            if filtered:
                return filtered
        else:
            if self._edge_visible(neighbor):
                return self._raw_neighbors()[neighbor]

        raise KeyError(f"Key {neighbor} not found")


class FilterAtlas(Mapping):
    def __init__(self, view, node, *, reverse=False):
        self._neighbors = _FilteredNeighborMap(view, node, reverse=reverse)

    def __iter__(self):
        return iter(self._neighbors)

    def __len__(self):
        return len(self._neighbors)

    def __getitem__(self, key):
        return self._neighbors[key]


class _FilteredAdjacencyView(Mapping):
    def __init__(self, view, *, reverse=False):
        self._view = view
        self._reverse = reverse

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        if not self._view._node_visible(node):
            raise KeyError(f"Key {node} not found")
        atlas_getter = lambda: _FilteredNeighborMap(
            self._view, node, reverse=self._reverse
        )
        if self._view.is_multigraph():
            return AdjacencyView(atlas_getter)
        return AtlasView(atlas_getter)


def _filtered_public_adjacency_view(view, *, reverse=False):
    atlas_getter = lambda: _FilteredAdjacencyView(view, reverse=reverse)
    if view.is_multigraph():
        return MultiAdjacencyView(atlas_getter)
    return AdjacencyView(atlas_getter)


def _node_attrs_for_view_graph(graph, node):
    graph_nodes = graph.nodes
    try:
        return graph_nodes[node]
    except TypeError:
        pass
    except KeyError:
        raise
    if callable(graph_nodes):
        for current_node, attrs in graph_nodes(data=True):
            if current_node == node:
                return attrs
    raise KeyError(f"Key {node} not found")


class NodeView(Mapping):
    def __init__(self, view):
        self._view = view

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        if not self._view._node_visible(node):
            raise KeyError(f"Key {node} not found")
        return _node_attrs_for_view_graph(self._view._graph, node)

    def __call__(self, data=False, default=None):
        if isinstance(data, str):
            return [(node, self[node].get(data, default)) for node in self]
        if data:
            return [(node, self[node]) for node in self]
        return list(self)

    def data(self, data=True, default=None):
        return self(data=data, default=default)


class _FilteredEdgeView:
    def __init__(self, view):
        self._view = view

    def __call__(self, nbunch=None, data=False, keys=False, default=None):
        if isinstance(data, str):
            base = self._view._edges(nbunch=nbunch, data=True, keys=keys)
            if keys:
                return [
                    (u, v, k, attrs.get(data, default)) for u, v, k, attrs in base
                ]
            return [
                (u, v, attrs.get(data, default)) for u, v, attrs in base
            ]
        # br-edgesnone: `data=None, default=X` yields 3-tuples with the
        # default as the third element for every edge (matches nx).
        if data is None:
            base = self._view._edges(nbunch=nbunch, data=False, keys=keys)
            if keys:
                return [(u, v, k, default) for u, v, k in base]
            return [(u, v, default) for u, v in base]
        return self._view._edges(nbunch=nbunch, data=data, keys=keys)

    def __iter__(self):
        return iter(self())

    def __len__(self):
        return len(self())

    def __contains__(self, edge):
        try:
            u, v = edge[:2]
        except (TypeError, ValueError):
            return False
        if not self._view.has_edge(u, v):
            return False
        return True

    def __getitem__(self, edge):
        u, v = edge
        if not self._view.has_edge(u, v):
            raise KeyError(edge)
        return self._view.adj[u][v]

    def data(self, data=True, default=None, nbunch=None, keys=False):
        return self(nbunch=nbunch, data=data, keys=keys, default=default)

    get = _adjacency_view_get
    keys = _adjacency_view_keys
    items = _adjacency_view_items
    values = _adjacency_view_values

    # br-filtedgeop: nx.EdgeView inherits from Set, so `G.edges - some_iter`
    # works via Set.__sub__. fnx's _FilteredEdgeView had no set-operator
    # methods, breaking nx._min_cycle_basis which does
    # `chords = G.edges - tree_edges - {(v, u) for u, v in tree_edges}`.
    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)

    def __eq__(self, other):
        if isinstance(other, (set, frozenset)):
            return set(self) == other
        return NotImplemented

    __hash__ = None


class _FilteredGraphView:
    adjlist_inner_dict_factory = dict
    adjlist_outer_dict_factory = dict
    edge_attr_dict_factory = dict
    graph_attr_dict_factory = dict
    node_attr_dict_factory = dict
    node_dict_factory = dict

    def __init__(self, graph, *, filter_node=None, filter_edge=None):
        self._graph = graph
        self.graph = graph.graph
        self._filter_node = filter_node or (lambda node: True)
        self._filter_edge = filter_edge or (lambda *args: True)
        self.frozen = True
        self.nodes = NodeView(self)
        self.adj = _filtered_public_adjacency_view(self)
        if graph.is_directed():
            self.succ = _filtered_public_adjacency_view(self)
            self.pred = _filtered_public_adjacency_view(self, reverse=True)

    def __iter__(self):
        for node in self._graph:
            if self._node_visible(node):
                yield node

    def __len__(self):
        return sum(1 for _ in self)

    def __contains__(self, node):
        return self._node_visible(node)

    def __getitem__(self, node):
        return self.adj[node]

    def __getattr__(self, name):
        if name in _FILTERED_VIEW_MUTATORS:
            return _frozen
        return getattr(self.copy(), name)

    def is_directed(self):
        return self._graph.is_directed()

    def is_multigraph(self):
        return self._graph.is_multigraph()

    def _node_visible(self, node):
        return node in self._graph and self._filter_node(node)

    def _edge_visible(self, u, v, key=None):
        if not (self._node_visible(u) and self._node_visible(v)):
            return False
        if self.is_multigraph():
            return self._filter_edge(u, v, key)
        return self._filter_edge(u, v)

    def _nbunch(self, nbunch):
        if nbunch is None:
            return list(self)
        if self._node_visible(nbunch):
            return [nbunch]
        try:
            return [node for node in nbunch if self._node_visible(node)]
        except TypeError:
            return []

    def nodes(self, data=False):
        if data:
            graph_nodes = self._graph.nodes
            if callable(graph_nodes):
                visible = set(self)
                return [
                    (node, attrs)
                    for node, attrs in graph_nodes(data=True)
                    if node in visible
                ]
            return [(node, graph_nodes[node]) for node in self]
        return list(self)

    def adjacency(self):
        if self.is_multigraph():
            return ((node, self.adj[node]) for node in self)
        return ((node, FilterAtlas(self, node)) for node in self)

    def _edges(self, nbunch=None, data=False, keys=False):
        nodes = self._nbunch(nbunch)
        result = []
        if self.is_directed():
            for source in nodes:
                for target in self.adj[source]:
                    if self.is_multigraph():
                        for key, attrs in self.adj[source][target].items():
                            if data and keys:
                                result.append((source, target, key, attrs))
                            elif data:
                                result.append((source, target, attrs))
                            elif keys:
                                result.append((source, target, key))
                            else:
                                result.append((source, target))
                    else:
                        attrs = self.adj[source][target]
                        if data:
                            result.append((source, target, attrs))
                        else:
                            result.append((source, target))
            return result

        seen = set()
        for source in nodes:
            for target in self.adj[source]:
                if target in seen:
                    continue
                if self.is_multigraph():
                    for key, attrs in self.adj[source][target].items():
                        if data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
                else:
                    attrs = self.adj[source][target]
                    if data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
            seen.add(source)
        return result

    @property
    def edges(self):
        return _FilteredEdgeView(self)

    def neighbors(self, node):
        if not self._node_visible(node):
            raise NetworkXError(f"The node {node} is not in the graph.")
        return iter(self.adj[node])

    def successors(self, node):
        return self.neighbors(node)

    def predecessors(self, node):
        if not self.is_directed():
            return self.neighbors(node)
        if not self._node_visible(node):
            raise NetworkXError(f"The node {node} is not in the graph.")
        return iter(self.pred[node])

    def has_edge(self, u, v, key=None):
        if self.is_multigraph():
            if not self._graph.has_edge(u, v, key):
                return False
            if key is not None:
                return self._edge_visible(u, v, key)
            return any(self._edge_visible(u, v, edge_key) for edge_key in self._graph[u][v])
        if not self._graph.has_edge(u, v):
            return False
        return self._edge_visible(u, v)

    def number_of_nodes(self):
        return len(self)

    def number_of_edges(self, u=None, v=None):
        if u is None and v is None:
            return len(self.edges(keys=True)) if self.is_multigraph() else len(self.edges())
        if v is None:
            if u not in self:
                raise KeyError(u)
            return 0
        if self.is_multigraph():
            if not self._graph.has_edge(u, v):
                return 0
            return sum(
                1
                for edge_key in self._graph[u][v]
                if self._edge_visible(u, v, edge_key)
            )
        return 1 if self.has_edge(u, v) else 0

    def _copy_type(self):
        if self.is_directed():
            return MultiDiGraph if self.is_multigraph() else DiGraph
        return MultiGraph if self.is_multigraph() else Graph

    def to_directed_class(self):
        return MultiDiGraph if self.is_multigraph() else DiGraph

    def to_undirected_class(self):
        return MultiGraph if self.is_multigraph() else Graph

    def copy(self, as_view=False):
        if as_view is True:
            return _generic_filtered_graph_view(self)

        result = self._copy_type()()
        result.graph.update(dict(self.graph))
        result.add_nodes_from((node, dict(attrs)) for node, attrs in self.nodes(data=True))
        if self.is_multigraph():
            # 4-tuple shape avoids the ``key=key, **attrs`` collision when an
            # edge attribute is literally named "key" (franken_networkx-9x7r0).
            result.add_edges_from(
                (u, v, key, dict(attrs))
                for u, v, key, attrs in self.edges(keys=True, data=True)
            )
        else:
            result.add_edges_from(
                (u, v, dict(attrs)) for u, v, attrs in self.edges(data=True)
            )
        return result


_PRIVATE_NODE_OVERRIDE = "_fnx_private_node_override"
_PRIVATE_ADJ_OVERRIDE = "_fnx_private_adj_override"
_PRIVATE_SUCC_OVERRIDE = "_fnx_private_succ_override"
_PRIVATE_PRED_OVERRIDE = "_fnx_private_pred_override"
