def _graph_shallowcopy(self):
    result = type(self)()
    setattr(result, _GRAPH_ATTR_OVERRIDE, self.graph)
    result._node = self._node
    if self.is_directed():
        result._succ = self.succ
        result._pred = self.pred
        result._adj = self.adj
    else:
        result._adj = self.adj
    return result


