def _to_undirected_with_view(to_undirected_impl):
    def to_undirected(self, as_view=False):
        if as_view is True:
            return _generic_undirected_graph_view(self)
        result = self.to_undirected_class()()
        result.graph.update(deepcopy(self.graph))
        result.add_nodes_from(
            (node, deepcopy(attrs)) for node, attrs in self.nodes(data=True)
        )
        if self.is_multigraph():
            result.add_edges_from(
                (u, v, key, deepcopy(attrs))
                for u, v, key, attrs in self.edges(keys=True, data=True)
            )
        else:
            result.add_edges_from(
                (u, v, deepcopy(attrs)) for u, v, attrs in self.edges(data=True)
            )
        return result

    return _wraps_without_signature_poisoning(to_undirected_impl, to_undirected)


def _directed_to_undirected_with_view(to_undirected_impl):
    def to_undirected(self, reciprocal=False, as_view=False):
        if as_view is True:
            return _generic_undirected_graph_view(self)
        if reciprocal is False:
            if self.is_multigraph():
                # Iterate in original-direction order so the undirected
                # edge orientation matches upstream nx, which preserves
                # (u, v) as added (the rust to_undirected_impl
                # canonicalises endpoints and diverges from nx on
                # MultiDiGraph where an edge was added one-way).
                result = self.to_undirected_class()()
                result.graph.update(deepcopy(self.graph))
                result.add_nodes_from(
                    (node, deepcopy(attrs)) for node, attrs in self.nodes(data=True)
                )
                result.add_edges_from(
                    (u, v, key, deepcopy(attrs))
                    for u in self
                    for v, keyed_attrs in self.adj[u].items()
                    for key, attrs in keyed_attrs.items()
                )
                return result

            result = self.to_undirected_class()()
            result.graph.update(deepcopy(self.graph))
            result.add_nodes_from(
                (node, deepcopy(attrs)) for node, attrs in self.nodes(data=True)
            )
            result.add_edges_from(
                (u, v, deepcopy(attrs))
                for u in self
                for v, attrs in self.adj[u].items()
            )
            return result

        result = self.to_undirected_class()()
        result.graph.update(deepcopy(self.graph))
        result.add_nodes_from((node, deepcopy(attrs)) for node, attrs in self.nodes(data=True))
        if self.is_multigraph():
            result.add_edges_from(
                (u, v, key, deepcopy(attrs))
                for u in self
                for v, keyed_attrs in self.adj[u].items()
                for key, attrs in keyed_attrs.items()
                if v in self.pred[u] and key in self.pred[u][v]
            )
        else:
            result.add_edges_from(
                (u, v, deepcopy(attrs))
                for u in self
                for v, attrs in self.adj[u].items()
                if v in self.pred[u]
            )
        return result

    return _wraps_without_signature_poisoning(to_undirected_impl, to_undirected)


# br-r37-c1-xsrkr: nx Graph uses object's default identity-based
# __eq__ and __hash__. The Rust binding implemented content-based
# __eq__, which (a) made fnx.path_graph(3) == fnx.path_graph(3)
# return True (False on nx) and (b) caused Python to set
# __hash__ = None, breaking ``set([G1, G2])``. Override to match
# nx's drop-in semantics on all four Graph classes.
for _G_cls in (Graph, DiGraph, MultiGraph, MultiDiGraph):
    _G_cls.__eq__ = object.__eq__
    _G_cls.__hash__ = object.__hash__
del _G_cls


# br-r37-c1-mpv5x: nx Graph.__str__ includes the graph name when set:
# "Graph named 'foo' with N nodes and E edges". The Rust binding
# returned the name-less form unconditionally.
def _graph_str(self):
    return "".join(
        [
            type(self).__name__,
            f" named {self.name!r}" if self.name else "",
            f" with {self.number_of_nodes()} nodes and {self.number_of_edges()} edges",
        ]
    )


for _G_cls in (Graph, DiGraph, MultiGraph, MultiDiGraph):
    _G_cls.__str__ = _graph_str
del _G_cls

Graph.copy = _copy_preserving_insertion_order
DiGraph.copy = _copy_preserving_insertion_order
MultiGraph.copy = _copy_preserving_insertion_order
MultiDiGraph.copy = _copy_preserving_insertion_order
Graph.subgraph = _subgraph_with_view(_GRAPH_SUBGRAPH)
DiGraph.subgraph = _subgraph_with_view(_DIGRAPH_SUBGRAPH)
MultiGraph.subgraph = _subgraph_with_view(_MULTIGRAPH_SUBGRAPH)
MultiDiGraph.subgraph = _subgraph_with_view(_MULTIDIGRAPH_SUBGRAPH)
Graph.to_directed = _graph_to_directed_with_view(_GRAPH_TO_DIRECTED)
DiGraph.to_directed = _digraph_to_directed_with_view(_DIGRAPH_TO_DIRECTED)
MultiGraph.to_directed = _multigraph_to_directed_with_view(_MULTIGRAPH_TO_DIRECTED)
MultiDiGraph.to_directed = _multidigraph_to_directed_with_view(_MULTIDIGRAPH_TO_DIRECTED)
Graph.to_undirected = _to_undirected_with_view(_GRAPH_TO_UNDIRECTED)
DiGraph.to_undirected = _directed_to_undirected_with_view(_DIGRAPH_TO_UNDIRECTED)
MultiGraph.to_undirected = _to_undirected_with_view(_MULTIGRAPH_TO_UNDIRECTED)
MultiDiGraph.to_undirected = _directed_to_undirected_with_view(
    _MULTIDIGRAPH_TO_UNDIRECTED
)


class _ConversionNodeView(Mapping):
    def __init__(self, view):
        self._view = view

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        return self._view._graph.nodes[node]

    def _data_rows(self, data=False, default=None):
        if data is False:
            return list(self)
        if data is True:
            return [(node, self[node]) for node in self]
        return [(node, self[node].get(data, default)) for node in self]

    def __call__(self, data=False, default=None):
        return self._data_rows(data=data, default=default)

    def data(self, data=True, default=None):
        return self._data_rows(data=data, default=default)

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)


class _ConversionMultiEdgeQuery:
    """View-backed edge-query result for multigraph conversion views.

    Returned by ``view.edges(...)`` on multigraph conversion live views so
    callers see a lazy, set-like, view-backed object rather than a plain
    list (matches upstream OutMultiEdgeView / MultiEdgeView surface for
    keyed multiedge queries).
    """

    def __init__(self, view, *, nbunch=None, data=False, keys=False, default=None):
        self._view = view
        self._nbunch = nbunch
        self._data = data
        self._keys = keys
        self._default = default

    def _materialise(self):
        return self._view._edges(
            nbunch=self._nbunch,
            data=self._data,
            keys=self._keys,
        )

    def __iter__(self):
        return iter(self._materialise())

    def __len__(self):
        return len(self._materialise())

    def __contains__(self, item):
        return item in self._materialise()

    def __eq__(self, other):
        if isinstance(other, _ConversionMultiEdgeQuery):
            other = other._materialise()
        if isinstance(other, set):
            return set(self._materialise()) == other
        try:
            return list(self._materialise()) == list(other)
        except TypeError:
            return NotImplemented

    def __ne__(self, other):
        result = self.__eq__(other)
        if result is NotImplemented:
            return result
        return not result

    def __hash__(self):
        return None  # Mutable view, intentionally unhashable.

    def __repr__(self):
        return repr(self._materialise())

    def __getitem__(self, idx):
        return self._materialise()[idx]

    def __and__(self, other):
        return set(self._materialise()) & set(other)

    def __rand__(self, other):
        return set(other) & set(self._materialise())

    def __or__(self, other):
        return set(self._materialise()) | set(other)

    def __ror__(self, other):
        return set(other) | set(self._materialise())

    def __sub__(self, other):
        return set(self._materialise()) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self._materialise())

    def __xor__(self, other):
        return set(self._materialise()) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self._materialise())


class _ConversionEdgeView:
    def __init__(self, view):
        self._view = view

    def __iter__(self):
        return iter(self())

    def __len__(self):
        return len(self())

    def __contains__(self, edge):
        try:
            u, v = edge[:2]
        except (TypeError, ValueError):
            return False
        if u not in self._view._graph:
            return False
        return v in self._view.adj[u]

    def __getitem__(self, edge):
        u, v = edge
        if u not in self._view._graph or v not in self._view.adj[u]:
            raise KeyError(edge)
        return self._view.adj[u][v]

    def __call__(self, nbunch=None, data=False, keys=False):
        if self._view.is_multigraph():
            return _ConversionMultiEdgeQuery(
                self._view, nbunch=nbunch, data=data, keys=keys
            )
        return self._view._edges(nbunch=nbunch, data=data, keys=keys)

    def data(self, data=True, default=None, nbunch=None, keys=False):
        if isinstance(data, str):
            base = self._view._edges(nbunch=nbunch, data=True, keys=keys)
            if keys:
                return [
                    (u, v, k, attrs.get(data, default))
                    for u, v, k, attrs in base
                ]
            return [
                (u, v, attrs.get(data, default)) for u, v, attrs in base
            ]
        return self._view._edges(nbunch=nbunch, data=data, keys=keys)

    def __and__(self, other):
        return set(self) & set(other)

    def __rand__(self, other):
        return set(other) & set(self)

    def __or__(self, other):
        return set(self) | set(other)

    def __ror__(self, other):
        return set(other) | set(self)

    def __sub__(self, other):
        return set(self) - set(other)

    def __rsub__(self, other):
        return set(other) - set(self)

    def __xor__(self, other):
        return set(self) ^ set(other)

    def __rxor__(self, other):
        return set(other) ^ set(self)

    get = _adjacency_view_get
    keys = _adjacency_view_keys
    items = _adjacency_view_items
    values = _adjacency_view_values


class _UnionKeyAtlas(Mapping):
    def __init__(self, primary, secondary):
        self._primary = primary
        self._secondary = secondary

    def __iter__(self):
        yielded = set()
        for key in self._primary:
            yielded.add(key)
            yield key
        for key in self._secondary:
            if key not in yielded:
                yield key

    def __len__(self):
        return sum(1 for _ in self)

    def __getitem__(self, key):
        if key in self._primary:
            return self._primary[key]
        return self._secondary[key]


class _ConversionNeighborMap(Mapping):
    def __init__(self, view, node, *, reverse=False):
        self._view = view
        self._node = node
        self._reverse = reverse

    def __iter__(self):
        if self._reverse:
            yield from self._view._pred_neighbors(self._node)
        else:
            yield from self._view._adj_neighbors(self._node)

    def __len__(self):
        return sum(1 for _ in self)

    def __getitem__(self, neighbor):
        if self._reverse:
            return self._view._pred_neighbor_value(self._node, neighbor)
        return self._view._adj_neighbor_value(self._node, neighbor)


class _ConversionAdjacencyView(Mapping):
    def __init__(self, view, *, reverse=False):
        self._view = view
        self._reverse = reverse

    def __iter__(self):
        return iter(self._view)

    def __len__(self):
        return len(self._view)

    def __getitem__(self, node):
        if node not in self._view._graph:
            raise KeyError(f"Key {node} not found")
        return _ConversionNeighborMap(self._view, node, reverse=self._reverse)


class _ConversionGraphViewBase:
    _directed = False
    _multigraph = False
    adjlist_inner_dict_factory = dict
    adjlist_outer_dict_factory = dict
    edge_attr_dict_factory = dict
    graph_attr_dict_factory = dict
    node_attr_dict_factory = dict
    node_dict_factory = dict

    def __init__(self, graph):
        self._graph = graph
        self.graph = graph.graph
        self.frozen = True
        self.nodes = _ConversionNodeView(self)
        self.edges = _ConversionEdgeView(self)
        self.adj = _ConversionAdjacencyView(self)
        if self.is_directed():
            self.succ = self.adj
            self.pred = _ConversionAdjacencyView(self, reverse=True)

    def __iter__(self):
        return iter(self._graph)

    def __len__(self):
        return len(self._graph)

    def __contains__(self, node):
        return node in self._graph

    def __getitem__(self, node):
        return self.adj[node]

    def __getattr__(self, name):
        if name in _FILTERED_VIEW_MUTATORS:
            return _frozen
        return getattr(self.copy(), name)

    def is_directed(self):
        return self._directed

    def is_multigraph(self):
        return self._multigraph

    def _nbunch(self, nbunch):
        if nbunch is None:
            return list(self)
        if nbunch in self._graph:
            return [nbunch]
        try:
            return [node for node in nbunch if node in self._graph]
        except TypeError:
            return []

    def _adj_neighbors(self, node):
        raise NotImplementedError

    def _adj_neighbor_value(self, node, neighbor):
        raise NotImplementedError

    def _pred_neighbors(self, node):
        yield from self._adj_neighbors(node)

    def _pred_neighbor_value(self, node, neighbor):
        return self._adj_neighbor_value(node, neighbor)

    def _edges(self, nbunch=None, data=False, keys=False):
        nodes = self._nbunch(nbunch)
        result = []
        if self.is_directed():
            for source in nodes:
                for target in self.adj[source]:
                    if self.is_multigraph():
                        for key, attrs in self.adj[source][target].items():
                            if data and keys:
                                result.append((source, target, key, attrs))
                            elif data:
                                result.append((source, target, attrs))
                            elif keys:
                                result.append((source, target, key))
                            else:
                                result.append((source, target))
                    else:
                        attrs = self.adj[source][target]
                        if data:
                            result.append((source, target, attrs))
                        else:
                            result.append((source, target))
            return result

        seen = set()
        for source in nodes:
            for target in self.adj[source]:
                if self.is_multigraph():
                    for key, attrs in self.adj[source][target].items():
                        marker = (frozenset((source, target)), key)
                        if marker in seen:
                            continue
                        seen.add(marker)
                        if data and keys:
                            result.append((source, target, key, attrs))
                        elif data:
                            result.append((source, target, attrs))
                        elif keys:
                            result.append((source, target, key))
                        else:
                            result.append((source, target))
                else:
                    marker = frozenset((source, target))
                    if marker in seen:
                        continue
                    seen.add(marker)
                    attrs = self.adj[source][target]
                    if data:
                        result.append((source, target, attrs))
                    else:
                        result.append((source, target))
        return result

    def neighbors(self, node):
        if node not in self._graph:
            raise NetworkXError(f"The node {node} is not in the graph.")
        return iter(self.adj[node])

    def successors(self, node):
        if not self.is_directed():
            return self.neighbors(node)
        if node not in self._graph:
            raise NetworkXError(f"The node {node} is not in the graph.")
        return iter(self.succ[node])

    def predecessors(self, node):
        if not self.is_directed():
            return self.neighbors(node)
        if node not in self._graph:
            raise NetworkXError(f"The node {node} is not in the graph.")
        return iter(self.pred[node])

    def number_of_nodes(self):
        return len(self)

    def number_of_edges(self):
        if self.is_multigraph():
            return len(self.edges(keys=True))
        return len(self.edges())

    def adjacency(self):
        return ((node, self.adj[node]) for node in self)

    def degree(self, nbunch=None, weight=None):
        def edge_weight(attrs):
            return attrs.get(weight, 1)

        def node_degree(node):
            if self.is_multigraph():
                if self.is_directed():
                    if weight is None:
                        total = sum(len(keydict) for keydict in self.succ[node].values())
                        total += sum(len(keydict) for keydict in self.pred[node].values())
                        return total

                    total = 0
                    for keydict in self.succ[node].values():
                        for attrs in keydict.values():
                            total += edge_weight(attrs)
                    for keydict in self.pred[node].values():
                        for attrs in keydict.values():
                            total += edge_weight(attrs)
                    return total

                total = 0
                for neighbor, keydict in self.adj[node].items():
                    edge_total = len(keydict) if weight is None else sum(
                        edge_weight(attrs) for attrs in keydict.values()
                    )
                    total += edge_total * 2 if neighbor == node else edge_total
                return total

            if self.is_directed():
                if weight is None:
                    return len(self.succ[node]) + len(self.pred[node])

                total = 0
                for attrs in self.succ[node].values():
                    total += edge_weight(attrs)
                for attrs in self.pred[node].values():
                    total += edge_weight(attrs)
                return total

            total = 0
            for neighbor, attrs in self.adj[node].items():
                edge_total = 1 if weight is None else edge_weight(attrs)
                total += edge_total * 2 if neighbor == node else edge_total
            return total

        if nbunch is None:
            return ((node, node_degree(node)) for node in self)

        try:
            if nbunch in self._graph:
                return node_degree(nbunch)
        except TypeError:
            pass

        nodes = self._nbunch(nbunch)
        return ((node, node_degree(node)) for node in nodes)

    def _directed_degree(self, adjacency, nbunch=None, weight=None):
        def edge_weight(attrs):
            return attrs.get(weight, 1)

        def node_degree(node):
            if self.is_multigraph():
                if weight is None:
                    return sum(len(keydict) for keydict in adjacency[node].values())

                total = 0
                for keydict in adjacency[node].values():
                    for attrs in keydict.values():
                        total += edge_weight(attrs)
                return total

            if weight is None:
                return len(adjacency[node])

            total = 0
            for attrs in adjacency[node].values():
                total += edge_weight(attrs)
            return total

        if nbunch is None:
            return ((node, node_degree(node)) for node in self)

        try:
            if nbunch in self._graph:
                return node_degree(nbunch)
        except TypeError:
            pass

        nodes = self._nbunch(nbunch)
        return ((node, node_degree(node)) for node in nodes)

    def copy(self):
        result = self._copy_type()()
        result.graph.update(dict(self.graph))
        result.add_nodes_from((node, dict(attrs)) for node, attrs in self.nodes(data=True))
        if self.is_multigraph():
            # 4-tuple shape avoids the ``key=key, **attrs`` collision when
            # an edge attribute is literally named "key"
            # (franken_networkx-9x7r0).
            result.add_edges_from(
                (u, v, key, dict(attrs))
                for u, v, key, attrs in self.edges(keys=True, data=True)
            )
        else:
            result.add_edges_from(
                (u, v, dict(attrs)) for u, v, attrs in self.edges(data=True)
            )
        return result

    def _copy_type(self):
        if self.is_directed():
            return MultiDiGraph if self.is_multigraph() else DiGraph
        return MultiGraph if self.is_multigraph() else Graph

    def to_directed_class(self):
        return MultiDiGraph if self.is_multigraph() else DiGraph

    def to_undirected_class(self):
        return MultiGraph if self.is_multigraph() else Graph

    def reverse(self, copy=True):
        if not self.is_directed():
            raise NetworkXError("Cannot reverse an undirected graph.")
        reversed_view = _reverse_directed_view_for(self)
        if copy:
            return reversed_view.copy()
        return reversed_view


class _DirectedGraphConversionView(_ConversionGraphViewBase):
    _directed = True

    def _adj_neighbors(self, node):
        return iter(self._graph[node])

    def _adj_neighbor_value(self, node, neighbor):
        return self._graph[node][neighbor]

    def _pred_neighbors(self, node):
        if self._graph.is_directed():
            return iter(self._graph.pred[node])
        return iter(self._graph[node])

    def _pred_neighbor_value(self, node, neighbor):
        if self._graph.is_directed():
            return self._graph.pred[node][neighbor]
        return self._graph[node][neighbor]

    def has_edge(self, u, v, key=None):
        return self._graph.has_edge(u, v)

    def has_successor(self, u, v):
        return u in self._graph and v in self.succ[u]

    def has_predecessor(self, u, v):
        return u in self._graph and v in self.pred[u]

    def in_degree(self, nbunch=None, weight=None):
        return self._directed_degree(self.pred, nbunch, weight)

    def out_degree(self, nbunch=None, weight=None):
        return self._directed_degree(self.succ, nbunch, weight)


class _DirectedMultiGraphConversionView(_ConversionGraphViewBase):
    _directed = True
    _multigraph = True

    def _adj_neighbors(self, node):
        return iter(self._graph[node])

    def _adj_neighbor_value(self, node, neighbor):
        return self._graph[node][neighbor]

    def _pred_neighbors(self, node):
        if self._graph.is_directed():
            return iter(self._graph.pred[node])
        return iter(self._graph[node])

    def _pred_neighbor_value(self, node, neighbor):
        if self._graph.is_directed():
            return self._graph.pred[node][neighbor]
        return self._graph[node][neighbor]

    def has_edge(self, u, v, key=None):
        return self._graph.has_edge(u, v, key)

    def has_successor(self, u, v):
        return u in self._graph and v in self.succ[u]

    def has_predecessor(self, u, v):
        return u in self._graph and v in self.pred[u]

    def in_degree(self, nbunch=None, weight=None):
        return self._directed_degree(self.pred, nbunch, weight)

    def out_degree(self, nbunch=None, weight=None):
        return self._directed_degree(self.succ, nbunch, weight)


_DIRECTED_CONVERSION_VIEW_TYPES = {
    False: type("DiGraph", (_DirectedGraphConversionView,), {}),
    True: type("MultiDiGraph", (_DirectedMultiGraphConversionView,), {}),
}


def _generic_directed_graph_view(graph):
    view_type = _DIRECTED_CONVERSION_VIEW_TYPES[graph.is_multigraph()]
    return view_type(graph)


class _UndirectedGraphConversionView(_ConversionGraphViewBase):
    def _adj_neighbors(self, node):
        if not self._graph.is_directed():
            return iter(self._graph[node])

        def merged():
            yielded = set()
            for neighbor in self._graph.succ[node]:
                yielded.add(neighbor)
                yield neighbor
            for neighbor in self._graph.pred[node]:
                if neighbor not in yielded:
                    yield neighbor

        return merged()

    def _adj_neighbor_value(self, node, neighbor):
        if not self._graph.is_directed():
            return self._graph[node][neighbor]
        if self._graph.has_edge(node, neighbor):
            return self._graph.succ[node][neighbor]
        return self._graph.pred[node][neighbor]

    def has_edge(self, u, v, key=None):
        if not self._graph.is_directed():
            return self._graph.has_edge(u, v)
        return self._graph.has_edge(u, v) or self._graph.has_edge(v, u)


class _UndirectedMultiGraphConversionView(_ConversionGraphViewBase):
    _multigraph = True

    def _adj_neighbors(self, node):
        if not self._graph.is_directed():
            return iter(self._graph[node])

        def merged():
            yielded = set()
            for neighbor in self._graph.succ[node]:
                yielded.add(neighbor)
                yield neighbor
            for neighbor in self._graph.pred[node]:
                if neighbor not in yielded:
                    yield neighbor

        return merged()

    def _adj_neighbor_value(self, node, neighbor):
        if not self._graph.is_directed():
            return self._graph[node][neighbor]

        outgoing = self._graph.succ[node].get(neighbor)
        incoming = self._graph.pred[node].get(neighbor)
        if outgoing is not None and incoming is not None:
            return _UnionKeyAtlas(outgoing, incoming)
        if outgoing is not None:
            return outgoing
        if incoming is not None:
            return incoming
        raise KeyError(f"Key {neighbor} not found")

    def has_edge(self, u, v, key=None):
        if not self._graph.is_directed():
            return self._graph.has_edge(u, v, key)
        return self._graph.has_edge(u, v, key) or self._graph.has_edge(v, u, key)


_UNDIRECTED_CONVERSION_VIEW_TYPES = {
    False: type("Graph", (_UndirectedGraphConversionView,), {}),
    True: type("MultiGraph", (_UndirectedMultiGraphConversionView,), {}),
}


def _generic_undirected_graph_view(graph):
    view_type = _UNDIRECTED_CONVERSION_VIEW_TYPES[graph.is_multigraph()]
    return view_type(graph)


def reverse(G, copy=True):
    """Return graph with all edges reversed."""
    if not G.is_directed():
        raise NetworkXError("Cannot reverse an undirected graph.")
    if copy:
        return G.reverse()
    return _reverse_directed_view_for(G)


def nodes(G):
    """Return nodes of G (global function form)."""
    return G.nodes


def _global_nbunch_nodes(G, nbunch):
    if nbunch is None:
        return None
    try:
        if nbunch in G:
            return [nbunch]
    except TypeError:
        pass
    try:
        nodes = []
        for node in nbunch:
            try:
                hash(node)
            except TypeError as exc:
                raise NetworkXError(
                    f"Node {node} in sequence nbunch is not a valid node."
                ) from exc
            if node in G:
                nodes.append(node)
        return nodes
    except TypeError as exc:
        message = exc.args[0] if exc.args else ""
        if "object is not iterable" in message:
            raise NetworkXError(f"Node {nbunch} is not in the graph.") from exc
        raise NetworkXError("nbunch is not a node or a sequence of nodes.") from exc


def _triangle_selection(G, nodes):
    if nodes is None:
        return None, False

    try:
        if nodes in G:
            return [nodes], True
    except TypeError:
        pass

    return _global_nbunch_nodes(G, nodes), False


def _triangles_and_degree_iter_local(G, nodes=None):
    node_iter = G if nodes is None else nodes
    nodes_neighbors = ((node, G[node]) for node in node_iter)

    for node, node_neighbors in nodes_neighbors:
        neighbor_set = set(node_neighbors) - {node}
        generalized_degree = Counter(
            len(neighbor_set & (set(G[neighbor]) - {neighbor})) for neighbor in neighbor_set
        )
        triangle_count = sum(size * count for size, count in generalized_degree.items())
        yield (node, len(neighbor_set), triangle_count, generalized_degree)


def _weighted_triangles_and_degree_iter_local(G, nodes=None, weight="weight"):
    if weight is None or G.number_of_edges() == 0:
        max_weight = 1
    else:
        max_weight = max(
            attrs.get(weight, 1) for _, _, attrs in G.edges(data=True)
        )

    node_iter = G if nodes is None else nodes
    nodes_neighbors = ((node, G[node]) for node in node_iter)

    def normalized_weight(u, v):
        return G[u][v].get(weight, 1) / max_weight

    for node, node_neighbors in nodes_neighbors:
        neighbor_set = set(node_neighbors) - {node}
        weighted_triangle_sum = 0.0
        seen_neighbors = set()
        for neighbor in neighbor_set:
            seen_neighbors.add(neighbor)
            neighbor_neighbors = set(G[neighbor]) - seen_neighbors
            edge_weight = normalized_weight(node, neighbor)
            for shared_neighbor in neighbor_set & neighbor_neighbors:
                weighted_triangle_sum += math.cbrt(
                    edge_weight
                    * normalized_weight(neighbor, shared_neighbor)
                    * normalized_weight(shared_neighbor, node)
                )
        yield (node, len(neighbor_set), 2.0 * weighted_triangle_sum)


def _directed_triangles_and_degree_iter_local(G, nodes=None):
    node_iter = G if nodes is None else nodes
    nodes_neighbors = ((node, G.pred[node], G.succ[node]) for node in node_iter)

    for node, predecessors, successors in nodes_neighbors:
        predecessor_set = set(predecessors) - {node}
        successor_set = set(successors) - {node}

        directed_triangle_count = 0
        for neighbor in itertools.chain(predecessor_set, successor_set):
            neighbor_predecessors = set(G.pred[neighbor]) - {neighbor}
            neighbor_successors = set(G.succ[neighbor]) - {neighbor}
            directed_triangle_count += sum(
                1
                for third_node in itertools.chain(
                    predecessor_set & neighbor_predecessors,
                    predecessor_set & neighbor_successors,
                    successor_set & neighbor_predecessors,
                    successor_set & neighbor_successors,
                )
            )

        total_degree = len(predecessor_set) + len(successor_set)
        reciprocal_degree = len(predecessor_set & successor_set)
        yield (node, total_degree, reciprocal_degree, directed_triangle_count)


def _directed_weighted_triangles_and_degree_iter_local(G, nodes=None, weight="weight"):
    if weight is None or G.number_of_edges() == 0:
        max_weight = 1
    else:
        max_weight = max(
            attrs.get(weight, 1) for _, _, attrs in G.edges(data=True)
        )

    node_iter = G if nodes is None else nodes
    nodes_neighbors = ((node, G.pred[node], G.succ[node]) for node in node_iter)

    def normalized_weight(u, v):
        return G[u][v].get(weight, 1) / max_weight

    for node, predecessors, successors in nodes_neighbors:
        predecessor_set = set(predecessors) - {node}
        successor_set = set(successors) - {node}

        directed_triangle_sum = 0.0
        for neighbor in predecessor_set:
            neighbor_predecessors = set(G.pred[neighbor]) - {neighbor}
            neighbor_successors = set(G.succ[neighbor]) - {neighbor}
            for third_node in predecessor_set & neighbor_predecessors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(neighbor, node)
                    * normalized_weight(third_node, node)
                    * normalized_weight(third_node, neighbor)
                )
            for third_node in predecessor_set & neighbor_successors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(neighbor, node)
                    * normalized_weight(third_node, node)
                    * normalized_weight(neighbor, third_node)
                )
            for third_node in successor_set & neighbor_predecessors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(neighbor, node)
                    * normalized_weight(node, third_node)
                    * normalized_weight(third_node, neighbor)
                )
            for third_node in successor_set & neighbor_successors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(neighbor, node)
                    * normalized_weight(node, third_node)
                    * normalized_weight(neighbor, third_node)
                )

        for neighbor in successor_set:
            neighbor_predecessors = set(G.pred[neighbor]) - {neighbor}
            neighbor_successors = set(G.succ[neighbor]) - {neighbor}
            for third_node in predecessor_set & neighbor_predecessors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(node, neighbor)
                    * normalized_weight(third_node, node)
                    * normalized_weight(third_node, neighbor)
                )
            for third_node in predecessor_set & neighbor_successors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(node, neighbor)
                    * normalized_weight(third_node, node)
                    * normalized_weight(neighbor, third_node)
                )
            for third_node in successor_set & neighbor_predecessors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(node, neighbor)
                    * normalized_weight(node, third_node)
                    * normalized_weight(third_node, neighbor)
                )
            for third_node in successor_set & neighbor_successors:
                directed_triangle_sum += math.cbrt(
                    normalized_weight(node, neighbor)
                    * normalized_weight(node, third_node)
                    * normalized_weight(neighbor, third_node)
                )

        total_degree = len(predecessor_set) + len(successor_set)
        reciprocal_degree = len(predecessor_set & successor_set)
        yield (node, total_degree, reciprocal_degree, directed_triangle_sum)


def clustering(G, nodes=None, weight=None):
    """Compute the clustering coefficient for nodes."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    selected_nodes, single_node = _triangle_selection(G, nodes)

    if G.is_directed():
        if weight is not None:
            triangle_data = _directed_weighted_triangles_and_degree_iter_local(
                G, selected_nodes, weight
            )
        else:
            triangle_data = _directed_triangles_and_degree_iter_local(G, selected_nodes)
        clustering_coefficients = {
            node: 0 if triangle_count == 0 else triangle_count / ((total_degree * (total_degree - 1) - 2 * reciprocal_degree) * 2)
            for node, total_degree, reciprocal_degree, triangle_count in triangle_data
        }
    else:
        if weight is not None:
            triangle_data = _weighted_triangles_and_degree_iter_local(
                G, selected_nodes, weight
            )
            clustering_coefficients = {
                node: 0 if triangle_count == 0 else triangle_count / (degree * (degree - 1))
                for node, degree, triangle_count in triangle_data
            }
        else:
            triangle_data = _triangles_and_degree_iter_local(G, selected_nodes)
            clustering_coefficients = {
                node: 0 if triangle_count == 0 else triangle_count / (degree * (degree - 1))
                for node, degree, triangle_count, _ in triangle_data
            }

    if single_node:
        return clustering_coefficients[nodes]
    return clustering_coefficients


def average_clustering(G, nodes=None, weight=None, count_zeros=True):
    """Compute the average clustering coefficient for the graph."""
    clustering_values = clustering(G, nodes, weight=weight).values()
    if not count_zeros:
        clustering_values = [value for value in clustering_values if abs(value) > 0]
    return sum(clustering_values) / len(clustering_values)


def transitivity(G):
    """Compute graph transitivity."""
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    triangles_contributions = [
        (triangle_count, degree * (degree - 1))
        for _, degree, triangle_count, _ in _triangles_and_degree_iter_local(G)
    ]
    if len(triangles_contributions) == 0:
        return 0
    triangles, contributions = map(sum, zip(*triangles_contributions))
    return 0 if triangles == 0 else triangles / contributions


def square_clustering(G, nodes=None):
    """Compute the squares clustering coefficient for nodes."""
    single_node = False
    if nodes is None:
        node_iter = G
    elif nodes in G:
        node_iter = [nodes]
        single_node = True
    else:
        node_iter = _global_nbunch_nodes(G, nodes)

    square_coefficients = {}
    graph_adj = G.adj

    class CachedNeighborSets(dict):
        def __missing__(self, node):
            neighbors = self[node] = set(graph_adj[node])
            neighbors.discard(node)
            return neighbors

    neighbor_sets = CachedNeighborSets()

    for node in node_iter:
        node_neighbors = neighbor_sets[node]
        neighbor_count_minus_one = len(node_neighbors) - 1
        if neighbor_count_minus_one <= 0:
            square_coefficients[node] = 0
            continue

        neighbor_pair_degrees = 0
        neighbor_pair_count = len(node_neighbors) * neighbor_count_minus_one
        triangle_count = 0
        square_count = 0

        for neighbor in node_neighbors:
            neighbor_neighbors = neighbor_sets[neighbor]
            neighbor_pair_degrees += len(neighbor_neighbors) * neighbor_count_minus_one
            shared_neighbors = len(neighbor_neighbors & node_neighbors)
            triangle_count += shared_neighbors
            square_count += shared_neighbors * (shared_neighbors - 1)

        two_hop_neighbors = set.union(
            *(neighbor_sets[neighbor] for neighbor in node_neighbors)
        )
        two_hop_neighbors -= node_neighbors
        two_hop_neighbors.discard(node)

        for opposite_corner in two_hop_neighbors:
            shared_neighbors = len(node_neighbors & neighbor_sets[opposite_corner])
            square_count += shared_neighbors * (shared_neighbors - 1)

        square_count //= 2
        potential = (
            neighbor_pair_degrees - neighbor_pair_count - triangle_count - square_count
        )
        square_coefficients[node] = square_count / potential if potential > 0 else 0

    if single_node:
        return square_coefficients[nodes]
    return square_coefficients


def triangles(G, nodes=None):
    """Compute the number of triangles."""
    if nodes is None:
        raw = _raw_triangles(G)
        # br-r37-c1-k3khk: the Rust binding returns the dict with keys
        # sorted; nx iterates in node-insertion order. Reorder so
        # ``for node, count in triangles(G).items():`` matches nx.
        return {node: raw[node] for node in G.nodes() if node in raw}

    if G.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    if G.is_multigraph():
        raise NetworkXNotImplemented("not implemented for multigraph type")

    if nodes in G:
        return _raw_triangles(G)[nodes]

    triangle_counts = _raw_triangles(G)
    nbunch_nodes = _global_nbunch_nodes(G, nodes)
    return {node: triangle_counts[node] for node in nbunch_nodes}


def edges(G, nbunch=None):
    """Return edges of G (global function form)."""
    if nbunch is None:
        return G.edges

    nbunch_nodes = _global_nbunch_nodes(G, nbunch)
    if G.is_directed():
        result = []
        if G.is_multigraph():
            for u in nbunch_nodes:
                if u not in G:
                    continue
                for v, keydict in G[u].items():
                    for _key in keydict:
                        result.append((u, v))
            return result

        for u in nbunch_nodes:
            if u not in G:
                continue
            for v in G[u]:
                result.append((u, v))
        return result

    if G.is_multigraph():
        seen = set()
        result = []
        for u in nbunch_nodes:
            if u not in G:
                continue
            for v, keydict in G[u].items():
                for key in keydict:
                    marker = (frozenset((u, v)), key)
                    if marker in seen:
                        continue
                    seen.add(marker)
                    result.append((u, v))
        return result

    seen = set()
    result = []
    for u in nbunch_nodes:
        if u not in G:
            continue
        for v in G[u]:
            marker = frozenset((u, v))
            if marker in seen:
                continue
            seen.add(marker)
            result.append((u, v))
    return result


def degree(G, nbunch=None, weight=None):
    """Return degree view of G (global function form)."""
    if weight is None:
        if nbunch is None:
            return G.degree
        try:
            if nbunch in G:
                return G.degree[nbunch]
        except TypeError:
            pass

        nbunch_nodes = _global_nbunch_nodes(G, nbunch)
        return ((node, G.degree[node]) for node in nbunch_nodes)

    def edge_weight(attrs):
        return attrs.get(weight, 1)

    def weighted_degree(node):
        if G.is_multigraph():
            if G.is_directed():
                total = 0
                for keydict in G.succ[node].values():
                    for attrs in keydict.values():
                        total += edge_weight(attrs)
                for keydict in G.pred[node].values():
                    for attrs in keydict.values():
                        total += edge_weight(attrs)
                return total

            total = 0
            for neighbor, keydict in G.adj[node].items():
                edge_total = 0
                for attrs in keydict.values():
                    edge_total += edge_weight(attrs)
                total += edge_total * 2 if neighbor == node else edge_total
            return total

        if G.is_directed():
            total = 0
            for attrs in G.succ[node].values():
                total += edge_weight(attrs)
            for attrs in G.pred[node].values():
                total += edge_weight(attrs)
            return total

        total = 0
        for neighbor, attrs in G.adj[node].items():
            edge_total = edge_weight(attrs)
            total += edge_total * 2 if neighbor == node else edge_total
        return total

    if nbunch is None:
        return ((node, weighted_degree(node)) for node in G.nodes)

    try:
        if nbunch in G:
            return weighted_degree(nbunch)
    except TypeError:
        pass

    nbunch_nodes = _global_nbunch_nodes(G, nbunch)
    return ((node, weighted_degree(node)) for node in nbunch_nodes)


def number_of_nodes(G):
    """Return number of nodes (global function form)."""
    return G.number_of_nodes()


def number_of_edges(G):
    """Return number of edges (global function form)."""
    return G.number_of_edges()


