def from_pandas_adjacency(df, create_using=None):
    """Build graph from pandas DataFrame adjacency matrix."""
    try:
        df = df[df.index]
    except Exception as err:
        missing = list(set(df.index).difference(set(df.columns)))
        msg = f"{missing} not in columns"
        raise NetworkXError("Columns must match Indices.", msg) from err

    return from_numpy_array(df.values, create_using=create_using, nodelist=df.columns)


def to_pandas_adjacency(
    G,
    nodelist=None,
    dtype=None,
    order=None,
    multigraph_weight=sum,
    weight="weight",
    nonedge=0.0,
):
    """Export adjacency as pandas DataFrame."""
    import pandas as pd

    matrix = to_numpy_array(
        G,
        nodelist=nodelist,
        dtype=dtype,
        order=order,
        multigraph_weight=multigraph_weight,
        weight=weight,
        nonedge=nonedge,
    )
    if nodelist is None:
        nodelist = list(G)
    return pd.DataFrame(data=matrix, index=nodelist, columns=nodelist)


def from_prufer_sequence(sequence):
    """Reconstruct labeled tree from Prüfer sequence."""
    edges = _fnx.from_prufer_sequence_rust(list(sequence))
    n = len(sequence) + 2
    G = Graph()
    for i in range(n):
        G.add_node(i)
    for u, v in edges:
        G.add_edge(u, v)
    return G


def to_prufer_sequence(T):
    """Extract Prüfer sequence from labeled tree.

    Raises
    ------
    NetworkXPointlessConcept
        If the tree has fewer than two nodes.
    NotATree
        If *T* is not a tree.
    KeyError
        If the node set is not {0, …, n-1}.
    """
    if T.is_directed():
        raise NetworkXNotImplemented("not implemented for directed type")
    n = T.number_of_nodes()
    if n < 2:
        raise NetworkXPointlessConcept(
            "Prüfer sequence undefined for trees with fewer than two nodes."
        )
    if not is_tree(T):
        raise NotATree("provided graph is not a tree")
    # The Rust helper indexes by integer position [0, n); validate labels
    # like nx does before falling through — else we get a KeyError anyway.
    if set(T.nodes()) != set(range(n)):
        raise KeyError("Nodes must be labelled 0 to n-1")
    return _fnx.to_prufer_sequence_rust(T)


def from_nested_tuple(sequence, sensible_relabeling=False):
    """Build tree from nested tuple representation."""
    G = Graph()
    counter = [0]

    def _build(parent, subtree):
        for child_tree in subtree:
            child = counter[0]
            counter[0] += 1
            G.add_node(child)
            if parent is not None:
                G.add_edge(parent, child)
            if isinstance(child_tree, tuple):
                _build(child, child_tree)

    root = counter[0]
    counter[0] += 1
    G.add_node(root)
    if isinstance(sequence, tuple):
        _build(root, sequence)
    return G


def to_nested_tuple(T, root, canonical_form=False):
    """Convert rooted tree to nested tuple."""
    def _recurse(node, parent):
        children = [n for n in T.neighbors(node) if n != parent]
        if not children:
            return ()
        subtrees = [_recurse(child, node) for child in sorted(children, key=str)]
        if canonical_form:
            subtrees.sort()
        return tuple(subtrees)

    return _recurse(root, None)


def attr_sparse_matrix(
    G, edge_attr=None, node_attr=None, normalized=False, rc_order=None, dtype=None
):
    """Like attr_matrix but returns scipy sparse."""
    import scipy.sparse

    if rc_order is None:
        M, nodelist = attr_matrix(
            G,
            edge_attr=edge_attr,
            node_attr=node_attr,
            normalized=normalized,
            rc_order=rc_order,
            dtype=dtype,
        )
        return scipy.sparse.csr_array(M), nodelist
    M = attr_matrix(
        G,
        edge_attr=edge_attr,
        node_attr=node_attr,
        normalized=normalized,
        rc_order=rc_order,
        dtype=dtype,
    )
    return scipy.sparse.csr_array(M)


