import networkx as _nx

# Match NetworkX's top-level config object rather than exposing the older stub
# helper function shape from this module.
config = _nx.config
approximation = _ApproximationNamespace()


# br-Gsigbulk: bulk-rename the first parameter of Rust-bindings that
# name the graph arg lowercase ``g`` to the nx-standard ``G`` so
# kwarg-style drop-in calls like ``fnx.is_empty(G=g)`` work. The wrapper
# forwards positionally so the Rust side still sees the graph as its
# first positional argument. This mops up the long tail of
# Rust-native-imports that Round 19 left behind.
def _bulk_rename_first_param_to_G():
    import functools as _ft
    import inspect as _insp

    targets = [
        "bfs_layers",
        "biconnected_component_edges",
        "bidirectional_shortest_path",
        "core_number",
        "descendants_at_distance",
        "dominance_frontiers",
        "enumerate_all_cliques",
        "is_arborescence",
        "is_bipartite",
        "is_branching",
        "is_connected",
        "is_dominating_set",
        "is_edge_cover",
        "is_empty",
        "is_eulerian",
        "is_isolate",
        "is_k_edge_connected",
        "is_k_regular",
        "is_matching",
        "is_maximal_matching",
        "is_perfect_matching",
        "is_semieulerian",
        "is_simple_path",
        "is_weakly_connected",
        "isolates",
        "kosaraju_strongly_connected_components",
        "max_weight_clique",
        "max_weight_matching",
        "maximal_independent_set",
        "maximal_matching",
        "min_weight_matching",
        "node_connected_component",
        "number_connected_components",
        "number_of_isolates",
        "number_of_spanning_trees",
        "number_strongly_connected_components",
        "number_weakly_connected_components",
        "tree_broadcast_center",
        "tree_broadcast_time",
    ]
    ns = globals()
    for name in targets:
        raw = ns.get(name)
        if raw is None:
            continue
        try:
            raw_sig = _insp.signature(raw)
        except (ValueError, TypeError):
            continue
        params = list(raw_sig.parameters.values())
        if not params or params[0].name != "g":
            continue

        def _make_wrapper(raw_fn, raw_params):
            # Build a new signature renaming first positional to 'G'.
            new_first = raw_params[0].replace(name="G")
            new_sig = _insp.Signature([new_first] + list(raw_params[1:]))

            @_ft.wraps(raw_fn)
            def wrapper(*args, **kwargs):
                if "G" in kwargs and "g" not in kwargs:
                    kwargs["g"] = kwargs.pop("G")
                return raw_fn(*args, **kwargs)

            wrapper.__signature__ = new_sig
            return wrapper

        ns[name] = _make_wrapper(raw, params)


_bulk_rename_first_param_to_G()


def _bulk_promote_to_generator():
    """br-bulkgen: nx returns generators for these functions; fnx's
    bindings returned materialised lists. Wrap each so the contract
    matches (lazy, exhausts after iteration, user code calling
    ``next(it)`` works).
    """
    import functools as _ft

    targets = [
        "find_cliques",
        "find_cliques_recursive",
        "enumerate_all_cliques",
        "all_simple_paths",
        "all_shortest_paths",
        "bfs_edges",
        "dfs_edges",
        "bfs_layers",
        "isolates",
        "minimum_spanning_edges",
        "maximum_spanning_edges",
    ]

    ns = globals()
    for name in targets:
        raw = ns.get(name)
        if raw is None:
            continue

        def _make_wrapper(raw_fn):
            @_ft.wraps(raw_fn)
            def wrapper(*args, **kwargs):
                result = raw_fn(*args, **kwargs)
                if hasattr(result, "__next__"):
                    return result
                return iter(result)

            return wrapper

        ns[name] = _make_wrapper(raw)


_bulk_promote_to_generator()


def _install_mutation_detection_on_node_views():
    """br-mutiter: nx detects mutation during ``for n in G.nodes(): ...``
    and raises ``RuntimeError('dictionary changed size during iteration')``.
    fnx's Rust NodeView iterator snapshots the node list at iter() time
    and quietly yields the snapshot even if the graph has been mutated.

    Wrap __iter__ on each NodeView variant with a size-checker: snapshot
    len(self) at iter() time and, on each yield, compare to current
    len(self). If they differ, raise RuntimeError with nx-exact wording.
    This works without access to the underlying graph because the view's
    __len__ queries the graph directly.
    """
    from franken_networkx import _fnx as _raw

    def _make_iter(raw_iter):
        def __iter__(self):
            initial_len = len(self)
            for node in raw_iter(self):
                if len(self) != initial_len:
                    raise RuntimeError(
                        "dictionary changed size during iteration"
                    )
                yield node
        return __iter__

    targets = [
        _raw.NodeView,
        _raw.DiNodeView,
        _raw.MultiGraphNodeView,
        _raw.MultiDiGraphNodeView,
    ]
    for cls in targets:
        cls.__iter__ = _make_iter(cls.__iter__)


_install_mutation_detection_on_node_views()


def __getattr__(name):
    """Fallback to the NetworkX top-level namespace for missing public attrs."""
    import networkx as nx

    try:
        return getattr(nx, name)
    except AttributeError as exc:
        raise AttributeError(f"module {__name__!r} has no attribute {name!r}") from exc


def __dir__():
    """Expose FrankenNetworkX globals plus NetworkX's public top-level namespace."""
    import networkx as nx

    return sorted(set(globals()) | set(dir(nx)))
